window.PDFTEXT={"centralisateur-dessin":[{"p":1,"t":"TÉL:(819)825-4657 FAX:(819)825-0698 WWW.MACHINES-ROGER.CA COULEUR DE SURFACE/SURFACE COLOR TITRE/TITLE PAGE REV. NO."},{"p":1,"t":"±1/16\" FRACTION/FRACTION ±1/16\" FRACTION/FRACTION ANGULAIRE/ANGULAR TOLERANCES GENERALES SI NON INDIQUEES DECOUPAGE - USINAGE/CUT - MILLING FINI SURFACE/SURFACE FINISH IF NOT INDICATED GENERALS TOLERANCES ±0.015\" ASSEMBLAGE SOUDE/WELDMENT ASSEMBLY DECIMALE/DECIMAL ±0.4mm ±1.5mm ±1.5mm 125 ±1/2 L'INFO"},{"p":1,"t":"RMATION CONTENUE DANS CE DESSIN EST LA PROPRIÉTÉ DE MACHINES-ROGER INTERNATIONAL INC. TOUTE REPRODUCTION COMPLÈTE OU PARTIELLE SANS L'AUTORISATION DE MACHINES-ROGER INTERNATIONAL INC EST INTERDITE."},{"p":1,"t":"THE INFORMATION CONTAINED IN THIS DRAWING IS THE SOLE PROPERTY OF MACHINES-ROGER INTERNATIONAL INC ANY REPRODUCTION IN PART OR WHOLE WITHOUT THE WRITTENOF MACHINES-ROGER INTERNATIONAL INC IS PROHIBITED."},{"p":1,"t":"INFORMATION ECHELLE/SCALE POIDS/WEIGHT DATE DATE APPROUVE/APPROUVED DESSINE/DRAW CATEGORIE MATERIEL/MATERIAL GRADE DESCRIPTION MATERIEL/MATERIAL DESCRIPTION A-M-J / Y-M-D A-M-J / Y-M-D № INVENTAIRE MRI 1 1 1 1 4 3 2 3 2 4 1 2 3 4 4 3 2 1 No."},{"p":1,"t":"ARTICLE NUMERO DE PIECE TITRE QTE 1 30271101 CENTRALISATEUR 2 2 Regular LW 0.5 LOCKWASHER 12 3 HNUT 0.5000-13-D-N ECROU 12 4 HBOLT 0.5000-13x1.375x1.25-N BOLT 12 PROCEDURE INSTALATION 1:5 93.0lbs K.BECHARD 2023-03-15 2023-03-15 V.CHYHRYNAU PROCEDURE INSTALATION CENTRALISATEUR"}],"centralisateur":[{"p":1,"t":"PROCÉDURE D’INSTALLATION DU CENTRALISATEUR"},{"p":1,"t":"BOULONS ET ÉCROUS NÉCESSAIRES AU MONTAGE"},{"p":1,"t":"12 boulons ½ X 1’’ 3/8 de long"},{"p":1,"t":"12 locknut ½ 12 lockwashers ½"},{"p":1,"t":"OUTILS NÉCESSAIRES AU MONTAGE"},{"p":1,"t":"2 Clés ¾ ou,"},{"p":1,"t":"1 clé ¾ et 1 box ¾ avec"},{"p":1,"t":"1 ratchet ou 1 impact"},{"p":1,"t":"L’INSTALLATION DU CENTRALISATEUR DOIT TOUJOURS SE FAIRE À DEUX TRAVAILLEURS"},{"p":1,"t":"1- Le centralisateur de tiges est principalement utilisé pour le forage de trous de V-30 pour empêcher l’oscillement des tiges et pour maintenir le V-30 correctement alignée;"},{"p":1,"t":"2- Les centralisateurs de tiges sont normalement installés tous les 40 pieds ou selon les besoins en fonction des conditions de terrain dans la monterie ainsi que de la longueur et l’angle de la monterie forée;"},{"p":1,"t":"3- Avant d’installer le centralisateur, la tige doit être mise sur le train de tige;"},{"p":1,"t":"4- Le centralisateur de tige est installé sur l'extrémité femelle de la tige conformément au dessin ci-joint;"},{"p":1,"t":"5- Les deux pièces du centralisateur pèsent 46 livres chacune. Il est important de toujours être positionné de la meilleure manière pour manipuler ces pièces;"},{"p":1,"t":"6- Aligner l’accouplement du bas d’une des deux pièces du centralisateur sur les coches de slip plate de la tige;"},{"p":1,"t":"7- Rapprocher l’autre pièce du centralisateur et l’aligner avec l’autre pièce déjà maintenue en place par un des deux travailleurs;"},{"p":1,"t":"8- Mettre 6 boulons dans un sens et 6 dans l’autre sens tel qu’illustré dans le plan de montage plus bas;"},{"p":2,"t":"PROCÉDURE D’INSTALLATION DU CENTRALISATEUR"},{"p":2,"t":"2 9- Attention de ne pas endommager les filets des boulons quand vous les entrez dans les trous prévus à cet effet;"},{"p":2,"t":"Il n’y a pas de séquence d’installation ou de serrages des boulons et des écrous"},{"p":2,"t":"10- S’assurer de la présence des 12 boulons, des 12 locknuts et des 12 lockwashers"},{"p":2,"t":"11- Serrer tous les boulons en maintenant une tension sur les lockwashers à l’aide de l’outil adéquat (clé ou box);"},{"p":2,"t":"L’UTILISATION D’UN WESCOT OU D’UN PIPE WRENCH N’EST PAS ADÉQUATE"},{"p":2,"t":"12- Faites la procédure contraire lors du démantèlement du centralisateur."},{"p":2,"t":"PLAN DE MONTAGE"},{"p":2,"t":"________________________________ Christian St-Amour Directeur des Opérations"}],"dr600-op-002":[{"p":1,"t":"PROCÉDURE DE TRAVAIL"},{"p":1,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA FOREUSE DR-600-MU #2923 Juillet 2023 Page 1 sur 17 Révision Janvier 2026 OBJECTIF"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour déplacer la DR-600-MU par ses propres moyens et la remorquer. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur doit appliquer cette procédure en tout temps lors des déplacements et lors du remorquage de la DR-600-MU. Le superviseur doit s’assurer de la bonne compréhension de la procédure par le travailleur ainsi que de son application."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le Directeur des Opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"LA DR-600-MU PEUT ÊTRE DÉPLACÉE PAR SES PROPRES MOYENS SEULEMENT SUR DE COURTES DISTANCES SANS PENTE IL EST STRICTEMENT INTERDIT DE DÉPLACER LA DR-600 PAR SES PROPRES MOYENS DANS LA RAMPE"},{"p":2,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 PROCÉDURE DÉPLACEMENT AUTONOME AVEC LE MOTEUR DIESEL La DR-600-MU est équipée d’un moteur diésel entrainant une pompe hydraulique auxiliaire permettant l’utilisation du mode « positioning » de la machin"},{"p":2,"t":"e. Il est donc possible de : • D’utiliser les tractions de gauche et de droite (« TRACTION ») • De déployer le mât (« TILT ») • D’ajuster l’angle du mât (« DIP ») • Déployer les pattes de coins (« JACKS ») • De pivoter la table (« TABLE ROTATE ») • D’extensionner la table (longitudinal) • De pivoter"},{"p":2,"t":"le mât (MAST ROTATE) • De monter et descendre le bras (ARM UP-DOWN) • De déployer les « stingers » (SELECTOR IN-OUT) ou le mast extension (SELECTOR SUR TÉLÉCOMMANDE + BRAS SUR LA TOUR IMAGE) Voici les étapes à suivre afin de déplacer la machine en mode diesel : 1."},{"p":2,"t":"Actionner les 4 pattes de coins afin que les roues ne touchent plus au sol"},{"p":2,"t":"2. S’assurer que l’engagement au centre des 4 roues est bien dévissé AU COMPLET."},{"p":2,"t":"ATTENTION, IL N’Y A AUCUN FREIN SUR LA FOREUSE SI LES PLANÉTAIRES SONT DÉSENGAGÉS"},{"p":3,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 Pour les engager, si on sent une résistance, c’est que les engrenages sont mal placés et il faut alors tourner légèrement la roue manuellement et réessayer"},{"p":3,"t":"1. Assurez-vous que la foreuse est bien détachée du véhicule de remorquage (s’il y a lieu) et vérifier que la machine est libre de tout mouvement"},{"p":3,"t":"2. Assurez-vous que tous les arrêts d’urgence sont désactivés (ils doivent être tirés). Il y en a 3 au total : Un sur chaque boîtier électrique et un « Pull cord » qu’on réactive avec le bouton bleu"},{"p":3,"t":"3. Mettre la « master switch » à On"},{"p":3,"t":"4. Sur le boîtier, mettre la « switch » à 1-Batt"},{"p":4,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 5. Démarrer la télécommande sans fil en maintenant le bouton SFT et en appuyant ensuite le bouton START"},{"p":4,"t":"Maintenir ce bouton et appuyer ensuite sur start 6. Mettre la machine en mode « positioning »"},{"p":4,"t":"7. Démarrer le moteur diésel avec la clé qui se trouve au-dessus de la Master switch"},{"p":4,"t":"8. Augmenter le régime du moteur au maximum pour éviter qu’il cale."},{"p":4,"t":"MODE « POSITIONING » Le mode « positioning » englobe toutes les fonctions reliées au positionnement et au déplacement de la machine."},{"p":4,"t":"Dans ce mode on peut contrôler : • L’extension du mât (MAST EXTEND) • Les tractions de gauche (« TRACTION LEFT ») • Les tractions de droite (« TRACTION RIGHT ») • Le pivot du mât (« TILT ») • L’angle du mât (« DIP ») • Les pattes de coins (« JACKS »)"},{"p":5,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 • L’extension de la table (LONGITUDINAL) • La rotation de la table (« TABLE ROTATE ») • La rotation du mât (MAST ROTATE) • La montée et descente du bras (ARM UP-DOWN) • Le déploiement des « stingers » ("},{"p":5,"t":"SELECTOR IN-OUT) ou le « MAST EXTENSION » (SELECTOR SUR TÉLÉCOMMANDE + BRAS SUR LA TOUR IMAGE)"},{"p":5,"t":"Toutes les fonctions du mode « POSITIONING » peuvent être utilisées lorsque la foreuse fonctionne sur le moteur diesel EXTENSION MÂT (« MAST EXTEND ») La fonction « MAST EXTEND » contrôle un cylindre hydraulique qui déplace le mât sur son assise et peut être actionné avec le LEVIER SELECTOR quand le"},{"p":5,"t":"BRAS SUR LA TOUR EST EN POSITION « MAST EXTEND ». Cette fonction n’est pas proportionnelle. La vitesse de déplacement ne peut donc pas être contrôlée."},{"p":5,"t":"TRACTIONS GAUCHE/DROITE (« TRACTION LEFT/RIGHT ») Les fonctions « TRACTIONS LEFT/RIGHT » permettent de faire tourner les roues de la foreuse dans un sens ou dans l’autre, pour faire avancer ou reculer la foreuse."},{"p":5,"t":"Ces fonctions sont proportionnelles et peuvent être actionnées à l’aide des LEVIERS GAUCHE/DROITE EN VERT. La vitesse maximale transmise par les leviers associés aux tractions peut être augmentée ou diminuée à l’aide du potentiomètre « TRACTION »."},{"p":6,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026"},{"p":6,"t":"LORS DE L’UTILISATION DES TRACTIONS EN DIRECTION OPPOSÉE SUR MODE DIESEL, LA POSITION DU POTENTIOMÈTRE NE DOIT PAS DÉPASSER LA MOITIÉ POUR ÉVITER DE FAIRE CALER LE MOTEUR PIVOT MÂT (« MAST TILT ») La fonction « MAST TILT » permet de déployer le mât dans le but de positionner la machine pour un forage"},{"p":6,"t":"à venir. Cette fonction est proportionnelle et peut être utilisée à l’aide du LEVIER MAST TILT. Plus le levier est enfoncé, plus l’action sera rapide."},{"p":6,"t":"ANGLE DU MÂT (« DIP ») La fonction « DIP » permet d’ajuster l’angle du mât dans le but d’atteindre l’angle de forage désiré. Cette fonction est proportionnelle et peut être actionnée à l’aide du levier #4. Plus le levier est enfoncé, plus l’action sera rapide."},{"p":7,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 PATTES DE COIN (« JACKS ») La fonction « JACK » permet de contrôler les 4 pattes de coins afin de mettre la foreuse au niveau avant de débuter un nouveau forage."},{"p":7,"t":"Cette fonction n’est pas proportionnelle et peut être actionné à l’aide du LEVIER JACK. Toutes les pattes de coin peuvent fonctionner indépendamment."},{"p":7,"t":"Les DEUX LEVIERS « JACK SELECTION » permettent de choisir si on veut actionner : • Les cylindres de gauche (« LEFT»); • Les cylindres de droite (« RIGHT») ; • Les cylindres droit et gauche EN MÊME TEMPS («ALL »); • Les cylindres avant (« FRONT »); • Les cylindres arrière (« REAR ») ; • Les cylindres"},{"p":7,"t":"avant et arrière EN MÊME TEMPS (« ALL »)."},{"p":7,"t":"EXTENSION DE LA TABLE «LONGITUDINAL» La fonction «Longitudinal IN/OUT» contrôle des cylindres situés dans la table qui permettent de faire sortir les 2 extensions de table et atteindre des positions de forage plus éloignées. Cette fonction n’est pas proportionnelle."},{"p":7,"t":"La vitesse de déplacement ne peut donc être contrôlée."},{"p":8,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 ROTATION DU MAT «MAST ROTATE» La fonction «Mast Rotate CW/CCW» permet de tourner le mat de la foreuse CW/CCW et ainsi atteindre les positions de forage, se rapprocher ou s’éloigner de la paroi de forage"},{"p":8,"t":". Cette fonction permet aussi de coucher le mât de la foreuse lors du repliage. Cette fonction est proportionnelle et peut être actionnée à l’aide du levier «Mast Rotate». Plus le levier est enfoncé, plus l’action sera rapide."},{"p":8,"t":"MONTÉE ET DESCENTE DU BRAS «ARM UP/DOWN» La fonction «Arm UP/DOWN» permet d’ajuster la hauteur du bras soutenant le mât pour le positionner à une hauteur adéquate. Cette fonction est proportionnelle et peut être actionnée à l’aide du levier «Arm Up/Down». Plus le levier est enfoncé, plus l’action sera rapide."},{"p":9,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 BRAS DE LA TOUR & SELECTOR IN/OUT Toujours dans le mode «POSITIONING» placer le bras sélecteur de la tour pour choisir la fonction «MAST EXTENTION» Attention au point de coincement, arrêter la foreuse a"},{"p":9,"t":"vant de se rendre près de la tour. Sur la manette, utiliser la fonction «SELECTOR IN» afin relever le mat dans l’assise du mat."},{"p":9,"t":"ATTENTION, LE MOTEUR DIESEL DOIT TOUJOURS ÊTRE ARRÊTÉ AU PLUS BAS RÉGIME POSSIBLE AFIN DE FACILITER LE REDÉMARRAGE"},{"p":9,"t":"PROCÉDURE DE REPLIAGE DE LA DR600-MU Avant de déplacer la machine, il est nécessaire de placer cette dernière en configuration de transport. Pour ce faire, vous devez suivre les étapes suivantes afin d’éviter les bris et les accidents."},{"p":9,"t":"LA FOREUSE DOIT RESTER CONNECTÉE AU 600 VOLTS POUR TOUTE LA DURÉE DES OPÉRATIONS DE PLIAGE-DÉPLIAGE"},{"p":10,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 Le dépliage de la machine peut se faire à partir d’une multitude de positions différentes. Cependant, les étapes du repliage demeurent les mêmes et doivent être effectuées dans l’ordre prescrit par cette procédure."},{"p":10,"t":"LORS DES OPÉRATIONS DE PLIAGE ET DE DÉPLIAGE, L’OPÉRATEUR DOIT SE TENIR À L’EXTÉRIEUR DU RAYON D’ACTION DU MÂT."},{"p":10,"t":"S’IL DOIT S’APPROCHER DE LA FOREUSE, IL DOIT APPUYER SUR « STOP » ET IL DOIT METTRE LA TÉLÉCOMMANDE DANS UN ENDROIT SÛR"},{"p":10,"t":"1. ROT TABLE Tout d’abord, utiliser la fonction «ROT TABLE» (dans le mode «POSITIONNING») afin de ramener la table parallèle à la machine telle qu’illustré."},{"p":11,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 2. LONGITUDINALE Utilisé la fonction «Longitudinale» (dans le mode «POSITIONNING») pour rétracter les extensions de table"},{"p":11,"t":"3. DIP Utiliser la fonction «DIP» (dans le mode «POSITIONINIG») pour positionner le mat à la vertical."},{"p":12,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 4. MAST ROTATE Utiliser la fonction «Mast Rotate CW/CCW» (dans le mode «POSITIONNING») pour enligner le mat parallèle à la «TABLE» de la foreuse."},{"p":12,"t":"5. Bras de la tour & SELECTOR IN/OUT Toujours dans le mode «POSITIONING» placer le bras sélecteur de la tour pour choisir la fonction «MAST EXTENTION» Attention au point de coincement, arrêter la foreuse avant de se rendre près de la tour Sur la manette, utiliser la fonction «SELECTOR IN» afin releve"},{"p":12,"t":"r le mat dans l’assise du mat."},{"p":13,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 6. MAST TILT Utilisez la fonction MAST TILT UP (dans le mode POSITIONING) pour Rabattre la tour sur la table"},{"p":13,"t":"7. MAST ROTATE Utiliser la fonction «Mast Rotate CW/CCW» (dans le mode «POSITIONNING») pour coucher la tour sur le côté gauche de la table lorsqu’on est face à la foreuse. Attention aux boyaux hydrauliques et aux câbles électriques lors de cette manœuvre"},{"p":14,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 8. ARM UP/DOWN & DIP Utiliser la fonction «ARM DOWN» (dans le mode «POSITIONNING») pour descendre l’ensemble de la tour sur le pilier d’assise."},{"p":14,"t":"Utiliser la fonction «DIP» pour ajuster le mat en descendant sur le pilier d’assise de manière a bien l’appuyer. Attention aux boyaux hydrauliques et aux câbles électriques lors de ces manœuvres"},{"p":14,"t":"Bien attacher, les boyaux hydrauliques, les boyaux à eau et le «loading chamber» sur la tour de la foreuse pour éviter les bris de matériels."},{"p":14,"t":"LORS DES DÉPLACEMENTS, L’OPÉRATEUR DOIT : 1- RESTER IMMOBILE; 2- TOUJOURS SE TENIR À PLUS DE 3 MÈTRES DE LA MACHINE; 3- SE POSITIONNER DE MANIÈRE À CE QUE LA MACHINE S’ÉLOIGNE TOUJOURS DE LUI; 4- SE TENIR HORS DE LA LIGNE DE TIR DE LA MACHINE EN CAS DE DÉPLACEMENTS INATTENDU."},{"p":15,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 REMORQUAGE LA DR-600 Nous favorisons le remorquage à partir du côté moteur mais comme l’illustrent les figures suivantes, la foreuse peut être remorquée par l’avant (côté foreuse) ou l’arrière (côté mot"},{"p":15,"t":"eur). *Pour les étapes suivantes, il est primordial d’avoir une bonne communication avec l’opérateur du véhicule remorqueur (Chargeuse navette) et de s’assurer d’être en contact visuel en tout temps."},{"p":15,"t":"Bien que la DR-600-MU soit équipée d’un moteur diesel permettant un déplacement autonome, il est possible de la déplacer à l’aide d’un véhicule remorqueur (Chargeuse navette) afin d’accélérer les déplacements sur une longue distance."},{"p":15,"t":"Si vous devez remorquer la foreuse à l’aide d’un autre véhicule, assurez-vous EN TOUT TEMPS d’avoir une BONNE COMMUNICATION et d’être en CONTACT VISUEL avec l’opérateur du véhicule remorqueur (Chargeuse navette) lors de chacune des étapes suivantes."},{"p":16,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 Voici les étapes à suivre afin de déplacer la foreuse à l’aide d’un véhicule tracteur. 1."},{"p":16,"t":"Démarrez la foreuse en mode électrique ou diesel; *Advenant le cas où le mode diesel est hors-fonction et que le 600 volts n’est pas disponible, il est OBLIGATOIRE de sécurisée l’équipement avec les CALLE DE ROUES disponibles sur le rangement prévu à cet effet pour s’assurer que celui-ci demeure immobile."},{"p":16,"t":"2. Actionner les 4 pattes de coins afin que les roues ne touchent plus au sol; 3. Visser la visse d’engagement au cœur des 4 ensembles de roues. Les 4 ensembles de roues devraient maintenant tourner librement;"},{"p":16,"t":"4. Relier la main de remorquage à l’équipement de remorquage et les chaînes de sécurité à la foreuse et à l’équipement de remorquage EN ‘’X’’."},{"p":17,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 Pour des raisons évidentes de sécurité afin de s’assurer de ne pas s’exposer entre la chargeuse navette et la foreuse un objet(ex; une chaudière vide, un bloc de bois ou les fourches d’un tracteur ) doi"},{"p":17,"t":"t être placé sous la tongue pour la soutenir et permettre ne pas s’exposer durant l’approche et l’accouplement du véhicule remorqueur sur celle-ci."},{"p":18,"t":"PROCÉDURE DE DÉPLACEMENT ET DE REMORQUAGE DE LA DR-600-MU #2923 Juillet 2023 Révision Janvier 2026 5. Remontez les pattes de coins complètement; Si vous aviez utilisé les calles de roue à l’étape 1, veuillez les retirer et passer à l’étape 9 si celle-ci n’a pas été fait. 6. Arrêter la foreuse; 7."},{"p":18,"t":"Fermer le disjoncteur principal de la foreuse; 8. Débrancher le câble de 600V et l’alimentation en eau 9. Enroulez le câble de l’écran sur le réservoir à eau et le sécuriser en l’attachant à l’aide de sangles."},{"p":18,"t":"LA FOREUSE EST MAINTENANT PRÊTE À ÊTRE REMORQUÉE DÉCROCHAGE DE LA FOREUSE DU VÉHICULE DE REMORQUAGE 1."},{"p":18,"t":"Démarrez la foreuse en mode électrique ou diesel; Advenant le cas où le mode diesel est hors-fonction et que le 600 volts n’est pas disponible, il est OBLIGATOIRE de sécuriser l’équipement avec les CALLE DE ROUES 2. Actionner les 4 pattes de coins afin que les roues ne touchent plus au sol; 3."},{"p":18,"t":"Dévisser la visse d’engagement au cœur des 4 ensembles de roues. Les 4 ensembles de roues ne devraient pas tourner librement. Les roues devraient être engagés; 4."},{"p":18,"t":"Détacher la foreuse et les chaînes de sécurité du véhicule de remorquage et placer un objet (ex; une chaudière vide, un bloc de bois ou les fourches d’un tracteur) sous la tongue pour vous permettre de désaccoupler le véhicule remorqueur. 5."},{"p":18,"t":"Démarrer la foreuse en mode électrique ou en mode diesel; 6. Actionner les 4 pattes de coins afin que les roues reviennent au sol."},{"p":18,"t":"Ajouts ou modifications Date Par Changé photos des sling pour celles avec les chaînes page #16. Les sling ont été changées pour des chaînes suite à un bris Septembre 2025 S. Tremblay F. Croteau"},{"p":18,"t":"Préciser les outils pour soutenir la tongue (accident mal de dos) Janvier 2026 S. Tremblay É. Thibeault"},{"p":18,"t":"______________________________ Christian St-Amour Directeur des Opération"}],"pro-dd-st-001":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-001"},{"p":1,"t":"Commencement d’un trou de forage avec un core barrel de 1,5 m"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour commencer un trou de forage avec un core barrel de 1,5 m APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et de voir au bon déroulement des opérations et de la qualité du travail accompli."},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES Core barrel ronde de 1,5 m"},{"p":1,"t":"Reaming shell 6 ‘’"},{"p":1,"t":"Locking coupling"},{"p":1,"t":"Locking adapter"},{"p":1,"t":"Tige de forage de 3 m"},{"p":1,"t":"EPI OBLIGATOIRES Équipements de base obligatoires"},{"p":2,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-001"},{"p":2,"t":"Commencement d’un trou de forage avec un core barrel de 1,5 m"},{"p":2,"t":"1. Installer le bearing avec le bushing modifié sur le couvercle du clam, s’assurer que le bearing est en bonne condition."},{"p":2,"t":"2. Mettre le core barrel complet (reaming shell de 6 pouces, core barrel de 1,5 m, locking adapter et locking coupling) Il est important de vérifier le reaming shell avec la jauge à shell pour vérifier l’usure et remplacer si nécessaire."},{"p":3,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-001"},{"p":3,"t":"Commencement d’un trou de forage avec un core barrel de 1,5 m"},{"p":3,"t":"3. Mettre le tube de 1,5m dans le core barrel avec la backend"},{"p":3,"t":"4. Mettre la tige de forage de 3 mètres avec le water swivel. Il est très important de bien graisser les filets."},{"p":3,"t":"5. Forer au complet le core barrel de 1,5 mètre et la tige de 3 mètres pour s’assurer d’avoir l’espace nécessaire pour mettre le core barrel de 3 mètres. -Forer 2 tiges de 3 mètres si vous voulez vous mettre en 6 mètres"},{"p":3,"t":"6. Mettre le core barrel complet dans la tête et le clam de la foreuse (3 mètres ou 6 mètres selon le cas) et insérer le tube carottier avec la backend"},{"p":3,"t":"7. Mettre la tige de forage de 3 mètres avec la water swivel"},{"p":3,"t":"8. Reculer la tête de la foreuse au-dessus du joint de la tige de forage et du core barrel"},{"p":4,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-001"},{"p":4,"t":"Commencement d’un trou de forage avec un core barrel de 1,5 m"},{"p":4,"t":"9. Dévisser la tige de forage et lever la tête de la foreuse jusqu’à ce qu’il y a suffisamment d’espace pour retirer le bushing modifié et mettre le bushing standard sur la tige de forage, revisser la tige sur le core barrel"},{"p":4,"t":"10. Insérer le core barrel à l’intérieur du trou jusqu’au fond pour qu’il ne soit plus à l’intérieur du clam"},{"p":4,"t":"11. Boulonner le bearing avec le bushing standard sur le clam une fois le core barrel au fond du trou."},{"p":4,"t":"_____________________________ Christian St-Amour Directeur des Opérations"}],"pro-dd-st-002":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":1,"t":"VIDER LE TUBE CAROTTIER"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour vider le tube carottier. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et le superviseur et responsable de voir au bon déroulement des opérations et à la qualité du travail accompli."},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES Tube carottier Marteau Core case Core knoker Anneau en acier Clé à tube"},{"p":1,"t":"EPI OBLIGATOIRES Équipements de base obligatoires"},{"p":1,"t":"1. Dévisser la backend en utilisant les 2 clés à tube, et le ranger dans un endroit sécuritaire."},{"p":2,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":2,"t":"VIDER LE TUBE CAROTTIER"},{"p":2,"t":"2. Vider le tube de manière à ne jamais s’exposer les mains en avant du tube carottier Mettre les mains en avant du tube lorsque la roche sort pourrait causer des blessures graves."},{"p":2,"t":"3. Placer les carottes au fur et à mesure (cela évite de les mélanger)"},{"p":2,"t":"4. Lorsqu’on doit casser la carotte à la fin d’une rangée, mettre la carotte dans la rangée et la casser en frappant avec le marteau."},{"p":3,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":3,"t":"VIDER LE TUBE CAROTTIER"},{"p":3,"t":"Ne jamais tenir la rocher dans les mains pour la casser avec le marteau."},{"p":3,"t":"5. Si le tube est bloqué, glisser l’anneau sur le tube et frapper dessus avec le marteau jusqu’à ce que la carotte tombe, recommencer au besoin. Il ne faut pas tenir l’anneau avec les mains quand on frappe."},{"p":3,"t":"Ne jamais frapper directement sur le tube avec le marteau pour ne pas le bosser"},{"p":4,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":4,"t":"VIDER LE TUBE CAROTTIER"},{"p":4,"t":"6. Lorsque que la carotte est coincée dans le core case, insérer le core knocker sur le bout du core case et le tube. Frapper sur le percuteur avec le marteau ou une petite masse, ceci empêche les éclats de roches."},{"p":4,"t":"Ne jamais regarder dans le tube pour voir s’il est vide, insérer plutôt une tige de métal d’un pied dans l’extrémité et la faire glisser dans le tube. Ne jamais effectuer de mouvement de va-et-vient avec le core knocker pour ne pas se coincer les doigts entre le core knocker et le tube"},{"p":4,"t":"7. Quand le tube est bloqué loin du bout du tube, insérer une tige d’acier d’un pied dans le tube, glisser l’anneau sur le tube et frapper dessus jusqu’au déblocage"},{"p":4,"t":"Il est interdit d’insérer une longue tige d’acier dans le tube et d’effectuer un mouvement de va-et-vient avec la tige pour frapper la carotte"},{"p":4,"t":"8. Quand le tube est vide, vérifier le bon fonctionnement du core spring en utilisant un bout de carotte pour voir s’il la retient bien;"},{"p":4,"t":"9. Après vérification, il est important de graisser le core spring et le core case pour éviter l’usure prématurée."},{"p":5,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":5,"t":"VIDER LE TUBE CAROTTIER"},{"p":5,"t":"10. Remettre la backend sur le tube et faire une bonne inspection visuelle, ne pas oublier de bien la graisser pour éviter l’usure prématurée."},{"p":5,"t":"11. Entreposer le tube dans un endroit sécuritaire en attendant sa prochaine utilisation, ne jamais mettre les tubes par terre ou à la hauteur du visage."},{"p":6,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-002"},{"p":6,"t":"VIDER LE TUBE CAROTTIER"},{"p":6,"t":"12. Avant de fermer une boite pleine toujours s’assurer que les blocs de métrage soient bien placés et initialisés et que votre numéro de boite soit bien inscrit,"},{"p":6,"t":"13. Le foreur doit toujours vérifier les boites avant qu’elles soient fermées."},{"p":6,"t":"Ajouts ou modifications Date Par Point #6 ajouter interdiction des mouvements de va-et-vient. Point #7 : ajout d’une méthode sécuritaire et d’interdictions lors du blocage du tube loin du bord. 6 mai 2021 S. Tremblay"},{"p":6,"t":"___________________________ Christian St-Amour Directeur des Opérations"}],"pro-dd-st-003":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":1,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour la fabrication d’un plancher pour foreuse aux diamants sous terre APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et le superviseur et responsable de voir au bon déroulement des opérations et à la qualité du travail accompli. TOUJOURS TRANSPORTER LES GROSSES PIÈCES DE BOIS À DEUX."},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES -bois brut préférablement de 6’’ X 6’’ ou de 8’’ X 8’’ Pied de biche (arrache-clous) -bois brut de 3’’X8’’ ou 3’’ X 6’’ Hache -Coin de bois Marteau -bois de construction 2’’ X 4’’ planés ou bruts Sciotte -clous 3 1/ 2’’ et 6’’ Pinces à billots"},{"p":1,"t":"Scie va-et-vient avec lame à bois -Scie à chaîne (approbation du superviseur) Niveau de 48’’"},{"p":1,"t":"ÉPI nécessaires"},{"p":1,"t":"Équipement de base obligatoire Gants spéciaux pour la scie à chaîne Pantalons de protection pour scie à chaîne Visière"},{"p":2,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":2,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025"},{"p":2,"t":"Le superviseur doit d’abord avoir fait une inspection des lieux avant de déplacer les équipements à l’endroit de forage. Il doit s’assurer que : • Que le plancher est exempt de débris • Que le plancher est plat • Que les fonds de trous ont été trouvés et marqués"},{"p":2,"t":"1- Placer la structure de base en 8’’X8’’ ou les 6’’X6’’dans le sens contraire du forage de façon à ce que les patins de la foreuse croisent les 8’’X8’’, selon le plan et devis (azimut du forage)"},{"p":2,"t":"2- Placer les 8’’X8’’ à une distance de 48’’, et les 6’’X6’’ à une distance de 36’’"},{"p":2,"t":"3- Placer le plancher au niveau en utilisant un niveau de 48’’ et un morceau de 3’’X8’’ de 8 pieds minimum pour avoir une plus grande porter et avoir de meilleurs résultats • Pour mettre les 8’’X8’’ ou 6’’X6’’ au niveau, couper des 8’’X8’’ ou 6’’X6’’ en bout de 36’’ pour faire des cages selon la haut"},{"p":2,"t":"eur désirée • Utiliser des coins de bois pour égaliser la structure de base."},{"p":2,"t":"4- Une fois la base au niveau, mettre les 3’’X8’’ de bois brut en les disposant dans le sens contraire des 8’’X8’’ ou 6’’X6’’"},{"p":3,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":3,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025"},{"p":3,"t":"5- Une fois les 3’’X8’’ disposés s’assurer que les extrémités soient clouées sur un morceau de la structure de base."},{"p":3,"t":"6- À l’entrée du plancher, les 3’’X8’’ doivent être coupés de manière carrée et égale avec le bord du plancher pour ne pas trébucher sur des morceaux inégaux."},{"p":3,"t":"7- Si le plancher est plus haut que 12 pouces une construction de marche devra être faite. Elles devront avoir une profondeur de 8’’ minimum, une largeur de 36’’ minimum, un maximum de 60’’ de largeur et une hauteur maximum de 12 pouces."},{"p":4,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":4,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025 8- Si le plancher est plus haut que 12 pouces, des garde-corps devront être installés et respecter l’article 12 du RSST :"},{"p":4,"t":"12. Garde-corps: Tout garde-corps incorporé à un bâtiment, à l’exception de celui dont est muni un équipement, doit être conforme au Code national du bâtiment tel qu’il se lit au moment de son installation."},{"p":4,"t":"Les autres garde-corps doivent être conçus, construits et installés de façon à résister aux charges minimales suivantes: 1° une charge ponctuelle horizontale de 0,55 kN appliquée en un point quelconque de la lisse supérieure; 2° une charge verticale de 1,5 kN, par mètre linéaire, appliquée à la lisse"},{"p":4,"t":"supérieure. De plus, de tels garde-corps doivent posséder une lisse supérieure située entre 900 mm et 1 100 mm du plancher et au moins une lisse intermédiaire fixée à la mi-distance entre la lisse supérieure et le plancher. La lisse intermédiaire peut être remplacée par des balus"},{"p":4,"t":"9- Une lisse inférieure doit être ajoutée pour les endroits sur le plancher où les travailleurs ont accès"},{"p":4,"t":"10- S’il y a plus d’une marche il devra avoir des mains courantes."},{"p":4,"t":"Lisse supérieure Lisse intermédiaire Lisse inférieure (coup de pied)"},{"p":5,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":5,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025"},{"p":5,"t":"PLANCHER SECONDAIRE"},{"p":5,"t":"1- S’il y a une construction d’un autre plancher pour se surélever à côté de la tour : a. Il devra avoir un minimum de 32’’ de largeur par 72’’ de long et un maximum de 12’’ de hauteur; b. Aucun morceau ne doit se retrouver en porte-à-faux, et doit être bien appuyés sur des travers en dessous; c."},{"p":5,"t":"Les 2 dernières planches les plus près de la foreuse doivent être vissées à l’aide de tire-fonds; d. La dernière planche doit se rapprocher à au moins 3 pouces de la tour;"},{"p":5,"t":"e. À chaque changement d’azimut, de degrés ou d’angle de forage, les 2 dernières planches devront être modifiées pour s’ajuster au contour de la foreuse. f. Les garde-corps devront aussi être ajustés pour fermer les ouvertures créées par le déplacement g. L’ajout de bois plané sur les planchers n’est pas toléré"},{"p":5,"t":"DÉMANTÈLEMENT APRÈS LA DÉMOBILISATION DE LA FOREUSE"},{"p":5,"t":"1. Démanteler d’abord le plancher secondaire si nécessaire"},{"p":5,"t":"2. Démanteler ensuite le plancher principal en commençant toujours par les planches du fond,"},{"p":5,"t":"3. Toujours enlever les clous à mesure que les planches sont enlevées,"},{"p":5,"t":"4. Lorsque toutes les planches sont retirées et les clous tous enlevés, démanteler la structure de base en 6’’X6’’ ou en 8’’X8’’."},{"p":5,"t":"5. L’accumulation de boue de forage sous le plancher peut rendre les déplacements difficiles et instables :"},{"p":5,"t":"a. Se positionner dans la partie la plus solide et stable; b. Demeurer vigilant et garder les pieds solides au sol; c. Commencer au fond de la baie de forage;"},{"p":6,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":6,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025 d. Travailler de manière à faire glisser les pièces de bois les unes sur les autres pour les sortir de leur position;"},{"p":6,"t":"APRÈS LA FIN DU DÉMANTÈLEMENT"},{"p":6,"t":"1. Installer une clôture orange."},{"p":6,"t":"2. Installer une carte de ruban rouge avec les inscriptions suivantes :"},{"p":6,"t":"a. Trou non arpenté et non cimenté b. Date de l’installation c. Nom du superviseur"},{"p":6,"t":"CRITÈRES DÉCISIONNELS POUR LE CHOIX DES TYPES DE PLANCHERS EN FONCTION DES SITUATIONS PARTICULIÈRES"},{"p":6,"t":"Certaines situations nécessitent que les planchers soient plus petits et de formes différentes. Comme, par exemple, pour des trous courts avec une foreuse qui n’est pas de type ‘’MOBILE’’ mais qui est utilisée comme telle."},{"p":6,"t":"1- 0 à 49 mètres sur le même set-up et/ou trou sans changement de bit ou arrachage de tiges : a. Plancher 10 X 8 sans ajout de support à tiges (largeur minimum) debout"},{"p":6,"t":"2- Si un changement de bit est connu pendant le forage d’un ou plusieurs trous sur un même set-up et moins de 100 m a. Ajout d’un support à rod (largeur minimum) debout selon le nombre de tiges à arracher"},{"p":6,"t":"3- 49 à 499 mètres ou dès que nous savons que nous devons arracher des tiges pour un changement de bit ou autres : a. Plancher 10 X 16 avec l’ajout d’un support à tiges (largeur minimum) debout"},{"p":6,"t":"4- 500 mètres et plus: a. Plancher complet 16 X 32"},{"p":6,"t":"L’ajout du support à tiges debout sert à diminuer le nombre de tiges à manipuler et à mettre sur le support couché."},{"p":7,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-003"},{"p":7,"t":"FABRICATION D’UN PLANCHER POUR FOREUSE AUX DIAMANTS SOUS TERRE Avril 2019 Janvier 2025"},{"p":7,"t":"_________________________ Christian St-Amour Directeur des Opérations"},{"p":7,"t":"Correctifs apporteés Date Par Ajout lisse inférieure point 9 19-11-2020 S. Tremblay Ajout de la partie plancher secondaire suite à événement d’entorse cheville 1-09-2022 S."},{"p":7,"t":"Tremblay Ajouter OU BRUT après (2X4) planés dans le tableau matériel nécessaire à cause du manque de disponibilité du bois plané 27-09-2024 S. Tremblay Ajout de la partie ‘’Planchers dans situations particulières 21-01-2025 S. Tremblay S. Desrosiers"}],"pro-dd-st-004":[{"p":1,"t":"23 octobre 2020 PROCÉDURE DE TRAVAIL"},{"p":1,"t":"PROCÉDURE DE RÉCUPÉRATION DE TUBE CAROTTIER AVEC LE LOADING CHAMBER OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour extraire un tube carottier avec le loading chamber APPLICATION Cette procédure s’applique à tous les employés de forage aux diamants de INTERPRÉTATI"},{"p":1,"t":"ON Le personnel ayant l’autorité pour l’interprétation de ce document est le Directeur des Opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS Les foreurs et les aides-foreurs doivent respecter cette procédure et les superviseurs doivent s’assurer que les travailleurs la respectent."},{"p":1,"t":"Attention aux brins saillants et câble endommagé. Une inspection visuelle doit être faite avant la manipulation du câble Wire line. Si le câble est endommagé, il est obligatoire de retirer ce dernier. PROCÉDURE 1- Effectuer les manœuvres pour casser la carotte de forage avec la foreuse"},{"p":1,"t":"2- Arrêter la pompe à l’eau"},{"p":2,"t":"23 octobre 2020"},{"p":2,"t":"3- Purger la pression d’eau dans les tiges de forage à l’aide de la vanne de purge"},{"p":2,"t":"4- Retirer le boyau a l’eau à l’extrémité du «water swivell»"},{"p":2,"t":"5- Mettre la transmission en première vitesse avant de dévisser la water swivell"},{"p":2,"t":"6- Dévisser la «water swivell a l’aide de la tête de la foreuse, elle doit être munis d’un adaptateur long pour effectuer la manœuvre. Pour les adaptateurs courts, la tige de forage devra être retirée au complet avec la tête de la foreuse. IL EST INTERDIT D’UTILISER UN PIPE WRENCH POUR DÉVISSER LA WATER SWIVELL"},{"p":2,"t":"7- Installer le «loading chamber» avec «l`over shot»"},{"p":2,"t":"8- Connecter le boyau a l’eau"},{"p":3,"t":"23 octobre 2020 9- Serré les caoutchoucs du «loading chamber» avec la clé à molette"},{"p":3,"t":"10- Évacuer la zone de travail derrière les portes de sécurité et refermer les portes. -aucun travailleur ne doit se trouver à l’intérieur de la zone de travail lorsqu’ il y a mouvement du treuil. La porte d’accès à la zone de travail doit être fermée. exception : lors de changement de câble sur le treuil"},{"p":3,"t":"11- Activer la pompe à l’eau"},{"p":4,"t":"23 octobre 2020 12- Quand ‘’l`over shot‘’ est arrivé au fond du trou, purger la pression d’eau dans les tiges de forage"},{"p":4,"t":"13- Desserrer le caoutchouc du «loading chamber» avec la clé à molette"},{"p":4,"t":"14- Évacuer la zone de travail"},{"p":4,"t":"15- Tiré le tube carottier en utilisant la commande du treuil jusqu’ à l’arrivée de celui-ci dans le «loading chamber» Il est obligatoire d’avoir le loading chambers en place en tout temps jusqu’à la remontée du tube au collet pour éviter l’éjection du tube lors d’interception de veine d’eau ou de gaz"},{"p":4,"t":"16- Enlever le boyau à eau"},{"p":4,"t":"17- Retirer le loading chamber et le déposer entre les patins pour garder le plancher libre de tout obstacle"},{"p":5,"t":"23 octobre 2020 18- Retirer le tube carottier des tiges de forage. A cette étape seulement, Il est permis à l’aide foreur de rester dans la zone de travail et d’utiliser le dead man pour sortir le tube des tiges."},{"p":5,"t":"19- Installer les pinces à tube si le trou est descendant"},{"p":5,"t":"20- Pour le forage en 6 mètres (Quand les deux tubes sont dévissés) : a. Le travailleur qui tient le tube à l’intérieur des tiges doit garder un contact visuel sur son partenaire qui s’éloigne avec l’autre tube. b."},{"p":5,"t":"Une fois que celui-ci a traversé la porte, le deuxième tube pourra alors être sorti des tiges. c. La même procédure devra être suivie en réinsérant les tubes dans les tiges de forage."},{"p":5,"t":"21- Entreposer le(s) tube(s) carottier(s) sur la table"},{"p":5,"t":"Ajouts ou modifications Date Par Ajout la vérification du wireline (brins saillants) 26-01-2026 S. Tremblay"},{"p":5,"t":"______________________________ Christian St-Amour Directeur des Opérations"}],"pro-dd-st-006":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-006"},{"p":1,"t":"RECUPERATION DU TUBE CAROTTIER AVEC UN OVERSHOT DE SURFACE"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour la récupération du tube carottier avec un over shot de surface APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et de voir au bon déroulement des opérations. Le superviseur doit s’assurer que la procédure est respectée."},{"p":1,"t":"Attention aux brins saillants et câble endommagé. Une inspection visuelle doit être faite avant la manipulation du câble Wire line. Si le câble est endommagé, il est obligatoire de retirer ce dernier."},{"p":1,"t":"1. Brisé la carotte de forage au fond du trou à l’aide de la foreuse"},{"p":1,"t":"2. Arrêter la pompe à l’eau"},{"p":2,"t":"RECUPERATION DU TUBE CAROTTIER AVEC UN OVERSHOT DE SURFACE"},{"p":2,"t":"3. Purgé la pression d’eau dans les tiges de forage à l’aide de la valve de purge;"},{"p":2,"t":"4. Retirer le boyau à l’eau à l’extrémité du water swivel;"},{"p":2,"t":"5. Mettre la transmission en première vitesse et à l’aide de la foreuse dévisser la water swivel;"},{"p":2,"t":"6. La water swivel doit être munies d’un adapteur long pour effectuer cette tâche;"},{"p":2,"t":"7. Pour les adapteurs courts, la tige de forage devra être retirée au complet avec la tête de la foreuse"},{"p":2,"t":"EN AUCUN CAS LE PIPE WRENCH NE DOIT ÊTRE UTILISÉ POUR DÉVISSER LA WATER SWIVEL."},{"p":2,"t":"8. Envoyer l’overshot de surface à l’intérieur des tiges de forage"},{"p":2,"t":"9. Évacuer la zone de travail"},{"p":3,"t":"RECUPERATION DU TUBE CAROTTIER AVEC UN OVERSHOT DE SURFACE"},{"p":3,"t":"10. Activer la commande du treuil pour faire descendre l’overshot. Ne pas faire descendre trop rapidement pour garder une tension sur le câble."},{"p":3,"t":"11. Lorsque l’overshot arrive au fond, activer la commande du treuil pour remonter le tube carottier;"},{"p":3,"t":"12. Remonter doucement au début pour être sûr que le tube carottier est bien accroché avant de remonter à pleine puissance."},{"p":3,"t":"13. Lorsque le tube carottier arrive au collet, tirer le tube à l’extérieur des tiges de forage et installer les pinces à tube."},{"p":3,"t":"14. Retirer l’overshot de surface du tube carottier. Lors du travail à deux, s’assurer d’une bonne communication"},{"p":4,"t":"RECUPERATION DU TUBE CAROTTIER AVEC UN OVERSHOT DE SURFACE"},{"p":4,"t":"12. Entreposer l’overshot de surface dans un endroit sécuritaire."},{"p":4,"t":"13. Retirer le tube carottier des tiges de forage"},{"p":4,"t":"14. Pour le forage en 6 mètres :"},{"p":4,"t":"a. Quand les 2 tubes sont dévissés, le travailleur qui tient le tube à l’intérieur des tiges de forage doit garder un visuel sur son partenaire qui s’éloigne avec l’autre tube;"},{"p":4,"t":"b. Quand ce dernier a traversé les portes, le deuxième tube pourra être sorti des tiges de forage."},{"p":5,"t":"RECUPERATION DU TUBE CAROTTIER AVEC UN OVERSHOT DE SURFACE"},{"p":5,"t":"15. Entreposer le(s) tube(s) carottier(s) dans un endroit sécuritaire"},{"p":5,"t":"Ajouts ou modifications Date Par Ajout la vérification du wireline (brins saillants) 26-01-2026 S. Tremblay"},{"p":5,"t":"____________________________ Christian St-Amour Directeur des Opérations"}],"pro-dd-st-007":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":1,"t":"OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour l’utilisation de la pompe 435 lors des travaux de cimentation APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS Le superviseur doit s’assurer que les travailleurs appliquent cette procédure et qu’ils portent les ÉPI obligatoires. Les travailleurs doivent appliquer la procédure en tout temps."},{"p":1,"t":"ÉPI OBLIGATOIRES PERMIS OBLIGATOIRES FORMATIONS OBLIGATOIRES • Équipements de protection de base sur le site • Masque powerflow • N/A • Cimentation • Formation sur les protections respiratoires"},{"p":2,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":2,"t":"• Gants caoutchouc extra longs pour la cimentation • Habit caoutchouc (imperméable) • Couvre-tout tyvek blanc avec dossard réfléchissante ou couvre-tout tyvek orange avec bande réfléchissante • Crème protectrice • Fit test pour masque powerflow"},{"p":2,"t":"MATÉRIEL NÉCESSAIRE"},{"p":2,"t":"ÉQUIPEMENTS PRODUITS • Pompe à ciment 435 • Pulvérisateur • Extincteur • Douches oculaires (minimum 2) • Trousse de premiers soins • Trousse de déversement"},{"p":2,"t":"• Ciment type 30 HE ou GU • Huile végétale"},{"p":2,"t":"TROUSSE D’URGENCE OBLIGATOIRE SUR LE SITE"},{"p":3,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":3,"t":"1- Faire une inspection complète de la pompe tel que décrit dans la procédure sur l’inspection et entretien d’une pompe à ciment;"},{"p":3,"t":"2- S’assurer que la pompe à ciment est bien propre et exempte de tout résidus de ciment. Les résidus de ciment durcis peuvent boucher la pompe lors du pompage;"},{"p":3,"t":"3- Bien huiler avec de l’huile végétale avec un pulvérisateur toutes les composantes du mélangeur et de la pompe qui seront en contact avec le ciment (sec ou humide). Le nettoyage se fera plus facilement après les travaux."},{"p":3,"t":"4- Connecter l’alimentation d’eau au header, ne pas oublier de mettre les barrures CHICAGO; 5- Bien tenir et blower le boyau à l’eau; 6- Raccorder un boyau de la pompe à ciment jusqu’au distributeur à eau; (barrures CHICAGO); 7- Vérifier si les boyaux sont bien raccordés;"},{"p":4,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":4,"t":"8- Mettre les EPI avant de commencer la cimentation. ÉPI CHOIX #1 CHOIX #2"},{"p":4,"t":"- Enfiler le couvre-tout tyvek par-dessus le couvre-tout de travail. - S’assurer que la fermeture éclair soit fermée complètement. - Enfiler le couvre-tout par-dessus les bottes de sécurité."},{"p":4,"t":"- Mettre le dossard haute-visibilité par-dessus le couvre tout tyvek blanc - Appliquer de la crème protectrice sur les mains et poignets. - Enfiler les gants extra longs."},{"p":4,"t":"- Enfiler le masque power flow, activer le ventilateur et ajuster le masque - Enfiler le casque de sécurité - Il est interdit de circuler à l’extérieur de la zone de travail. - Changer de couvre-tout lorsqu’ il y a éclaboussures ou bris de celui-ci."},{"p":5,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":5,"t":"- Une bonne inspection de l’intérieur des gants doit être faite avant chaque utilisation. Le port des EPI est obligatoire à partir du moment où l’on commence à manipuler les sacs de ciment jusqu’à ce que le nettoyage complet de la machine à ciment soit terminé."},{"p":5,"t":"- Enfiler les pantalons, ajuster ceux-ci et les mettre par-dessus les bottes de sécurité. - Enfiler le manteau et boutonner au complet. - Appliquer de la crème protectrice sur les mains et poignets. - Enfiler les gants extra longs."},{"p":5,"t":"- Enfiler le masque power flow, activer le ventilateur et ajuster le masque. - Enfiler le casque de sécurité"},{"p":5,"t":"1. S’assurer que la pompe, les poches de ciment et tous les outils soient bien disposés dans la place de travail;"},{"p":5,"t":"2. S’assurer que les boyaux (hydrauliques et tuyau jaunes) sont bien raccordés à la MARGOT PLUG ou VK PLUG et/ou clamés avec des pinces-grip à chaîne sur l'adapteur NPT 3/8 fileté à un bout :"},{"p":6,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":6,"t":"a. Dans un trou ou il y a de l'injection on connecte un boyau # 16 à la MARGO PLUG ou VK plug, une procédure de cimentation doit être émise par l'ingénierie b."},{"p":6,"t":"Dans un trou descendant ou il n'y a pas d'injection de ciment, on cimente à l'aide de boyaux jaunes ''Grout tube'' en l'insérant jusqu'à la profondeur désirée. Le pompage se fait par ce même boyau;"},{"p":6,"t":"c. Dans un trou ascendant ou il n'y a pas d'injection de ciment, on cimente à l'aide de boyaux jaunes ''Grout tube'' en insérant un boyau d'évent jusqu'à la profondeur ou l'on veut pousser le ciment."},{"p":6,"t":"On insère un deuxième boyau de plus ou moins 3-4 mètres, le pompage se fait par ce deuxième boyau jusqu'à atteindre le boyau d'évent inséré à la profondeur désirée."},{"p":6,"t":"i. Un bouchon de résine ou de ciment en bâton doit être fait au collet du trou autour des boyaux insérés au préalable. ii."},{"p":6,"t":"Une fois le pompage terminé, le boyau ou l'on pompe le ciment doit être plié en deux et 2 ty-rap doivent le tenir plié jusqu'à ce que le temps de cure de 24hrs soit complété pour empêcher le ciment de ressortir du boyau."},{"p":6,"t":"d. Dans un trou descendant ou l'on cimente par les tiges de forage : se référer à la procédure PRO-SYN-14 CIMENTATION AVEC ACIER DE FORAGE"},{"p":6,"t":"LA FOREUSE DOIT ÊTRE CADENASSÉE LORS DU REMONTAGE/DÉMONTAGE DE LA POMPE ET LORS DU NETTOYAGE OU DÉBLOCAGE DES MÉLANGEURS DES CUVES DE POMPAGE"},{"p":6,"t":"LES GARDES DOIVENT ÊTRE EN PLACE EN TOUT TEMPS AVANT LA MISE EN MARCHE POUR TESTER LES COMPOSANTES ET DURANT TOUT LE PROCESSUS DE CIMENTATION"},{"p":6,"t":"3. Mettre de l’eau dans la cuve de pompage;"},{"p":6,"t":"4. Faire fonctionner toutes les composantes en même temps qu’on met de l’eau;"},{"p":6,"t":"5. Démarrer la pompe;"},{"p":6,"t":"6. Vérifier le fonctionnement du manomètre à la sortie de la pompe;"},{"p":7,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":7,"t":"7. Si l’eau ne s’accumule pas dans la cuve et qu’elle sort au bout de la valve de purge, la pompe est prête à être utilisée; Avant de Manipuler les poches de ciment :"},{"p":7,"t":"8. Ajouter la quantité d’eau dans le mélangeur de la machine selon la recette :"},{"p":7,"t":"a. LE MÉLANGE DE D’EAU ET DE CIMENT DOIT TOUJOURS ÊTRE DE :"},{"p":7,"t":"i. 8 POCHES DE CIMENT POUR 123 LITRES D’EAU"},{"p":7,"t":"ii. OU 4 POCHES POUR 60 LITRES D’EAU"},{"p":7,"t":"Une coulée de 8 sacs rempli un trou sur une longueur d’environ :"},{"p":7,"t":"- 70m dans un trou de forage BQ;"},{"p":7,"t":"- 45m dans un trou de forage NQ;"},{"p":7,"t":"ATTENTION CES LONGUEURS SONT ESTIMÉES ET CIMENTÉES DANS UN TERRAIN NON FRACTURÉ"},{"p":7,"t":"9. Mettre l’eau dans le mélangeur en marche;"},{"p":7,"t":"10. Ajouter les sacs de ciment TYPE 30 par petites quantités dans l’eau selon la recette;"},{"p":7,"t":"11. Laisser mélanger pendant 5 minutes afin que le mélange soit homogène;"},{"p":7,"t":"12. Une fois le mélange homogène, vider le ciment mélangé dans la cuve de pompage;"},{"p":7,"t":"a. TROUS DESCENDANTS de -9 à -90 degrés sans pression d’eau i. Descendre le tube jaune au fond du trou de forage; ii. Laisser 3 m au fond pour ne pas obstruer le tube; iii. Raccorder à l’aide d’unions 3/8 à la pompe à ciment; iv. Ouvrir la valve du tube jaune; v. Démarrer le pompage du ciment; vi."},{"p":7,"t":"Retirer le boyau à coup de 30 pieds maximum; vii. S’assurer que la pression ne monte pas durant le pompage :"},{"p":8,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":8,"t":"1. Si la pression commence à monter à plus de 30 psi, remonter le tube vers le collet du trou d’une dizaine de pieds; 2. Si la pression continue de monter, arrêter le pompage et sortir le tube complètement; 3. Repartir la pompe et surveiller si le ciment sort au bout du tube; 4."},{"p":8,"t":"Si oui, arrêter la pompe et remettre boyau ou est rendu le ciment; 5. Si non, le tube est bloqué. Il faut le changer."},{"p":8,"t":"viii. La cimentation est terminée quand le trou déborde"},{"p":8,"t":"b. Quand il y a pression d’eau dans le trou, i. Installation d’une plug MARGO par la mine 1. Se connecter sur la MARGO avec le boyau hydraulique #16 et partir la pompe ; 2."},{"p":8,"t":"Le trou est plein quand la pression dépasse la pression d’eau initiale (la pression sera déterminée par l’ingénierie); Ou : ii. Installation d’une VK plug 1. Installer l’adapteur VK 2. Installer une tige de la longueur appropriée 3. Installer la swivel sur la tige 4."},{"p":8,"t":"Installer le boyau hydraulique #16 sur la swivel 5. Démarrer la foreuse 6. Le trou est plein quand la pression dépasse la pression d’eau initiale (la pression sera déterminée par l’ingénierie);"},{"p":8,"t":"EN AUCUN TEMPS, SE METTRE DEVANT LE BOUT DU BOYAU. UN DÉBLOCAGE SOUDAIN CAUSERAIT DES BLESSURES GRAVES"},{"p":8,"t":"c. TROUS ACSENDANTS sans pression d’eau i. Insérer le tube jaune de ventilation coupé en biseau au collet du trou sur la longueur à cimenter; ii. Laisser une longueur suffisante à l’extérieur du trou pour avoir accès au bout du boyau et pour pouvoir le replier à la fin de l’opération; iii."},{"p":8,"t":"Insérer le boyau de cimentation deux pieds à l’intérieur du trou;"},{"p":9,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":9,"t":"iv. Laisser une longueur suffisante à l’extérieur du trou pour se raccorder à la pompe; v. Insérer la plug pour retenir les deux tubes dans le trou : 1. Insérer la jute à 1 pied du collet; 2. Mélanger la résine/ bâtons de ciment et l’insérer dans le collet du trou; 3."},{"p":9,"t":"Attendre le délai de cure de la résine/ bâtons de ciment (indications sur la boîte) avant d’injecter; vi. Connecter le boyau hydraulique au tube jaune de cimentation vii. Démarrer le pompage du ciment et commencer l’injection viii."},{"p":9,"t":"Il ne devrait pas avoir de pression et le ciment injecté doit sortir par le tube de ventilation (couper en biseau) quand le trou est plein;"},{"p":9,"t":"d. Quand il y a pression d’eau dans le trou, i. Installation d’une plug MARGO par la mine : 1. Se connecter sur la MARGO avec le boyau hydraulique #16 et partir la pompe ; 2."},{"p":9,"t":"Le trou est plein quand la pression dépasse la pression d’eau initiale (la pression sera déterminée par l’ingénierie); Ou ii. Installation d’une VK plug : 1. Installer l’adapteur VK; 2. Installer une tige de la longueur appropriée; 3. Installer la swivel sur la tige; 4."},{"p":9,"t":"Installer le boyau hydraulique #16 sur la swivel; 5. Démarrer la foreuse; 6. Le trou est plein quand la pression dépasse la pression d’eau initiale (la pression sera déterminée par l’ingénierie);"},{"p":9,"t":"13. Ouvrir les valves à la sortie de la pompe; 14. Ouvrir les valves de la Margo plug, des boyaux jaunes ou de la VK plug; 15. Fermer la valve de purge. 16."},{"p":9,"t":"Pendant le pompage, recommencer un autre mélange dans la cuve à mélanger pour avoir une séquence régulière et répéter les étapes précédentes jusqu’à ce que la cimentation soit complétées; 17. Une fois la cimentation terminée, répéter les points 10 à 12; 18. Fermer l’eau sur les header; 19."},{"p":9,"t":"Déconnecter le boyau à l’eau sur la machine;"},{"p":10,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-007 Cimentation des trous de forage aux diamants avec pompe 435"},{"p":10,"t":"20. Nettoyer l’ensemble des équipements à grande eau et s’assurer qu’il n’y ait plus aucune accumulation de ciment à aucun endroit;"},{"p":10,"t":"21. Démonter la pompe pour le nettoyage interne;"},{"p":10,"t":"22. Laisser démonter tous les éléments internes de la pompe incluant les bouchons du dessous (chaque côté de la succion) et placer toutes les pièces dans un sac d’échantillonnage (sample) fermé avec une ty-rap puis placer le sac de pièces dans une des deux cuves de mélange."},{"p":10,"t":"23. Une fois le démontage terminé, appliquer une couche d'huile dans et sur la pompe pour prévenir les dépôts de ciment."},{"p":10,"t":"24. Bien ranger pour le transport."},{"p":10,"t":"Ajouts ou modifications Date Par Point #8 Changer vise-grip pour pince-grip à chaîne Point #13 : Enfiler les culottes de caoutchouc"},{"p":10,"t":"Changement complet de la séquence de cimentation avec MARGO et VK plug 28 juillet 2021"},{"p":10,"t":"28 juillet 2021"},{"p":10,"t":"28 juillet 2021"},{"p":10,"t":"Changement aux points #26 et #27 pour éviter les accumulations de ciment dans les équipements 1er octobre 2024 S. Tremblay F. Croteau Ajout de la trousse d’urgence obligatoire Ajout choix d’ÉPI 5 novembre 2024 S. Tremblay F."},{"p":10,"t":"Croteau Reformer le début et ajuster la procédure pour la standardiser avec celle de la Chemgrout 8 novembre 2024 S. Tremblay F. Croteau Ajouter 2 avertissements avant le #3 de mettre de l’eau dans la cuve Ajouter point #6 de vérifier le fonctionnement du manomètre 27 mars 2025 S. Tremblay F. Croteau"},{"p":10,"t":"____________________________ Christian St-Amour Directeur des Opérations"}],"pro-dd-st-008":[{"p":1,"t":"Avril 2021 Révision Août 2024"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-008"},{"p":1,"t":"PROCÉDURE D’INSTALLATION DU SUPPORT DE TIGES DE FORAGE OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour l’installation du support de tige et en établir l’emplacement adéquat selon la configuration de la foreuse."},{"p":1,"t":"APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL. INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le Directeur des Opérations."},{"p":1,"t":"Toute demande de modification, révision ou de mise à jour doit être faite auprès de de cette personne. RESPONSABILITÉS Le travailleur doit s’assurer de bien respecter la procédure, particulièrement la quantité et l’angle d’empilage dans le support."},{"p":1,"t":"Le superviseur doit faire respecter la procédure en tout temps et faire reprendre toute installation non-conforme La mine doit forer des trous de service à l’aide de leur équipement de forage pour le soutènement avant de quitter le site de forage au diamant pour y introduire des boulons à oeil PROCÉD"},{"p":1,"t":"URE 1- Opter pour un endroit près du mur et loin de la ligne de tir des trous de forage. (Voir plus loin les exemples de positionnement);"},{"p":2,"t":"PROCÉDURE D’INSTALLATION DU SUPPORT DE TIGES DE FORAGE"},{"p":2,"t":"A v r i l 2 0 2 1 P a g e 2 | 5"},{"p":2,"t":"2- Au mur, situer le centre du support et faire un trou de 18 po de profond avec la foreuse à percussion électrique à ± 5 pi du plancher; 3- Insérer le eye bolt, mais ne pas l’enfoncer jusqu’au fond du trou;"},{"p":2,"t":"4- À deux, soulever le support et positionner adéquatement les pattes du haut pour qu’elles soient bien appuyées au mur; 5- S’assurer d’avoir un angle entre 75° et 80°;"},{"p":2,"t":"6- Passer une chaîne dans le eye bolt jusqu’à son milieu; 7- Passer chaque bout de chaîne dans l’œillet du support qui lui est destiné, de l’extérieur vers l’intérieur; 8- Relier les deux bouts de chaîne avec un tendeur à cliquet chaîne et serrer le tendeur au maximum, ou avec un tendeur de type ‘’bear trap’’; ou"},{"p":3,"t":"PROCÉDURE D’INSTALLATION DU SUPPORT DE TIGES DE FORAGE"},{"p":3,"t":"A v r i l 2 0 2 1 P a g e 3 | 5"},{"p":3,"t":"9- Placer les tiges dans le support en quinconce (voir le schéma) par rangée à partir de la gauche;"},{"p":3,"t":"10-S’assurer d’appuyer les tiges sur la barre transversale du fond et non sur les côtés."},{"p":3,"t":"11-Placer une chaîne de retenue de tiges accrochée solidement dans les 2 crochets fermés de chaque côté du support; 12-La chaîne doit être ajustée de façon que les tiges ne puissent dépasser 80° si elles chutent vers un travailleur; 13-La chaîne de retenue doit être utilisée en tout temps, sauf penda"},{"p":3,"t":"nt les actions d’ajout et de retrait des tiges en continu. Les crochets doivent être à maximum 72 pouces et minimum 66 pouces du sol pour s'assurer que la chaîne ''lousse'' ne sera jamais moins de 5 pieds du sol au centre."},{"p":3,"t":"Marques à 5 pieds du sol"},{"p":4,"t":"PROCÉDURE D’INSTALLATION DU SUPPORT DE TIGES DE FORAGE"},{"p":4,"t":"A v r i l 2 0 2 1 P a g e 4 | 5"},{"p":4,"t":"14-Lors de la prise des tiges de forage dans le support, il est possible que la graisse sur celles-ci fasse en sorte qu’elles soient difficiles à prendre. L’utilisation d’un tournevis plat sera préconisée pour les séparer et aider à les prendre"},{"p":4,"t":"15-La capacité maximale en fonction de la résistance du support est de : HQ = 108 tiges, 324m NQ = 184 tiges, 552m BQ = 240 tiges, 720m"},{"p":5,"t":"PROCÉDURE D’INSTALLATION DU SUPPORT DE TIGES DE FORAGE"},{"p":5,"t":"A v r i l 2 0 2 1 P a g e 5 | 5"},{"p":5,"t":"Exemples de configuration"},{"p":5,"t":"Ajouts ou modifications Date Par Ajout point #14 de l’utilisation d’un tournevis plat pour séparer les tiges 22-01-2024 S. Tremblay Ajout après le point #13 des hauteurs de la chaînes de retenue 6-08-2024 S. Tremblay Changement de la photo pour les marques à 5 pieds du sol 15-01-2025 M. Rossignol S. Tremblay"},{"p":5,"t":"_________________________________ Stéphane Tremblay Surintendant Santé et Sécurité"}],"pro-dd-st-009-1":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-009-1"},{"p":1,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS STM-1500"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour le forage de trous ascendants de plus de 20 degrés. Elle donne des pistes de réflexion pour toutes les tâches ainsi que les risques entourant le forage ascendant."},{"p":1,"t":"APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL. RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure."},{"p":1,"t":"Il participe à la mise en place des contrôles Le superviseur est responsable de voir au bon déroulement des opérations et à la qualité du travail accompli. Le contremaître-général doit s’impliquer dans l’analyse de la situation pour déterminer les contrôles à mettre en place"},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES 9 nouveaux boulons ½ grade #8 de 2’’¼ Oreilles neuves pour la back end Locking coupling JAWS (si necessaire) Clé dynamométrique Box ¾ Clé ¾ Clé 1’’ ¼"},{"p":1,"t":"EPI OBLIGATOIRES Équipements de base obligatoires et ÉPI pour travail en hauteur si nécessaire"},{"p":1,"t":"PENDAGE MINIMUM QUI NÉCESSITE UNE ANALYSE Le pendage minimum qui nécessite une analyse est toujours de + 21 degrés. Pour chaque configuration des foreuses, des ajustements seront nécessaires pour avoir accès facilement au foot clam"},{"p":2,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS STM-1500"},{"p":2,"t":"Juin 2021 TYPE DE FOREUSE AJUSTEMENTS STM-1500 SANS lift kit Ancrage en bas STM 1500 AVEC lift kit Plancher de 24 pouces DR-1500 Plancher de 24 pouces"},{"p":2,"t":"MISE EN CONTEXTE"},{"p":2,"t":"En raison des risques associés au travail en hauteur lors du forage de certains trous ascendants, une analyse considérant ces risques doit être effectuée avant que la foreuse ne soit installée."},{"p":2,"t":"Concernant les risques reliés aux bris mécaniques, une liste des bris possibles ou probables (qui sont déjà survenus sur nos foreuses) est incluse dans cette procédure. Les mesures mises en place pour diminuer les probabilités de survenance y sont aussi ajoutées."},{"p":2,"t":"Le formulaire en annexe à cette procédure doit être utilisé pour analyser la situation et mettre des contrôles en place"},{"p":2,"t":"Quand la décision de forer un trou ascendant est prise, Une analyse de risque doit être faite. L’analyse doit porter :"},{"p":2,"t":"1- Sur le travail en hauteur :"},{"p":2,"t":"o Dépendamment de la hauteur : ▪ Construire un plancher surélevé; ▪ Évaluer la superficie de la plate-forme de travail en fonction de l’espace disponible, de l’Azimut et du degré de forage ▪ À plus de 6 pieds : • Prévoir des ÉPI pour s’attacher et limiter la chute à 4 pieds ou; • Prévoir des garde-co"},{"p":2,"t":"rps si nous travaillons sur un plancher tel que spécifié dans la procédure PRO-DD-ST-003 Procédure de fabrication d'un plancher pour foreuse aux diamants sous terre octobre 2020;"},{"p":3,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS STM-1500"},{"p":3,"t":"Juin 2021 2- Sur les risques de bris mécaniques qui pourraient avoir comme conséquences des blessures aux travailleurs: o Pour éviter un changement de jaws après que le forage est débuté ▪ Vérifier l’état et l’usure des jaws visuellement et en effectuant les manœuvres de serrage des jaws sur une tige"},{"p":3,"t":"avant de commencer le forage. Si elles sont usées la tige va glisser et elles doivent être changées"},{"p":3,"t":"o Pour éviter un changement de ressorts après que le forage est débuté ▪ Vérifier l’état des ressorts en effectuant les manœuvres de serrage des jaws sur une tige. Si les jaws sont belles visuellement et que la tige glisse, l’état des ressorts seront à vérifier visuellement;"},{"p":3,"t":"o Pour éviter qu’il y ait bris des 9 boulons du chuck : ▪ Mettre 9 nouveaux boulons selon la procédure PRO-OP-DD-005 Procédure pour démonter et remonter un clam ou un chuck sur une foreuse. ▪ Vérifier le serrage des boulons au début de chaque quart avec la clé dynamométrique sans les resserrer."},{"p":3,"t":"o Pour diminuer le risque qu’un tube délatch ou ne latch pas sur des trous de plus de 20 degrés ▪ Mettre des oreilles neuves ▪ Mettre un latch piston neuf ▪ Mettre une locking coupling neuve"},{"p":3,"t":"o Quand on se rend compte que le tube n’est pas latché ▪ Tous les travailleurs doivent être en-dehors de la porte interverrouillée ▪ Descendre le bout des tiges le plus proche du plancher possible; ▪ Effectuer les manœuvres nécessaires pour faire sortir le tube en faisant des mouvements de va-et-vien"},{"p":3,"t":"t avec les tiges de forage à l’aide de la tête IL EST POSSIBLE QU’ON NE SE RENDE PAS COMPTE QUE LE TUBE N’EST PAS LATCHÉ. LES TRAVAILLEURS DOIVENT TOUJOURS RESTER HORS DE LA LIGNE DE TIR DES TIGES"},{"p":3,"t":"o Quand on se rend compte que le tube est délatché ▪ Tous les travailleurs doivent être en-dehors de la porte interverrouillée ▪ Descendre le bout des tiges le plus proche du plancher possible; ▪ Effectuer les manœuvres nécessaires pour faire sortir le tube en faisant des mouvements de va-et-vient av"},{"p":3,"t":"ec les tiges de forage à l’aide de la tête"},{"p":4,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS STM-1500"},{"p":4,"t":"Juin 2021 IL EST POSSIBLE QU’ON NE SE RENDE PAS COMPTE QUE LE TUBE EST DÉLATCHÉ. LES TRAVAILLEURS DOIVENT TOUJOURS RESTER HORS DE LA LIGNE DE TIR DES TIGES Les changements de pièces en prévention effectués avant le début du forage viennent diminuer les probabilités de survenance à ‘’TRÈS IMPROBABLE’’"},{"p":4,"t":"Des bris peuvent être provoqués par des opérations inadéquates qui endommagent les pièces des composantes des foreuses."},{"p":4,"t":"Il faut éviter l’exagération de faire du ‘’marteau’’ quand les rods sont prises dans le trou."},{"p":4,"t":"Si on doit faire du marteau, une vérification du serrage des boulons doit être faite"},{"p":4,"t":"Il est interdit de :"},{"p":4,"t":"1- Faire tourner la tête rapidement et fermer les jaws pour casser une rod"},{"p":4,"t":"2- Laisser descendre les rods et les arrêter avec les jaws du chuck"},{"p":4,"t":"Ajouts ou modifications Date Par Nouvelle procédure Juin 2021 S. Tremblay Ajout dans le questionnaire concernant le relevage de la foreuse Octobre 2021 S."},{"p":4,"t":"Tremblay Ajout dans le titre 009-1 Ajout dans le titre des types de foreuses STM- 1500 et DR-600 #2907 Ajout d’infos dans le formulaire (place de travail, #foreuse et pendage) Ajout des noms du superviseur, du foreur et de l’aide foreur à la fin du formulaire Avril 2023 S. Tremblay F. Croteau"},{"p":4,"t":"___________________________ Christian St-Amour Directeur des Opérations"},{"p":5,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-009-1"},{"p":5,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS STM-1500"},{"p":5,"t":"FORMULAIRE D’ANALYSE LORS DU FORAGE ACENDANT DE PLUS DE 20 DEGRÉS"},{"p":5,"t":"Place de travail :_______________________ #Foreuse : ___________ Pendage : ____________"},{"p":5,"t":"TRAVAIL EN HAUTEUR"},{"p":5,"t":"Est-ce que les travaux suivants peuvent se faire à partir du plancher primaire :"},{"p":5,"t":"NON 1- Installation de l’ancrage?"},{"p":5,"t":"N 2- Travaux mécaniques sur le footclam?"},{"p":5,"t":"N 3- Installation du Clam Morissette?"},{"p":5,"t":"N 4- Changer la bit?"},{"p":5,"t":"N 5- Serrer les pattes?"},{"p":5,"t":"N 6- Enlever le bearing?"},{"p":5,"t":"Si un des items nécessite du travail en hauteur : 1- Est-ce qu’un 3,4 ou 6 marches est utilisable?"},{"p":5,"t":"N a. Si non, quelle hauteur de plancher a-t-on besoin? _________pieds b. Quel type de construction doit-on faire? : ___________________________________________________ ____________________________________________________________________________________ c. A-t-on besoin d’un plan d’ingénierie"},{"p":5,"t":"N 2- Le travailleur doit-il être attaché?"},{"p":5,"t":"N a. Si oui, procédure de travail en hauteur?"},{"p":5,"t":"HAUTEUR DE LA FOREUSE 1- A-t-on besoin de remonter la foreuse?"},{"p":5,"t":"N a. Si oui, appliquer la procédure pour relever une foreuse"},{"p":5,"t":"LIGNE DE TIR"},{"p":5,"t":"Est-ce que l’installation de la foreuse permet aux travailleurs d’être hors de la ligne de tir des tiges de forage en tout temps?"},{"p":5,"t":"N Est-ce l’espace est suffisant pour forer en 10 pieds?"},{"p":5,"t":"N Est-ce qu’un trou dans le plancher sera nécessaire?"},{"p":5,"t":"Est-ce que la grandeur du trou crée un risque de chute"},{"p":5,"t":"Si oui, l’utilisation des tiges de 5 pieds est obligatoire Est-ce que l’utilisation de tiges de 5 pieds est à considérer?"},{"p":5,"t":"POUR DIMINUER LES RISQUES DE BRIS MÉCANIQUES Tube qui ne latch pas ou qui délatch CHANGER OREILLES"},{"p":5,"t":"CHANGER LOCKING COUPLING"},{"p":5,"t":"N Bris des boulons CHANGER LES 9 BOULONS ET SERRÉS À105 LBS/PIED O"},{"p":5,"t":"Formulaire rempli et travaux exécutés par:"},{"p":5,"t":"Nom du superviseur : _____________________________________ Signature: _____________________________"},{"p":5,"t":"Nom du foreur : _________________________________________ Signature: _____________________________"},{"p":5,"t":"Nom aide-foreur : ________________________________________ Signature: _____________________________"},{"p":5,"t":"Date: ___________________________"}],"pro-dd-st-009-2":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-009-2"},{"p":1,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour le forage de trous ascendants de plus de 20 degrés avec la DR-600 #2923. Elle donne des pistes de réflexion pour toutes les tâches ainsi que les risques entourant le forage ascendant."},{"p":1,"t":"Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS"},{"p":1,"t":"Le travailleur est responsable d’appliquer cette procédure. Il participe à la mise en place des contrôles Le superviseur est responsable de voir au bon déroulement des opérations et à la qualité du travail accompli."},{"p":1,"t":"Le contremaître-général doit s’impliquer dans l’analyse de la situation pour déterminer les contrôles à mettre en place"},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES 9 nouveaux boulons ½ grade #8 de 2’’¼ Oreilles neuves pour la back end Locking coupling JAWS (si necessaire) Clé dynamométrique Box ¾ Clé ¾ Clé 1’’ ¼"},{"p":1,"t":"EPI OBLIGATOIRES Équipements de base obligatoires et ÉPI pour travail en hauteur si nécessaire"},{"p":1,"t":"PENDAGE MINIMUM QUI NÉCESSITE UNE ANALYSE Le pendage minimum qui nécessite une analyse est de +20 Degrés. Pour chaque configuration des foreuses, des ajustements seront nécessaires pour avoir accès facilement au foot clam."},{"p":2,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":2,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS SUR FOREUSE MOBILE DR-600"},{"p":2,"t":"MISE EN CONTEXTE"},{"p":2,"t":"En raison des risques associés au travail en hauteur lors du forage de certains trous ascendants, une analyse considérant ces risques doit être effectuée avant que la foreuse ne soit installée."},{"p":2,"t":"▪ Concernant les risques reliés aux bris mécaniques, une liste des bris possibles ou probables (qui sont déjà survenus sur nos foreuses) est incluse dans cette procédure. Les mesures mises en place pour diminuer les probabilités de survenance y sont aussi ajoutées."},{"p":2,"t":"Le formulaire en annexe à cette procédure doit être utilisé pour analyser la situation et mettre des contrôles en place. PROCÉDURE"},{"p":2,"t":"Quand la décision de forer un trou ascendant est prise, Une analyse de risque doit être faite. L’analyse doit porter :"},{"p":2,"t":"1- Sur le travail en hauteur :"},{"p":2,"t":"o Dépendamment des degrés et de la longueur des tiges utilisées: ▪ Inspection et utilisation d’un 3 marches : 1. À partir de +25 à +35 degrés avec des tiges de 3 mètres 2. À partir de +40 à +50 degrés avec des tiges de 1,5 mètres ▪ Inspection et utilisation d’un 6 marches : 1."},{"p":2,"t":"À partir de +50 à +55 degrés avec des tiges de 1,5 mètres"},{"p":2,"t":"▪ À plus de 6 pieds : • Prévoir des ÉPI pour s’attacher et limiter la chute à 4 pieds ou ; • Prévoir des garde-corps si nous travaillons sur un plancher tel que spécifié dans la procédure PRO-DD-ST-003 Procédure de fabrication d'un plancher pour foreuse aux diamants sous terre octobre 2020;"},{"p":3,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":3,"t":"Juin 2021 2- Sur les risques de bris mécaniques qui pourraient avoir comme conséquences des blessures aux travailleurs:"},{"p":3,"t":"o Pour éviter un changement de jaws après que le forage est débuté ▪ Vérifier l’état et l’usure des jaws visuellement et en effectuant les manoeuvres de serrage des jaws sur une tige avant de commencer le forage. Si elles sont usées la tige va glisser et elles doivent être changées;"},{"p":3,"t":"o Pour éviter un changement de ressorts après que le forage est débuté ▪ Vérifier l’état des ressorts en effectuant les manoeuvres de serrage des jaws sur une tige. Si les jaws sont belles visuellement et que la tige glisse, l’état des ressorts seront à vérifier visuellement;"},{"p":3,"t":"o Pour éviter qu’il y ait bris des 9 boulons du chuck : ▪ Mettre 9 nouveaux boulons selon la procédure PRO-OP-DD-005 Procédure pour démonter et remonter un clam ou un chuck sur une foreuse. ▪ Vérifier le serrage des boulons au début de chaque quart avec la clé dynamométrique sans les resserrer."},{"p":3,"t":"o Pour diminuer le risque qu’un tube délatch ou ne latch pas sur des trous de plus de 20 degrés ▪ Mettre des oreilles neuves ▪ Mettre un latch piston neuf ▪ Mettre une locking coupling neuve"},{"p":3,"t":"o Quand on se rend compte que le tube n’est pas latché ▪ Tous les travailleurs doivent être en-dehors de la porte interverrouillée ▪ Descendre le bout des tiges le plus proche du plancher possible; ▪ Effectuer les manoeuvres nécessaires pour faire sortir le tube en faisant des mouvements de va-et-vie"},{"p":3,"t":"nt avec les tiges de forage à l’aide de la tête IL EST POSSIBLE QU’ON NE SE RENDE PAS COMPTE QUE LE TUBE N’EST PAS LATCHÉ. LES TRAVAILLEURS DOIVENT TOUJOURS RESTER HORS DE LA LIGNE DE TIR DES TIGES"},{"p":4,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":4,"t":"Juin 2021 o Quand on se rend compte que le tube est délatché ▪ Tous les travailleurs doivent être en-dehors de la porte interverrouillée ▪ Descendre le bout des tiges le plus proche du plancher possible; ▪ Effectuer les manœuvres nécessaires pour faire sortir le tube en faisant des mouvements de va-e"},{"p":4,"t":"t-vient avec les tiges de forage à l’aide de la tête IL EST POSSIBLE QU’ON NE SE RENDE PAS COMPTE QUE LE TUBE EST DÉLATCHÉ. LES TRAVAILLEURS DOIVENT TOUJOURS RESTER HORS DE LA LIGNE DE TIR DES TIGES"},{"p":4,"t":"Les changements de pièces en prévention effectués avant le début du forage viennent diminuer les probabilités de survenance à ‘’TRÈS IMPROBABLE’’"},{"p":4,"t":"Des bris peuvent être provoqués par des opérations inadéquates qui endommagent les pièces des composantes des foreuses."},{"p":4,"t":"Il faut éviter l’exagération de faire du ‘’marteau’’ quand les rods sont prises dans le trou."},{"p":4,"t":"Si on doit faire du marteau, une vérification du serrage des boulons doit être faite"},{"p":4,"t":"Cimentation de trous ascendants aux bâtons : o Si l’utilisation d’un 3 marches ou 6 marches ne permets pas d’atteindre le collet du trou, elle doit être faite à l’aide d’une nacelle et de tiges de 1,5 mètres pour pousser le ciment Utilisation d’un 3 marches ou 6 marches : o Niveler le plancher de l’e"},{"p":4,"t":"mplacement ou sera installé le 3 ou 6 marches o Les 4 points de la base doivent être en contact avec le sol Ne jamais monter dans un 3 ou 6 marches instable et endommagé"},{"p":5,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":5,"t":"Juin 2021 o Sécuriser le 6 marches à l’aide de mousqueton et d’une chaine dans le grillage pour empêcher tout basculement Ne jamais monter dans un 6 marches instable et endommagé"},{"p":5,"t":"Il est interdit de :"},{"p":5,"t":"1- Faire tourner la tête rapidement et fermer les jaws pour casser une rod"},{"p":5,"t":"2- Laisser descendre les rods et les arrêter avec les jaws du chuck"},{"p":5,"t":"Ajouts ou modifications Date Par Nouvelle procédure Juin 2021 S. Tremblay Ajout dans le questionnaire concernant le relevage de la foreuse Octobre 2021 S."},{"p":5,"t":"Tremblay Adaptation de la procédure 009-1 pour la foreuses DR-600 #2923 Ajout dans le titre 009-2 Ajout dans le titre des types de foreuses DR-600 #2907 Ajout d’infos dans le formulaire (place de travail, #foreuse et pendage) Ajout des noms du superviseur, du foreur et de l’aide foreur à la fin du fo"},{"p":5,"t":"rmulaire Avril 2023 S. Tremblay F. Croteau"},{"p":5,"t":"___________________________ Christian St-Amour Directeur des Opérations"},{"p":6,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-009-2"},{"p":6,"t":"PROCÉDURE À SUIVRE POUR LE FORAGE DE TROUS ASCENDANTS DE PLUS DE 20 DEGRÉS"},{"p":6,"t":"FORMULAIRE D’ANALYSE LORS DU FORAGE ACENDANT DE PLUS DE 20 DEGRÉS"},{"p":6,"t":"Place de travail :_______________________ #Foreuse : ___________ Pendage : ____________"},{"p":6,"t":"TRAVAIL EN HAUTEUR"},{"p":6,"t":"Est-ce que les travaux suivants peuvent se faire à partir du plancher primaire (maximum +25 en 3m et +40 en 1,5m):"},{"p":6,"t":"NON 1- Installation de l’ancrage?"},{"p":6,"t":"N 2- Travaux mécaniques sur le footclam?"},{"p":6,"t":"N 3- Installation du Clam Morissette?"},{"p":6,"t":"N 4- Changer la bit?"},{"p":6,"t":"N 5- Serrer les pattes?"},{"p":6,"t":"N 6- Enlever le bearing?"},{"p":6,"t":"Si un des items nécessite du travail en hauteur : 1- Est-ce qu’un 3, 4 ou 6 marches est utilisable?"},{"p":6,"t":"N a. Si non, quelle hauteur de plancher a-t-on besoin? _________pieds b. Quel type de construction doit-on faire? : ___________________________________________________ ____________________________________________________________________________________ c. A-t-on besoin d’un plan d’ingénierie"},{"p":6,"t":"N 2- Le travailleur doit-il être attaché?"},{"p":6,"t":"N a. Si oui, procédure de travail en hauteur?"},{"p":6,"t":"HAUTEUR DE LA FOREUSE 1- A-t-on besoin de remonter la foreuse?"},{"p":6,"t":"N a. Si oui, appliquer la procédure pour relever une foreuse"},{"p":6,"t":"LIGNE DE TIR"},{"p":6,"t":"Est-ce que l’installation de la foreuse permet aux travailleurs d’être hors de la ligne de tir des tiges de forage en tout temps?"},{"p":6,"t":"N Est-ce l’espace est suffisant pour forer en 10 pieds?"},{"p":6,"t":"N Est-ce qu’un trou dans le plancher sera nécessaire?"},{"p":6,"t":"Est-ce que la grandeur du trou crée un risque de chute"},{"p":6,"t":"Si oui, l’utilisation des tiges de 5 pieds est obligatoire Est-ce que l’utilisation de tiges de 5 pieds est à considérer?"},{"p":6,"t":"POUR DIMINUER LES RISQUES DE BRIS MÉCANIQUES Tube qui ne latch pas ou qui délatch CHANGER OREILLES"},{"p":6,"t":"CHANGER LOCKING COUPLING"},{"p":6,"t":"N Bris des boulons CHANGER LES 9 BOULONS ET SERRÉS À105 LBS/PIED O"},{"p":6,"t":"Formulaire rempli et travaux exécutés par:"},{"p":6,"t":"Nom du superviseur : _____________________________________ Signature: _____________________________"},{"p":6,"t":"Nom du foreur : _________________________________________ Signature: _____________________________"},{"p":6,"t":"Nom aide-foreur : ________________________________________ Signature: _____________________________"},{"p":6,"t":"Date: ___________________________"}],"pro-dd-st-011":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-DD-ST-011"},{"p":1,"t":"PROCÉDURE DE RÉCUPÉRATION DU TUBE CAROTTIER LORS D’INTERCEPTION DE VEINES D’EAU"},{"p":1,"t":"Octobre 2017"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires et efficaces pour La récupération du tube carottier lors de l’interception de veines d’eau avec pression significative. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et de voir au bon déroulement des opérations. Le superviseur doit s’assurer que la procédure est appliquée."},{"p":1,"t":"EPI OBLIGATOIRE"},{"p":1,"t":"OUTILS NÉCESSAIRES Foreuse au diamant Équipement de forage Frein manuel (brake tube) Clé dynamométriue Clé à tuyau Douille 1’’ 5/8"},{"p":1,"t":"PROCÉDURE LORS DE L’INTERCEPTION DE VEINE D’EAU STANDARD"},{"p":1,"t":"1. Vérifier la pression d’eau à chaque fois que le tube carottier doit être récupéré : a. Casser la carotte; b. Arrêter la pompe à l’eau de la foreuse en gardant la valve de purge ouverte; c. Fermer la valve de purge; d. Lire la valeur de la pression affichée sur le manomètre :"},{"p":2,"t":"PROCÉDURE DE TRAVAIL LORS D’INTERCEPTION DE VEINES D’EAU"},{"p":2,"t":"Octobre 2019"},{"p":2,"t":"i. Entre 200 et 300 psi = poursuite des travaux avec vigilance; ii. Supérieur à 300 psi = installation du frein manuel (brake tube); iii. Le frein peut être installé si le débit d’eau est suffisamment important pour risquer l’éjection du tube carottier."},{"p":2,"t":"2. S’assurer que les tiges soient bien appuyées au fond du trou de forage. Si nécessaire, utiliser des tiges de différentes longueurs pour se positionner adéquatement. Ceci réduira la quantité d’eau entrante susceptible de pousser sur le tube;"},{"p":2,"t":"3. Installer le frein manuel au bout des tiges de forage"},{"p":2,"t":"4. Installer la rallonge de 48 pouces"},{"p":2,"t":"5. Installer la mâchoire de repêchage (OVERSHOT)"},{"p":2,"t":"6. Connecter le boyau à l’eau"},{"p":2,"t":"7. Envoyer la mâchoire de repêchage (OVERSHOT) et activant la pompe à eau"},{"p":2,"t":"8. Sortir le tube carottier jusqu’à la chambre de chargement (loading chamber)"},{"p":3,"t":"PROCÉDURE DE TRAVAIL LORS D’INTERCEPTION DE VEINES D’EAU"},{"p":3,"t":"Octobre 2019"},{"p":3,"t":"9. S’assurer que le câble reste tendu tout au long de la récupération du tube. Un câble qui se détend signifie qu’une pression d’eau pousse sur le tube carottier dans sa sortie"},{"p":3,"t":"10. Si le câble se détend, contrôler la remontée du tube avec la valve de purge"},{"p":3,"t":"11. Pour sortir le tube, s’assurer que la valve de purge est ouverte au maximum et que la pression d’eau est réduite"},{"p":3,"t":"12. Serrer l’écrou du frein manuel (brake tube) à l’aide de la clé dynamométrique. Le couple de serrage doit être établi en fonction de la pression d’eau (TABLEAU)"},{"p":4,"t":"PROCÉDURE DE TRAVAIL LORS D’INTERCEPTION DE VEINES D’EAU"},{"p":4,"t":"Octobre 2019"},{"p":4,"t":"13. Utiliser la clé dynamométrique pour desserrer l’écrou afin de retenir le tube et d’éviter son éjection"},{"p":4,"t":"14. Dévisser la chambre de chargement et la rallonge de 48 pouces à l’aide d’une clé à tuyau. La pression sera évacuée."},{"p":4,"t":"SOYEZ VIGILANT TOUJOURS SE PLACER HORS DE LA LIGNE DE TIR DU TUBE CAROTTIER"},{"p":4,"t":"15. Récupérer le tube carottier et desserrer le frein lentement"},{"p":4,"t":"SI LA RÉCUPÉRATION DU TUBE EST IMPOSSIBLE, VOIR LA SECTION ‘’CAS PARTICULIER’’"},{"p":5,"t":"PROCÉDURE DE TRAVAIL LORS D’INTERCEPTION DE VEINES D’EAU"},{"p":5,"t":"Octobre 2019"},{"p":5,"t":"16. Poursuivre le forage selon les directives afin de dépasser la veine d’eau pour permettre une cimentation efficace"},{"p":5,"t":"17. Si un manque d’espace rend cette procédure inapplicable, contacter le superviseur et une AST sera faite avant de poursuivre les travaux"},{"p":5,"t":"CAS PARTICULIER"},{"p":5,"t":"18. Quand il y a une pression d’eau importante, il est possible que le tube carottier reste coincé dans les tiges de forage ou que le câble soit sectionné. Dans ces deux cas : a."},{"p":5,"t":"Après avoir enlevé la chambre de chargement, pousser un bouchon de type ‘’VAN RUTH’’ avec la pression d’eau jusqu’au tube carottier afin de prévenir l’éjection du tube carottier"},{"p":5,"t":"b. Retirer toutes les tiges de forage c. Récupérer le tube carottier"},{"p":5,"t":"19. Poursuivre le forage afin de dépasser la veine d’eau"},{"p":5,"t":"20. Si un manque d’espace rend cette procédure inapplicable, contacter le superviseur et une AST sera faite avant de poursuivre les travaux"},{"p":5,"t":"____________________________ Christian St-Amour Directeur des Opérations"}],"pro-mec-011":[{"p":1,"t":"Date : Avril 2024 1 / 12"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-MEC-011 PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":1,"t":"L’objectif de cette procédure est de définir une façon sécuritaire de changer la coupling entre le moteur électrique et la pompe hydraulique des foreuses CUBEX. De plus, elle permet de faire une bonne inspection de l’ensemble des composantes entourant la pompe et le moteur électrique."},{"p":1,"t":"Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL qui ont à faire les changements de coupling. Les travaux doivent être effectués par un mécanicien, un superviseur oui par un foreur mandaté par le superviseur."},{"p":1,"t":"INTERPRÉTATION"},{"p":1,"t":"La personne ayant l’autorité pour l’interprétation de ce document est le directeur entretien. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS"},{"p":1,"t":"Le travailleur a la responsabilité de prendre connaissance de cette procédure et de l’appliquer lors du changement de coupling. Le superviseur doit s’assurer que la personne effectuant les travaux est en mesure de le faire. Il doit s’assurer que la procédure est connue des personnes concernées."},{"p":1,"t":"Outils et équipements nécessaires aux travaux Clés ordinaires"},{"p":1,"t":"Autres outils ou produits Pour les 2 boulons entre pompe et bell housing Antiseize ou graisse à filets"},{"p":1,"t":"Pour les 4 boulons entre bell housing et moteur électrique (si boulons avec tête hexagonale) Pry bar (barres de levier) Clés ALLEN"},{"p":1,"t":"Brosse d’acier Pour la barrure de la coupling sur la pompe Grattoire Pour la barrure de la coupling du moteur électrique Tournevis plat Pour la barrure sur du spline sur coupling de la pompe Petite masse ou marteau Pour les 4 boulons entre bell housing et moteur électrique (si boulons avec tête ALLEN"},{"p":1,"t":") Masse de coutchouc"},{"p":2,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":2,"t":"Date : Avril 2024 2/ 12 PROCÉDURE"},{"p":2,"t":"1- Cadenasser la foreuse;"},{"p":2,"t":"2- Enlever le capot sur la foreuse;"},{"p":2,"t":"3- Enrouler une sangle à cliquet autour de la pompe et au cadre de la foreuse en ne coinçant pas le fil de détection du système à feu;"},{"p":2,"t":"4- Enlever les boulons qui fixent la pompe au ‘’bell housing’’;"},{"p":2,"t":"5- Retirer la pompe;"},{"p":3,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":3,"t":"Date : Avril 2024 3/ 12 À ce moment, la pompe est retenue par les boyaux hydrauliques et la sangle. Il faut la retenir avec les mains sur les boyaux. ÉVITER DE SE METTRE LES MAINS SOUS LA POMPE ET PROTÉGER SES DOIGTS DES COINCEMENTS"},{"p":3,"t":"6- Desserrer la sangle et placer la pompe pour être certain qu’elle ne se déplacera pas de manière à frapper le travailleur qui exécute les travaux;"},{"p":3,"t":"7- Faire une inspection :"},{"p":3,"t":"a. Du bell housing; i. Trous et filets ou sont vissés les boulons,"},{"p":3,"t":"ii. Trou de l’ouverture sur le bell housing, iii. De l’intérieur du bell housing"},{"p":4,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":4,"t":"Date : Avril 2024 4/ 12 iv. S’il y de la saleté dans le bell housing, enlever les 4 boulons entre le bell housing et le moteur électrique Le retirer et le nettoyer avec un grattoire. v."},{"p":4,"t":"Si le bell housing reste collé sur le moteur électrique, vous devez utiliser une masse de caoutchouc pour frapper dessus. LE BELL HOUSING EST EN ALUMINIUM;"},{"p":4,"t":"8- Dévisser la barrure de la coupling de la pompe à l’aide de la clé ALLEN 5/16;"},{"p":4,"t":"9- Retirer la coupling sur le shaft de la pompe. Insérer une pry bar ou un tournevis plat dans la fente de la couping pour l’écarter et à l’aide d’une autre pry bar pousser la coupling vers le bout du shaft pour la sortir"},{"p":5,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":5,"t":"Date : Avril 2024 5/ 12 10-Enlever la barrure sur la moitié de coupling qui est sur le shaft du moteur électrique à l’aide la clé ALLEN 3/16;"},{"p":5,"t":"11- Retirer la coupling à l’aide d’une pry bar;"},{"p":5,"t":"SI LA COUPLING EST COLLÉE ET DIFFICILE À RETIRER : 1- ENLEVER LE BELL HOUSING 2- UTILISER UNE MASSE OU UN MARTEAU POUR FRAPPER SUR LA PRY BAR 3- ATTENTION DE NE PAS ENDOMMAGER LE SHAFT DU MOTEUR ÉLECTRIQUE"},{"p":6,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":6,"t":"Date : Avril 2024 6/ 12 12-Quand les 2 coupling sont enlevées :"},{"p":6,"t":"À l’aide d’une brosse d’acier ou d’un grattoire :"},{"p":6,"t":"BIEN NETTOYER"},{"p":6,"t":"LE SHAFT ET L’ÉPAULEMENT DE LA POMPE HYDRAULIQUE"},{"p":6,"t":"LE SHAFT DU MOTEUR ÉLECTRIQUE"},{"p":7,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":7,"t":"Date : Avril 2024 7/ 12 APPLIQUE DE L’ANTISEIZE SUR LE SHAFT DE LA POMPE"},{"p":7,"t":"SUR LE SHAFT DU MOTEUR ÉLECTRIQUE"},{"p":7,"t":"NETTOYER LES DEUX BOUTS DU BELL HOUSING"},{"p":8,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":8,"t":"Date : Avril 2024 8/ 12 13-Insérer la coupling de manière flottante sur le shaft du moteur électrique et serrer la barrure à la main (juste accotée). Ça permettra un réajustement après avoir entré la coupling de la pompe."},{"p":8,"t":"14-Si le bell housing a été enlevé ou changé, le remettre en place en utilisant la clé"},{"p":9,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":9,"t":"Date : Avril 2024 9/ 12 15-Mettre le boulon enduit d’anti-seize avec la clé ALLEN ¼ pour barrer le spline à la coupling"},{"p":9,"t":"16-Insérer un petite pry bar ou un tournevis plat dans la fente sur le dessus ou le devant de la coupling de la pompe pour l’écarter et mettre la coupling sur le shaft"},{"p":10,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":10,"t":"Date : Avril 2024 10/ 12 17-S’assurer que la coupling est ‘’FLUSH ‘’ au shaft;"},{"p":10,"t":"18-Serrer au maximum la barrure enduit d’anti-seize avec la clé ALLEN 5/16;"},{"p":11,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":11,"t":"Date : Avril 2024 11/ 12 19-Insérer le joint de caoutchouc dans la coupling du moteur électrique"},{"p":11,"t":"20-Resserrer la sangle à cliquet et aligner les deux coupling ensemble jusqu’à ce que les coupling soient collées;"},{"p":11,"t":"21-Insérer à la main les 2 boulons de la pompe hydraulique pour s’assurer d’un bon alignement des boulons :"},{"p":11,"t":"22-Serrer les 2 boulons avec la clé 15/16;"},{"p":11,"t":"23-S’assurer que les coupling sont bien collées et serrer au maximum la barrure de la coupling du moteur électrique avec la clé ALLEN 3/16;"},{"p":12,"t":"PROCÉDURE DE TRAVAIL POUR CHANGER LA COUPLING ENTRE LE MOTEUR ÉLECTRIQUE ET LA POMPE HYDRAULIQUE DES FOREUSES CUBEX"},{"p":12,"t":"Date : Avril 2024 12/ 12 24-Remettre le couvercle de plastique"},{"p":12,"t":"________________________"},{"p":12,"t":"Karl Béchard"},{"p":12,"t":"Directeur entretien"},{"p":12,"t":"Ajouts ou modifications Date Par Procédure mise en place à la suite d’un début d’incendie à la mine Westwood lors de la surchauffe du bell housing et du couvercle de plastique Avril 2024 S. Tremblay K. Béchard"}],"pro-op-dd-005":[{"p":1,"t":"30 juin 2018"},{"p":1,"t":"PROCÉDURE DE TRAVAIL"},{"p":1,"t":"DÉMONTER ET REMONTER UN CLAM ET UN CHUCK (mandrin) SUR LA FOREUSE"},{"p":1,"t":"L’objectif de cette procédure est de définir les méthodes sécuritaires pour effectuer le démontage et le remontage d’un clam ou d’un chuck (mandrin) sur la foreuse APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION La personne ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure pour le démontage d’un clam et d’un chuck (mandrin) sur la foreuse"},{"p":1,"t":"MATÉRIEL NÉCÉSSAIRE OUTILS NÉCESSAIRES 9 Boulons ½ de 2’’ 1/4 Clé 3/4 Ressorts de chuck Box 3/4 Toute pièce à changer Clé dynamométrique"},{"p":1,"t":"1. S’assurer que les manettes pour barrer le clam ou le chuck (mandrin) soient en position fermée pour que les ressorts soient étirés au maximum"},{"p":2,"t":"Démontage et remontage d’un clam et d’un chuck (mandrin) sur une foreuse"},{"p":2,"t":"Juin 2018 Révision : Juin 2019"},{"p":2,"t":"2. S’assurer que les jaws (mâchoires) dans le clam ou le chuck (mandrin) soient en position fermée. 3. Cadenasser la foreuse en suivant la procédure de cadenassage. 4. Dévisser les 6 boulons ¾ du couvert des jaws (mâchoires) avec une clé 1’’ 1/8"},{"p":2,"t":"5. enlever les 9 boulons ½ avec une clé ¾ du couvercle."},{"p":2,"t":"6. Enlever les 3 boulons1/2 avec une clé 3/4 avec les bushing sur le cône et les remettre sans les bushing pour empêcher la projection du cône. Sans les bushings"},{"p":2,"t":"6 boulons ¾ à dévisser avec une clé 1 1/8 9 boulons 1/2"},{"p":3,"t":"Démontage et remontage d’un clam et d’un chuck (mandrin) sur une foreuse"},{"p":3,"t":"Juin 2018 Révision : Juin 2019"},{"p":3,"t":"7. Enlever les 6 derniers boulons ½ avec une clé 3/4 en suivant l’ordre sur la photo. Il est important de dévisser les boulons seulement 1 tour à la fois, en suivant l’ordre sur la photo, les ressorts sont écrasés de 1/4 pouces. ."},{"p":3,"t":"8. Dévisser les 3 derniers boulons"},{"p":4,"t":"Démontage et remontage d’un clam et d’un chuck (mandrin) sur une foreuse"},{"p":4,"t":"Juin 2018 Révision : Juin 2019"},{"p":4,"t":"9. Changer les pièces à changer (ex : ressorts, chuck bowl, piston);"},{"p":4,"t":"10. Bien nettoyer les deux côtés du couvercle avant de le remettre en place;"},{"p":4,"t":"11. Pour remettre le piston, il est important de remettre ces 3 boulons au début et ensuite suite l’ordre de revissage de l’étape #7, en vissant 1 tour à la fois, pour ne pas écraser les ressorts juste un côté à la fois;"},{"p":4,"t":"12. Dès que les 9 boulons ½ de 2’’ ¼ sont enlevés sur un chuck, vous devez en remettre des neufs;"},{"p":4,"t":"13. Les 9 boulons doivent être serrés avec la clé dynamométrique à 105 lbs/pied"},{"p":4,"t":"Ajouts ou modifications Date Par Changer titre en ajoutant remonter 15 mai 2021 S. Tremblay Ajouter tableau matériel et outils nécessaires 15 mai 2021 S. Tremblay Ajouter les points 9, 10, 12 et 13 15 mai 2021 S. Tremblay"},{"p":4,"t":"Christian St-Amour Directeur des opérations"}],"pro-op-dd-012":[{"p":1,"t":"Novembre 2022"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-DD-012"},{"p":1,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE AU DIAMANT OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour le forage à distance avec une foreuse au diamant."},{"p":1,"t":"APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL (MRI) ainsi qu’au département de géologie du client. Le forage à distance doit être décidé par le département de géologie du client en fonction des dangers pouvant être présents lors du forage."},{"p":1,"t":"Le foreur ou la supervision de MRI sont invités à proposer le forage à distance s’il le considère davantage sécuritaire que le forage conventionnel."},{"p":1,"t":"Les articles 439 et 440 du Règlement sur la Santé et la Sécurité du travail dans les Mines prévoient :"},{"p":1,"t":"439. Il est interdit de forer à une distance inférieure à: 1° 150 mm (5,9 po) d’un fond de trou qui a été chargé et qui a sauté; 2° 1,5 m (4,9 pi) d’un trou contenant des explosifs à la suite d’un raté; 3° 1,5 m (4,9 pi) du matériau sauté pouvant cacher un raté; (…)"},{"p":1,"t":"440. Malgré l’article 439, des trous peuvent être forés à des distances moindres que celles prévues à cet article pourvu que le forage soit exécuté au moyen d’un dispositif de commande à distance sous surveillance et que la zone de forage soit évacuée."},{"p":1,"t":"Ce qui signifie que si un plancher n’a pas été soufflé et vérifié, et qu’il n’est pas possible de déterminer s’il y a présence d’explosifs, le départ du trou le plus proche doit être à 1,5 mètre de la roche abattue, OU le forage doit se faire à distance."},{"p":1,"t":"Cette procédure vient encadrer les travaux de forage à distance. INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne"},{"p":2,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE AU DIAMANT"},{"p":2,"t":"Novembre 2022"},{"p":2,"t":"RESPONSABILITÉS LE FOREUR Le foreur doit appliquer la procédure de forage à distance selon les exigences proposées par le client. Il doit respecter toutes les procédures entourant le forage avec une foreuse au diamant ou tout autre équipement. Cette procédure est le minimum demandé par Machines Roger International."},{"p":2,"t":"LE SUPERVISEUR MRI"},{"p":2,"t":"Le superviseur MRI doit s’assurer de l’application de cette procédure ainsi que du respect du plan et devis de l’ingénierie du client. Il doit aussi participer à toute analyse de risque demandée par nous ou par le client."},{"p":2,"t":"GÉOLOGIE DU CLIENT"},{"p":2,"t":"La géologie responsable du forage doit émettre des plans et devis de forage à distance. Ces plans et devis doivent prendre en considération les risques associés à ce type de forage."},{"p":2,"t":"L’ingénierie du client doit être l’initiateur, si une analyse de risque est nécessaire, ou minimalement participer à cette analyse de risque."},{"p":2,"t":"OPÉRATIONS SOUS-TERRE"},{"p":2,"t":"Le département des opérations sous-terre doit exiger l’application de cette procédure. Il doit aussi participer à la mise en place des travaux en collaboration avec MRI et la géologie, en plus de participer à toute analyse de risque reliée au forage à distance."},{"p":2,"t":"1. Positionner la foreuse selon les plans et devis de forage 2. Installer le système à distance entre le foreur et le trou à forer à un minimum de 50' (15 mètres) (Se référer aux plans de forage): a. Le foreur et l’aide-foreur doivent être vers la sortie en s’assurant que rien ne bloque l’accès b."},{"p":2,"t":"Ne pas être dans la ligne de sautage, où c. Certains clients pourraient aussi exiger d’être derrière une protection comme : i. Une galerie perpendiculaire à celle où la foreuse est installée ii. Un équipement iii. Un amas de roche 3."},{"p":2,"t":"Tous les accès aux lieux forage (foreur et la foreuse) doivent être barricadés par une clôture (selon exigences/procédures du client) ou gardés par un travailleur, 4. Une signalisation indiquant le type de travaux (ex."},{"p":2,"t":": ACCÈS INTERDIT, FORAGE EN COURS, FORAGE À DISTANCE.) doit être appliquée sur la clôture 5. Cette procédure doit être mise dans un sac étanche sur les clôtures de tous les accès et signée par le foreur qui aura visité ces endroits avant le début du forage à distance, au début de chaque quart de travail."},{"p":3,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE AU DIAMANT"},{"p":3,"t":"Novembre 2022"},{"p":3,"t":"6. Si une visite des lieux de forage est nécessaire, l'opérateur doit être contacté par radio, ou si un contact visuel est possible, le foreur se déplacera pour aller rejoindre la ou les personnes voulant visiter les lieux. 7."},{"p":3,"t":"Le foreur et l’aide-foreur resteront en tout temps dans la zone sécuritaire pendant le forage."},{"p":3,"t":"Correctifs apporteés Date Par Dans la partie APPLICATION, précisions du forage vs les articles 439 et 440 Préciser de se référer aux plans de forage point #2b 2 avril 2025 S. Tremblay F.Croteau É. Thibeault"},{"p":3,"t":"____________________________ Christian St-Amour"},{"p":3,"t":"Directeur des opérations"},{"p":4,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE AU DIAMANT"},{"p":4,"t":"Novembre 2022"},{"p":4,"t":"FEUILLE DE SIGNATURES DES BARRICADES LORS DU FORAGE À DISTANCE"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":5,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE AU DIAMANT"},{"p":5,"t":"Novembre 2022"}],"pro-op-dd-013":[{"p":1,"t":"Date : 8 octobre 2021 1/5 Révision Mars 2025"},{"p":1,"t":"PROCÉDURE DE TRAVAIL"},{"p":1,"t":"PROCÉDURE DE TRAVAIL LORS DU DÉPLACEMENT D’UNE FOREUSE AU DIAMANT SUR UN PLANCHER"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour déplacer une foreuse au diamant sur un plancher de forage. Que ce soit avec le FEED EXTENSION, la BARRE DE SWING ou la BARRE DE FORCE."},{"p":1,"t":"APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL. INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes."},{"p":1,"t":"On entend par ‘’ZONE D’EXCLUSION’’, la zone du côté de la barrière (clôture et porte) où l’opérateur et les contrôles sont situés. RESPONSABILITÉS Le superviseur est responsable de faire connaître cette procédure au travailleur et de s’assurer qu’il la respecte."},{"p":1,"t":"Le travailleur doit respecter la procédure en tout temps. Équipement de protection individuel Outils nécessaire - Équipements de protection individuelles de base approuvés par le site - Barre de swing - Barre de force - Chaîne"},{"p":2,"t":"PROCÉDURE DE TRAVAIL LORS DU DÉPLACEMENT D’UNE FOREUSE AU DIAMANT SUR UN PLANCHER Date : 8 octobre 2021 2/5 Révision Mars 2025"},{"p":2,"t":"PROCÉDURE POUR LES DÉPLACEMENTS SUR LE PLANCHER À L’AIDE DU ‘’FEED EXTENSION’’"},{"p":2,"t":"TOUJOURS ÊTRE DANS LA ZONE D’EXCLUSION LORS DE TOUT MOUVEMENT DE LA FOREUSE"},{"p":2,"t":"1- Lorsque la foreuse a été déposée sur le plancher par l’équipement de transport, s’assurer qu’elle est le plus près de son point d’arrivée finale;"},{"p":2,"t":"2- Si la foreuse ne peut être assez approchée, il est permis de mettre trois (3) tiges de forage sur le plancher et déposer la foreuse dessus pour aider le déplacement sur une longue distance;"},{"p":2,"t":"3- Pour déplacer la foreuse sur le plancher, étirer le ‘’feed extension’’ vers le mur à rejoindre;"},{"p":2,"t":"4- Attacher une chaîne entre un point d’ancrage situé dans l’enlignement de la foreuse et le clam de la foreuse;"},{"p":2,"t":"5- Rétracter le ‘’feed extension’’, la foreuse se déplacera vers le mur où elle doit être installée;"},{"p":2,"t":"6- Toujours s’assurer d’avoir au moins deux (2) tiges sous la foreuse si on en utilise pour rouler la foreuse."},{"p":2,"t":"PROCÉDURE pour déplacer la foreuse à l’aide de la BARRE DE FORCE"},{"p":2,"t":"1- Mettre la tête de la foreuse à l’extrémité opposée au côté que vous voulez déplacer, ceci vous facilitera le travail"},{"p":2,"t":"2- Glisser la barre levier sous le treuil du côté opposé auquel vous voulez déplacer la foreuse."},{"p":3,"t":"PROCÉDURE DE TRAVAIL LORS DU DÉPLACEMENT D’UNE FOREUSE AU DIAMANT SUR UN PLANCHER Date : 8 octobre 2021 3/5 Révision Mars 2025"},{"p":3,"t":"TOUJOURS ORIENTER LE COTÉ LE PLUS LONG (OU CÔTÉ PLAT) DE LA BARRE VERS LE BAS AFIN D’ASSURER UNE BONNE ADHÉRENCE AU PLANCHER."},{"p":3,"t":"3- Pousser la barre à l’aide des jambes et des bras;"},{"p":3,"t":"SI VOUS AVEZ DE LA DIFFICULTÉ À LEVER LA BARRE C’EST QU’ELLE EST GLISSÉE TROP LOIN SOUS LE TREUIL."},{"p":3,"t":"TOUJOURS ÊTRE CONSCIENT QUE LA BARRE PEUT ÉCHAPPER"},{"p":4,"t":"PROCÉDURE DE TRAVAIL LORS DU DÉPLACEMENT D’UNE FOREUSE AU DIAMANT SUR UN PLANCHER Date : 8 octobre 2021 4/5 Révision Mars 2025"},{"p":4,"t":"4- Pour les foreuses munis d’un anneau de levage, insérer la barre de levage à l’intérieur de celle-ci et utiliser la même méthode de levage que les étapes précédentes;"},{"p":4,"t":"PROCÉDURE POUR DÉPLACER LA FOREUSE À L’AIDE DE LA ‘’PATTE DE SWING’’"},{"p":4,"t":"TOUJOURS ÊTRE DANS LA ZONE D’EXCLUSION LORS DE TOUT MOUVEMENT DE LA FOREUSE"},{"p":4,"t":"1- Positionner la foreuse à 0°, la tête centrée avec le feedframe et surélever légèrement la partie que l’on veut déplacer;"},{"p":4,"t":"2- Ajuster la longueur de la barre de swing pour effectuer le mouvement désiré;"},{"p":4,"t":"S’assurer de replacer la pine et la contre-pine"},{"p":5,"t":"PROCÉDURE DE TRAVAIL LORS DU DÉPLACEMENT D’UNE FOREUSE AU DIAMANT SUR UN PLANCHER Date : 8 octobre 2021 5/5 Révision Mars 2025"},{"p":5,"t":"3- Insérer la barre de swing du bon côté de la tour et l’incliner du côté opposé au mouvement recherché. La barre doit être placée du côté inverse au mouvement désiré"},{"p":5,"t":"S’assurer de coincer la barre solidement"},{"p":5,"t":"TOUJOURS ÊTRE DANS LA ZONE D’EXCLUSION LORS DE TOUT MOUVEMENT DE LA FOREUSE"},{"p":5,"t":"4- Avec l’hydraulique, appliquer une pression délicate sur la barre de swing avec la tour. La foreuse fera le déplacement planifié, orientés par la barre de swing, les patins doivent demeurer au sol;"},{"p":5,"t":"5- Répéter les étapes 3 et 4 jusqu’à ce que la foreuse atteigne la position désirée;"},{"p":5,"t":"APPLIQUER ENSUITE L’OUTIL D’ENLIGNEMENT PRIVILÉGIÉ SUR LE CONTRAT POUR LES DERNIERS DÉPLACEMENTS PRÉCIS. TN-14 WALLY WALLER SPAD ET CORDES"},{"p":5,"t":"Ajouts ou modifications Date Par Nouvelle procédure 8 octobre 2021 S. Tremblay Révvision complète 12 mars 2025 S. Tremblay F. Croteau"},{"p":5,"t":"_________________________________ Christian St-Amour Directeur des opérations"}],"pro-op-ith-002":[{"p":1,"t":"Date : 04 Janvier 2012"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-002"},{"p":1,"t":"UTILISATION DE CLÉS ET UN TIRE-FORT POUR DÉVISSER DES TIGES DE FORAGES OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour l’utilisation des clés pour dévisser des tiges coincées."},{"p":1,"t":"APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL. INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document sont le directeur général et le directeur des opérations."},{"p":1,"t":"Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes. RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure d’inspecter les outils nécessaires et de coordonner la tâche."},{"p":1,"t":"OUTILS NÉCESSAIRES"},{"p":1,"t":"• 1 tire-fort N.B. Les crochets doivent être munis de linguet. • 2 manilles 3/4 • Clé pour tige • Clé pour le saver sub"},{"p":2,"t":"UTILISATION DE CLÉS ET D’UN TIRE-FORT POUR DÉVISSER DES TIGES DE FORAGES"},{"p":2,"t":"Date : 04 Janvier 2012"},{"p":2,"t":"1. Positionner les entailles planes de la tige du haut vis à vis l’ancrage du mât et celle de la tige du bas dans la ‘slip plate’."},{"p":2,"t":"2. Appliquer la procédure de cadenassage"},{"p":2,"t":"3. Insérer la clé dans les entailles de la tige."},{"p":2,"t":"4. Installer un des crochets du tire-fort sur l’ancrage du mât et l’autre sur la manille du manche de la clé."},{"p":2,"t":"5. Commencer à actionner le tire-fort pour mettre une tension sur la tige de forage coincé."},{"p":2,"t":"6. Actionner le tire-fort jusqu’à ce que les tiges se séparent. N.B : Il sera peut-être nécessaire de donner un coup de masse sur le manche de la clé pour que les tiges se séparent."},{"p":2,"t":"Dans ce cas, assurez-vous que vos pieds soient sur une surface solide et que personne ne soit dans la ligne advenant que la masse soit échappée."},{"p":2,"t":"Ancrage du mât certifié 2500 kg"},{"p":3,"t":"UTILISATION DE CLÉS ET D’UN TIRE-FORT POUR DÉVISSER DES TIGES DE FORAGES"},{"p":3,"t":"Date : 04 Janvier 2012"},{"p":3,"t":"Cette opération peut aussi s’effectuer sans utiliser l’ancrage du mât. On peut utiliser le même principe en prenant deux clés. Dans ce cas il suffit de relier le tire-fort à chaque extrémité de clé et de mettre une tension."},{"p":3,"t":"Dévisser une tige de forage ou un marteau coincé dans le saver sub"},{"p":3,"t":"1. Positionner le mât à l’horizontale pour éviter que la clé à saver sub tombe; 2. Placer le gearbox le plus loin possible des tables pour avoir suffisamment d’espace pour installer la clé;"},{"p":3,"t":"3. Appliquer la procédure de cadenassage;"},{"p":4,"t":"UTILISATION DE CLÉS ET D’UN TIRE-FORT POUR DÉVISSER DES TIGES DE FORAGES"},{"p":4,"t":"Date : 04 Janvier 2012"},{"p":4,"t":"4. Installer la clé à saver sub sur celui-ci en la passant au travers du marteau ou de la rod;"},{"p":4,"t":"5. Installer la clé à rod sur le marteau ou la rod;"},{"p":5,"t":"UTILISATION DE CLÉS ET D’UN TIRE-FORT POUR DÉVISSER DES TIGES DE FORAGES"},{"p":5,"t":"Date : 04 Janvier 2012"},{"p":5,"t":"6. Installer un des crochets du tire-fort sur chacune des manilles des manches des clés;"},{"p":5,"t":"7. Actionner le tire-fort jusqu’à ce que les tiges se séparent. N.B : Il sera peut-être nécessaire de donner un coup de masse sur le manche de la clé pour que les tiges se séparent; 8. Retirer les deux clés et décadenasser l’équipement puis poursuivre les travaux. 9."},{"p":5,"t":"Ajouts ou modifications Date Par Ajout de la partie concernant le marteau ou rod coincé dans le saver sub Juillet 2022 S. Tremblay Ajout de la procédure de cadenassage lors du dévissage des rods Octobre 2024 S. Tremblay"},{"p":5,"t":"_______________________________ Christian St-Amour Directeur des opérations"}],"pro-op-ith-002a":[{"p":1,"t":"Date : January 2012"},{"p":1,"t":"WORK PROCEDURE PRO-OP-ITH-002A USE OF WRENCH TO UNSCREW DRILLING RODS WITH A COME ALONG OBCTIVES The purpose of this procedure is to define safe methods for using wrench to unscrew stuck rods APPLICATION This procedure applies to all employees of MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRETATION The staff with authority for the interpretation of this document is the Director of Operations. Any request for modification, revision or update must be made to one of this individual."},{"p":1,"t":"RESPONSABILITIES The worker responsible of drilling must ensure that this procedure is followed and inspect the necessary tools and coordinate the task."},{"p":1,"t":"NECESSARY TOOLS - 1 come along N.B. The hooks must be equipped with latches. - 2 shackles 3/4 - Rod wrench - Saver sub wrench - Sledgehammer"},{"p":2,"t":"USE OF WRENCH TO UNSCREW DRILLING RODS WITH A COME ALONG Date : January 2012"},{"p":2,"t":"1. Place the flat notches in the upper rod then opposite the boom anchor and the bottom rod in the 'flat slip'"},{"p":2,"t":"2. Apply the lock out tag out procedure;"},{"p":2,"t":"3. Insert the wrench into the notches in the rods."},{"p":2,"t":"4. Install one of the come along hooks on the boom anchor and the other on the wrench shackle."},{"p":2,"t":"5. Start tightening the come along to put tension on the jammed drill rod."},{"p":2,"t":"6. Tighten the come along until the rods separate. N.B: It may be necessary to hit the handle of the wrench with a sledgehammer to separate the rods. . In this case, make sure your feet are on a solid surface and that no one is in line if the hammer is dropped."},{"p":2,"t":"Certified anchor 2500 kg"},{"p":3,"t":"USE OF WRENCH TO UNSCREW DRILLING RODS WITH A COME ALONG Date : January 2012"},{"p":3,"t":"This operation can also be performed without using the boom anchor. The same principle can be used by taking two wrenches. In this case simply connect the come along to each end of the wrench and put a tension."},{"p":3,"t":"Unscrewing a rod or the hammer jammed in the saver sub"},{"p":3,"t":"1. Put the boom in horizontal position to prevent the saver sub wrench from falling; 2. Place the gearbox as far as possible from tables to have enough space to install the wrench."},{"p":4,"t":"USE OF WRENCH TO UNSCREW DRILLING RODS WITH A COME ALONG Date : January 2012"},{"p":4,"t":"3. Apply the lock out tag out procedure; 4. Install the saver sub wrench on it by passing it through the hammer or the rod;"},{"p":4,"t":"5. Install the rod wrench on the rod or on the hammer;"},{"p":5,"t":"USE OF WRENCH TO UNSCREW DRILLING RODS WITH A COME ALONG Date : January 2012"},{"p":5,"t":"6. Install one of the hooks of the come along on each of the shackles of the handles of the wrench;"},{"p":5,"t":"7. Operate the come along until the rods separate. N.B: It may be necessary to hit the handle of the wrench with a sledgehammer to help the rods to unscrew; 8. Remove the two wrenches and unlock the equipment then continue to work."},{"p":5,"t":"_______________________________ Christian St-Amour Directeur des opérations"},{"p":5,"t":"Adds and/or modifications Date By Addition of the sequence for rod or hammer jammed in the saver sub July 2022 S. Tremblay Changing “KEYS” for wrench Change some sentences to clarify December 2023 S. Tremblay Add lock out tag out at point #2 October 2024 S. Tremblay"}],"pro-op-ith-003":[{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-003"},{"p":1,"t":"DÉMOBILISATION ET DÉPLACEMENT DE LA FOREUSE ET DU COMPRESSEUR"},{"p":1,"t":"L’objectif de cette procédure est de définir une façon sécuritaire pour effectuer la démobilisation et le déplacement de la foreuse."},{"p":1,"t":"Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION"},{"p":1,"t":"La personne ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS"},{"p":1,"t":"Le foreur-guide est responsable d’organiser la démobilisation. Il est aussi responsable de mettre en place les activités entourant les déplacements des équipements."},{"p":1,"t":"Le travailleur a la responsabilité d’utiliser cette procédure pour chaque démobilisation et déplacement. Les procédures de transport d’équipement des sites doivent être respectées"},{"p":1,"t":"Mise en garde"},{"p":1,"t":"Les accessoires de levage nécessaires doivent être inspectés avant leur utilisation. Si une anomalie est détectée, le remplacement de l’accessoire est obligatoire avant d’entreprendre le déplacement de la foreuse ou de l’équipement."},{"p":1,"t":"L’utilisation de composantes approuvées est obligatoire. Aucune modification n’est autorisée"},{"p":2,"t":"DÉMOBILISATION ET DÉPLACEMENT D’ÉQUIPEMENT FOREUSE ET COMPRESSEUR"},{"p":2,"t":"11 avril 2015 Révision : Janvier 2019 MÉTHODE DÉMOBILISATION DE LA FOREUSE."},{"p":2,"t":"1. Placer le mât en position de transport avec la tête de forage à l’opposé des tables et attacher le mât à la foreuse à l’aide d’un tire-fort ou palan à chaine."},{"p":2,"t":"2. Fermer les valves à air et eau sur la ligne principale. Il est très important de purger les boyaux à air, sur le filtre à air et le receiver, et le boyau à eau avant de les découpler."},{"p":2,"t":"3. Fermer le disjoncteur sur le panneau électrique de la foreuse et positionner le câble électrique de façon qu’il ne soit pas encombrant, qu’il y ait une longueur suffisante pour le déplacement et pour ne pas l’abîmer. Remettre l’alimentation électrique à ‘’ON’’ juste avant de déplacer l’équipement."},{"p":2,"t":"4. Relier le traineau ou remorque au véhicule avec deux élingues minimum 1’’ X 8 pieds. Ces élingues doivent être fixées avec des manilles de 1’’1/4 minimum."},{"p":2,"t":"5. Placer le traineau afin qu’il soit le plus au niveau possible et le nettoyer s`il y a des roches ou de la boue."},{"p":2,"t":"Si c’est une remorque et qu’elle est reliée au godet d’une chargeuse (option #1), assurez-vous de la positionner suffisamment à angle de façon à éviter un contre coup lorsque la foreuse montera sur la remorque."},{"p":2,"t":"On favorisera l’utilisation de la main dans un godet de chargeuse au lieu d’attacher directement la remorque à l’arrière d’un véhicule."},{"p":3,"t":"DÉMOBILISATION ET DÉPLACEMENT D’ÉQUIPEMENT FOREUSE ET COMPRESSEUR"},{"p":3,"t":"11 avril 2015 Révision : Novembre 2022 Dans le cas où c’est impossible d’utiliser la main, l’option #2 pourra être utilisée tout en considérant que des pièces de bois pourraient devoir être placées au début des rampes afin de réduire la pente de l’accès à la remorque et par le fait même réduit l’effe"},{"p":3,"t":"t de balancement créé lors du déplacement de la foreuse."},{"p":3,"t":"6. Démarrer la foreuse et l`embarquer sur le traineau ou la remorque. Pour cet opération, l`opérateur doit toujours se placer à l’intérieur du panier de la foreuse et mettre la chaine garde-corps."},{"p":3,"t":"7. Une fois la foreuse en place, arrêter la foreuse et fermer l’interrupteur d’alimentation de la mine (GFP). Débrancher le câble électrique et le rouler sur le crochet prévu sur le coté du panier ou dans le panier. Bien l’attacher pour éviter qu’il soit endommagé lors du transport."},{"p":3,"t":"8. Attacher la foreuse de chaque coté de façon qu’elle ne peut pas avancer ou reculer durant le transport. Rapprocher et attacher la console au ‘’Slideover’’ solidement. Attacher les boyaux haute pression à la foreuse pour qu’ils ne soient pas accrochant."},{"p":3,"t":"9. Assurez-vous qu’il n’y a pas de pièces libres ou outils sur la foreuse avant de commencer le transport."},{"p":3,"t":"10. Une fois le déplacement terminé ne pas mettre le traineau attaché au mur, toujours le laisser par terre et mettre un ruban jaune pour signaliser sa présence."},{"p":4,"t":"DÉMOBILISATION ET DÉPLACEMENT D’ÉQUIPEMENT FOREUSE ET COMPRESSEUR"},{"p":4,"t":"11 avril 2015 Révision : Janvier 2019"},{"p":4,"t":"Démobilisation d’un compresseur"},{"p":4,"t":"1) Fermer les valves à air et eau. Il est très important de purger les boyaux à air et eau avant de les découpler."},{"p":4,"t":"2) Bien rouler le câble électrique et boyaux à l’air et les attacher de façon qu’il ne tombe pas."},{"p":4,"t":"3) Assurer-vous que les deux boulons de la barre de tir soient en place pour limiter le mouvement de pivot de la barre de tir."},{"p":4,"t":"4) Vérifier la main d’attelage qui est dans le godet du scoop pour s’assurer de son bon fonctionnement;"},{"p":4,"t":"5) S’assurer que le compresseur est stable lors de l’accouplement et du désaccouplement. Au besoin, appliquer un ou des stabilisateurs ou des cales de roues;"},{"p":4,"t":"Lorsque la barre de tir est rabaissée pour effectuer un déplacement, il faut la verrouiller avec le boulon."},{"p":5,"t":"DÉMOBILISATION ET DÉPLACEMENT D’ÉQUIPEMENT FOREUSE ET COMPRESSEUR"},{"p":5,"t":"11 avril 2015 Révision : Novembre 2022 6) Relier l’attache du compresseur au véhicule à l’aide de manilles de 1’’1/4 minimum."},{"p":5,"t":"7) Attacher les deux chaines de sécurité au véhicule de remorquage."},{"p":5,"t":"Procédure de démobilisation sans la remorque"},{"p":5,"t":"Il est permis de déplacer la foreuse sans la remorque, à l’aide d’une barre de tir, sur de courtes distances, à plat. Il est interdit de déplacer la foreuse sans la remorque dans la rampe."},{"p":5,"t":"1) Installer la barre de tir sur la foreuse à l’aide de manilles ¾’’ ;"},{"p":5,"t":"2) Raccorder la barre de tir à la chargeuse-navette avec une manille de 1 ¼’’. Assurer une bonne communication avec l’opérateur de la chargeuse;"},{"p":5,"t":"3) Débarrer les planétaires des tractions;"},{"p":5,"t":"4) Installer une chaîne sécurité (minimum qui relie la foreuse à la chargeuse (exemple entre slide-over et godet de la chargeuse)"},{"p":5,"t":"5) Le déplacement doit se faire à basse vitesse"},{"p":5,"t":"N.B Appliquer la politique du site concernant les escortes pour le déplacement des équipements."},{"p":5,"t":"Ajouts ou modifications Date Par Point #4- Ajouter : Vérifier main d’attelage Point #5- Ajouter de s’assurer que le compresseur est stable lors de l’accouplement ou du désaccouplement 25-22-2022 S. Tremblay Ajout de la partie de déplacement sans la remorque 24-03-2023 S. Tremblay S."},{"p":5,"t":"Desrosiers Mise en page et en-têtes Décembre 2023 S. Tremblay"},{"p":5,"t":". Christian St-Amour Directeur des opérations"}],"pro-op-ith-004":[{"p":1,"t":"Mars 2002 Révision : Décembre 2023"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-004"},{"p":1,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour effectuer le forage de production de 3 7/8’’ à 6 ½’’. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document sont le directeur général et le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes."},{"p":1,"t":"RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure et de respecter les consignes qui proviennent du département d’ingénierie"},{"p":1,"t":"PROCÉDURE POUR LE FORAGE DE PRODUCTION"},{"p":1,"t":"3 7/8 pouces à 6 ½ pouces"},{"p":1,"t":"1. Les employés de M.R.I. peuvent déplacer l’équipement de forage à la place de travail en utilisant l’équipement de la compagnie, en respectant toute réglementation et directive de la compagnie."},{"p":1,"t":"2. Une inspection visuelle doit être faite de l’équipement de forage sur le lieu de travail ainsi que la ventilation, l’alimentation d’énergie et la distribution de l’eau et de l’air."},{"p":2,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":2,"t":"Mars 2002 Révision : Décembre2023 3. Le câble électrique est déchargé, inspecté et branché à la distribution d’énergie (ground fault box). Un électricien de la compagnie est requis s’il faut reconnecter la rotation du moteur."},{"p":2,"t":"4. La vérification de tous les leviers de commande est requise avant de déplacer l’unité de forage. Ils doivent être au neutre (point mort) avant que l’unité soit mise sous tension."},{"p":2,"t":"5. Une inspection visuelle de l’unité de forage est requise pour vérifier les huiles, les jauges, les fuites, etc. avant de la déplacer."},{"p":2,"t":"Il est primordial de faire une inspection rigoureuse de nos équipements dès qu’on doit les opérer. Dans le cas des CUBEX et des surcompresseurs, une attention particulière doit être portée sur les boyaux tressés haute- température (800 degrés F) des compresseurs."},{"p":2,"t":"Pour des raisons de sécurité, seul le type de boyau tel que présenté ci-dessous doit être utilisé."},{"p":2,"t":"6. Avant de déplacer l’unité de forage à la première ligne de forage, en respectant les plans et devis, il faut laver la zone de travail à partir des headers, vérifier"},{"p":3,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":3,"t":"Mars 2002 Révision : Décembre2023 l’écaillage et faire une inspection à la recherche d’explosifs restant dans le chantier ou non détonnés."},{"p":3,"t":"7. La foreuse est déplacée dans la zone de forage et nous prenons les précautions nécessaires pour ne pas endommager le câble électrique qui suit la foreuse. Si l’extension doit être manipulée alors qu’elle est sous tension, il faut utiliser le crochet de plastique."},{"p":3,"t":"Des barricades ou des affiches sont installées pour aviser tous les travailleurs des opérations en cours (trous ouverts, forage, etc.)."},{"p":3,"t":"Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…) Voir STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS"},{"p":3,"t":"8. Rendu au point de forage il faut mettre la foreuse hors tension en appuyant sur le E-STOP. Accrocher le câble électrique au mur au niveau de la poitrine (4 à 5 pieds du banc) pour éliminer tout contact avec des roches branlantes ou des véhicules motorisés."},{"p":3,"t":"Une inspection visuelle du câble doit être faite durant cette étape afin de déceler un bris."},{"p":3,"t":"9. La connexion du boyau à air de basse pression (2½ po. dia.) du dispositif d’alimentation de la mine au compresseur renforçateur de la foreuse est la prochaine priorité. Le boyau d’alimentation est relié au dispositif de purge et il est soufflé."},{"p":3,"t":"Ensuite retirer le boyau et le relier à l’entrée d’air de la foreuse. Les dispositifs de retenues (whip check) sont installés à chaque joint (s’il y en a un). A ce point, une inspection des dispositifs de retenu est importante."},{"p":3,"t":"Il faut vérifier l’état du câble métallique et le bon fonctionnement des mécanismes de serrage."},{"p":3,"t":"10. Le boyau à haute pression renforci (2½) est inspecté, soufflé et connecté du compresseur à la foreuse en installant les dispositifs de retenues à chacune des connections. (Note: Les « stem nuts » sur les boyaux de 2½ po. dia."},{"p":3,"t":"sont faits pour qu’ils ne puissent pas être interchangés entre la basse et haute pression pour éliminer tout accident potentiel)."},{"p":4,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":4,"t":"Mars 2002 Révision : Décembre2023"},{"p":4,"t":"Attention particulière requise Les raccords et boyaux doivent être inspectés minutieusement afin de s’assurer que les collets soient bien serrés, que les filets des raccords d’accouplement sont en bonne état et que les boyaux ne présentent aucune anomalie."},{"p":4,"t":"11. Le boyau à eau de 1 po. dia. est inspecté, soufflé et connecté au dispositif d’alimentation de la mine au système de refroidisseur d'eau du compresseur renforçateur et à la foreuse."},{"p":4,"t":"12. Tous les boyaux sont suspendus en dessous du câble électrique pour éliminer tout contact avec des roches branlantes et/ou de l’équipement minier."},{"p":4,"t":"13. S’il n’est pas physiquement possible de suspendre le câble et les boyaux (ex. les dimensions du chantier) ils sont étendus de façon à éliminer tout contact possible ou l’écrasement."},{"p":4,"t":"Ils peuvent être soulevés du banc avec des bidons ou des trépieds en bois et marqués (peinturés ou identifiés avec une banderole) pour être plus visible."},{"p":4,"t":"14. Les lignes d’eau et d’air sont pressurisées avec soin et inspectées pour des fuites."},{"p":4,"t":"15. La console de la foreuse doit être positionnée de façon à offrir une protection aux employés de toute pièce mouvement ou de toute projection de roches qui pourrait survenir en coupant le collet du trou pilote."},{"p":4,"t":"Une distance minimum de 1.5 mètre entre le mât et la console doit obligatoirement être respectée. Quand une pièce est en mouvement, aucun"},{"p":5,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":5,"t":"Mars 2002 Révision : Décembre2023 travailleur ne peut se placer entre la console et le mât, ni à moins de 1,5 mètre du mât de tous les côtés."},{"p":5,"t":"16. La foreuse est ensuite positionnée au-dessus de la cible de forage (sur la ligne et avec le pendage désiré) comme précisé dans les plans et devis fournis en utilisant un laser magnétique et un laser digital clinomètre pour le contrôle de qualité."},{"p":5,"t":"LORS DU DÉPLACEMENT DE LA FOREUSE AU-DESSUS D’UN COUVERCLE DE MÉTAL QUI EST SUR LA MONTERIE, IL EST IMPORTANT DÊTRE ATTENTIF POUR ÉVITER QUE LE COUVERCLE SE COINCE ENTRE LES TRACTIONS DE LA FOREUSE"},{"p":5,"t":"17. Lors du déplacement du mât en rotation, une attention particulière doit être portée aux boyaux hydrauliques, ils pourraient se coincer. Si c’est le cas, revenir en arrière et bouger le mât pour ramollir les boyaux et les décoincer."},{"p":5,"t":"Si un effort est nécessaire pour décoincer les boyaux, s’assurer d’être en position stable."},{"p":5,"t":"18. Le tubage est foré et installé au collet de tous les trous à moins qu’il soit spécifié autrement dans les plans et devis ;"},{"p":5,"t":"19. Les trous sont forés à la profondeur requise ;"},{"p":5,"t":"20. Lors du défoncement de trous, il est important de pousser, SANS ROTATION, 1 tige de plus que la longueur du défoncement ;"},{"p":5,"t":"21. Les trous forés en descendant sont obstrués tel que requis dans les plans et devis ;"},{"p":5,"t":"22. Les marteaux, forets et tiges sont positionnés manuellement par l’opérateur pour tous les trous de production de moins de 6 1/2 po. de diamètre ;"},{"p":5,"t":"Pour installer ou enlever les tiges de forage, la boîte de vitesse doit être relevée et arrêtée. La foreuse doit être à la position neutre (point mort) avant que les tiges de forage soient manipulées ;"},{"p":5,"t":"23. Pour les trous de production plus gros que 6½ po. de dia. l’opérateur doit utiliser le chariot de transport ou la cloche et la chaine. S’assurer que le chariot est stable lorsqu’on dépose le marteau dessus."},{"p":5,"t":"En dernier recours, le marteau pourrait être transporté manuellement avec l’aide d’un autre travailleur. Changer les forêts et les tiges peut être fait seul dépendamment de la longueur des trous forés."},{"p":5,"t":"Nous privilégions la présence d’un 2e travailleur pour le forage et l’arrachement des tiges pour les trous de 200 pieds et plus. S’il n’est pas possible d’avoir ce 2e travailleur, le foreur doit prévoir des pauses"},{"p":6,"t":"FORAGE DE PRODUCTION, 3 7/8 \" à 6 ½\""},{"p":6,"t":"Mars 2002 Révision : Décembre2023"},{"p":6,"t":"AVERTISSEMENT LA MANIPULATION DES TRÉPANS DOIT ÊTRE FAITE AVEC ATTENTION. ON DOIT ÉVALUER LES DISTANCES POUR LES DÉPOSER ET ÉVITER LES COINCEMENTS."},{"p":6,"t":"Ajouts ou modifications Date Par Ajout du déplacement de la foreuse au-dessus du couvercle entre les points 16 et 17 3 décembre 2020 S. Tremblay Ajout au point #17 de la possibilité de coincement des boyaux hydrauliques et des mesures à prendre si ça survient. 12 janvier 2023 S."},{"p":6,"t":"Tremblay Ajout de la mise en garde sur les inspections et les boyaux haute-température 7 avril 2023 S. Tremblay Ajout de la distance de 3 mètres entre le ruban et les premières pièces de matériel dans le chantier."},{"p":6,"t":"Ajout fait au point #7 et sur le ‘’STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS’’ à la suite de l’événement d’Amaruk 19 décembre 2023 S. Tremblay S. Desrosiers Point #20 ajout de pousser sans rotation 1 tige de plus après le défoncement du trou 10 juin 2024 S. Tremblay JF Gagnon"},{"p":6,"t":"Christian St-Amour Directeur des opérations"},{"p":7,"t":"Mars 2002 Révision : Décembre 2023"},{"p":7,"t":"STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS (Noter que la distance entre la foreuse et le surcompresseur doit être de 7 mètres) (Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…)"},{"p":7,"t":"b a r r i c a d e"}],"pro-op-ith-005":[{"p":1,"t":"Mars 2002 Révision: Avril 2024"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-005"},{"p":1,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour effectuer l’alésage en descendant sans accès avec la tête aléseuse V-30. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document sont le directeur général et le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes."},{"p":1,"t":"RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure et de respecter les consignes qui proviennent du département d’ingénierie."},{"p":1,"t":"PROCÉDURE POUR L’ALÉSAGE EN DESCENDANT SANS ACCÈS V-30"},{"p":1,"t":"1) Les employés de M.R.I. peuvent déplacer l’équipement de forage à la place de travail en utilisant l’équipement de la compagnie en respectant toute réglementation et directives de la compagnie ;"},{"p":1,"t":"2) Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…) Voir STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS"},{"p":1,"t":"3) Une inspection visuelle doit être faite de l’équipement de forage sur le lieu de travail ainsi que la ventilation, l’alimentation d’énergie et la distribution de l’eau et de l’air ;"},{"p":2,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":2,"t":"Mars 2002 Révision : Juin 2024 4) Le câble électrique est déchargé, inspecté et branché à la distribution d’énergie (ground fault box). Un électricien de la compagnie est requis s’il faut reconnecter la rotation du moteur ;"},{"p":2,"t":"5) La vérification de tous les leviers de commande est requise avant de déplacer l’unité de forage. Ils doivent être au neutre avant que l’unité soit mise sous tension ;"},{"p":2,"t":"6) Une inspection visuelle de l’unité de forage est requise pour vérifier les huiles, les jauges, les fuites, etc. avant de la déplacer ;"},{"p":2,"t":"Il est primordial de faire une inspection rigoureuse de nos équipements dès qu’on doit les opérer. Dans le cas des CUBEX et des surcompresseurs, une attention particulière doit être portée sur les boyaux tressés haute- température (800 degrés F) des compresseurs."},{"p":2,"t":"Pour des raisons de sécurité, seul le type de boyau tel que présenté ci-dessous doit être utilisé."},{"p":2,"t":"7) Avant de déplacer l’unité de forage à la première ligne de forage selon les plans et devis, il faut laver la zone de travail, vérifier l’écaillage et faire une inspection du"},{"p":3,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":3,"t":"Mars 2002 Révision : Juin 2024 plancher et des bas de murs pour voir s’il y a des explosifs non-détonnés dans le chantier ;"},{"p":3,"t":"8) La foreuse est déplacée dans la zone de forage et nous prenons les précautions nécessaires pour ne pas endommager le câble électrique qui suit la foreuse et aussi nous vérifions s’il n’y a pas de fuites ou anomalies sur la foreuse pendant les déplacements ;"},{"p":3,"t":"Si l’extension doit être manipulée alors qu’elle est sous tension, il faut utiliser le crochet de plastique. Des barricades ou des affiches sont installées pour aviser tous les travailleurs des opérations en cours ;"},{"p":3,"t":"9) Rendu au point de forage il faut mettre la foreuse hors tension en appuyant sur le E- STOP. Accrocher le câble électrique au mur au niveau de la poitrine (4 à 5 pieds du banc) pour éliminer tout contact avec des roches branlantes ou des véhicules motorisés."},{"p":3,"t":"Une inspection visuelle du câble doit être faite durant cette étape afin de déceler un bris ;"},{"p":3,"t":"10) La connexion du boyau à air de basse pression (2½ po. dia.) du dispositif d’alimentation de la mine au compresseur renforçateur (booster) de la foreuse est la prochaine priorité. Le boyau d’alimentation est relié au dispositif de purge et il est soufflé."},{"p":3,"t":"Ensuite retirer le boyau et le relier à l’entrée d’air de la foreuse. Les dispositifs de retenues (whip check) sont installés à chaque joint (s’il y en a un). A ce point, une inspection des dispositifs de retenu est importante."},{"p":3,"t":"Il faut vérifier l’état du câble métallique et le bon fonctionnement des mécanismes de serrage ;"},{"p":3,"t":"11) Le boyau à haute pression renforci (2½) est inspecté, soufflé et connecté du compresseur à la foreuse en installant les dispositifs de retenues à chacune des connections. (Note: Les « stem nuts » sur les boyaux de 2½ po. dia."},{"p":3,"t":"sont faits pour qu’ils ne puissent pas être inter changés entre la basse et haute pression pour éliminer autant que possible, tout accident potentiel.) ;"},{"p":4,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":4,"t":"Mars 2002 Révision : Juin 2024"},{"p":4,"t":"Attention particulière requise Les raccords et boyaux doivent être inspectés minutieusement afin de s’assurer que les collets soient bien serrés, que les filets des raccords d’accouplement sont en bonne état et que les boyaux ne présentent aucune anomalie ;"},{"p":4,"t":"12) Le boyau à eau de 1 po. dia. est inspecté, soufflé et connecté au dispositif d’alimentation de la mine au système de refroidisseur d'eau du compresseur renforçateur et à la foreuse ;"},{"p":4,"t":"13) Tous les boyaux sont suspendus en-dessous du câble électrique pour éliminer tout contact avec des roches branlantes et/ou de l’équipement minier ;"},{"p":4,"t":"14) S’il n’est pas physiquement possible de suspendre le câble et les boyaux (ex. les dimensions du chantier) ils sont étendus de façon à éliminer tout contact possible ou l’écrasement."},{"p":4,"t":"Ils peuvent être soulevés du banc avec des bidons ou des trépieds en bois et marqués (peinturés ou identifiés avec une banderole) pour être plus visibles ;"},{"p":4,"t":"15) Les lignes d’eau et d’air sont pressurisées avec soin et inspectées pour des fuites ;"},{"p":4,"t":"16) La console de la foreuse doit être positionnée à 1,5 mètre du mât et de façon à offrir une protection aux travailleurs de toute projection de roches, qui pourrait survenir en tout temps durant le forage ;"},{"p":4,"t":"17) La foreuse est ensuite positionnée au-dessus de la cible de forage (sur la ligne et avec le pendage désiré) comme précisé dans les plans et devis fournis en utilisant un laser magnétique et un laser digital clinomètre pour le contrôle de qualité ;"},{"p":5,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":5,"t":"Mars 2002 Révision : Juin 2024 18) Lors du déplacement du mât en rotation, une attention particulière doit être portée aux boyaux hydrauliques, ils pourraient se coincer. Si c’est le cas, revenir en arrière et bouger le mât pour ramollir les boyaux et les décoincer."},{"p":5,"t":"Si un effort est nécessaire pour décoincer les boyaux, s’assurer d’être en position stable ;"},{"p":5,"t":"19) Pour le trou pilote de 6½ po. de dia., l’opérateur doit utiliser le chariot de transport ou la cloche et la chaine pour manipuler le marteau. S’assurer que le chariot est stable lorsqu’on y dépose le marteau."},{"p":5,"t":"En dernier recours, le marteau pourrait être transporté manuellement avec l’aide d’un autre travailleur. Changer les forêts et les tiges peut être fait seul dépendamment de la longueur des trous forés ;"},{"p":5,"t":"Nous privilégions la présence d’un 2e travailleur pour le forage et l’arrachement des tiges pour les trous de 200 pieds et plus. S’il n’est pas possible d’avoir ce 2e travailleur, le foreur doit prévoir des pauses"},{"p":5,"t":"20) Pendant le forage du trou, personne (employé ou autre) n’est autorisé à circuler en avant de la foreuse ;"},{"p":5,"t":"21) Pour installer ou enlever les tiges de forage, la boîte de vitesse (gear box) doit être relevée et arrêtée. La foreuse doit être à la position neutre (homme mort) avant que les tiges de forage soient manipulées ;"},{"p":5,"t":"22) Lorsque le trou pilote de 6 ½ po. est complété, on doit aléser le trou à 10 po. pour le centralisateur (nez) de la V-30. La même méthode est employée pour l'installation et la désinstallation des tiges ;"},{"p":5,"t":"23) Lors du défoncement de trous, il est important de pousser, SANS ROTATION, 1 tige de plus que la longueur du défoncement ;"},{"p":5,"t":"INSTALLATION DE LA V-30 SUR LE MÂT DE LA FOREUSE"},{"p":5,"t":"NB : Ne jamais se tenir dans l’axe de déplacement possible de la tête si elle se décroche. S’assurer que les contrôles soient en position neutre"},{"p":5,"t":"1. Positionner la foreuse dans l’axe de la V-30 à une distance d’environ 15 pieds. La tête doit être orientée de la façon suivante; stabilisateur vers la foreuse et le centralisateur (nez) pointant vers l’avant;"},{"p":5,"t":"2. Incliner le mât à un angle d’environ 60 degrés vers l’arrière en gardant la base du mât au sol. Si ce n’est pas possible d’appuyer la base au sol pour approcher la tête, allonger le stinger pour créer un appui et stabiliser le mât et la foreuse;"},{"p":5,"t":"3. Installer l’adaptateur mâle dans le gear box ainsi que l’adaptateur femelle sur le drive shaft de la V-30;"},{"p":6,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":6,"t":"Mars 2002 Révision : Juin 2024 4. Installer la chaîne (grade 80, 12 pieds) entre le gear box de la foreuse et le drive shaft de la V-30;"},{"p":6,"t":"5. Utiliser le feed cylindre pour hisser la V-30 vers la table jusqu'à ce que le drive shaft soit entré suffisamment dans la table pour accoupler le gear box au drive shaft de la V-30;"},{"p":6,"t":"6. Fermer les centralisateurs sur le drive shaft de la V-30;"},{"p":6,"t":"7. Fermer la foreuse et enlever les adaptateurs;"},{"p":6,"t":"8. Positionner le mât afin d’aligner le drive shaft et le gear box;"},{"p":6,"t":"9. Approcher le gear box sur le drive shaft et amorcer la rotation pour les visser ensemble;"},{"p":6,"t":"10. Engager la slip plate dans les coches de la tige pour serrer le montage ;"},{"p":6,"t":"11. Retirer la pine et ouvrir les tables;"},{"p":6,"t":"12. Hisser complètement la V-30 sur le mât ;"},{"p":6,"t":"13. Refermer les tables de chaque côté de la V-30 pour la stabiliser ;"},{"p":6,"t":"14. Réaligner le mât en position de forage initial ;"},{"p":6,"t":"15. Aligner le nez de la V-30 dans le trou pilote et commencer les manœuvres de démarrage du trou de 30 pouces ;"},{"p":6,"t":"16. Aussitôt que la tête de la V-30 est complètement entrée dans le roc (approx. 6 pi.) la foreuse est arrêtée et un couvert (plancher amovible) est installé pour offrir le maximum de protection pour les employés et l’équipement ;"},{"p":6,"t":"Couvert en bois"},{"p":7,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":7,"t":"Mars 2002 Révision : Juin 2024 Couvert en plastique"},{"p":7,"t":"L’installation du couvert fourni par M.R.I. ou le client sur la monterie est obligatoire en tout temps lors du forage de V-30 en descendant ;"},{"p":7,"t":"Si le couvert doit être enlevé ou remis, les employés travaillant près de la monterie doivent être attachés en tout temps au moyen d’une longe restrictive ajustable qui empêche l’accès au trou ou avec un harnais et un bloc rétractable."},{"p":7,"t":"Tout équipement de protection contre les chutes doit être approuvé par le client."},{"p":7,"t":"17. Pendant le forage, si le trou pilote se bloque il faudra sortir la tête de forage V-30 et procéder au déblocage : a."},{"p":7,"t":"Lorsque la tête est sortie et stabilisée à l’intérieur du mât avec les tables fermées vous devez replacer le couvercle de protection sur l’ouverture dangereuse et finalement déplacer le mât."},{"p":7,"t":"Assurez-vous que cette manœuvre peut se faire sans qu’une des composantes du mât ou de la V-30 entre en contact avec la paroi rocheuse ou le collet du trou ;"},{"p":7,"t":"b. Retirer la tête aléseuse de la foreuse et la déposer à une distance l’empêchant de nuire aux opérations de déblocage ;"},{"p":7,"t":"c. L’aide foreur peut guider l’opérateur tout en évitant de s’exposer dans la zone des pièces en mouvement ;"},{"p":7,"t":"d. Repositionner le mât pour installer le marteau de 6 pouces ;"},{"p":8,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":8,"t":"Mars 2002 Révision : Juin 2024 e. Afin de débloquer le trou pilote, y aligner le marteau de 6 pouces jusqu’à ce que le trou soit débloqué ;"},{"p":8,"t":"18. Dépendant des conditions du terrain, le changement des forets et une inspection visuelle sont requis périodiquement. La tête de la V-30 est remontée et avant que l’enttretien ne soit effectuée, le couvert doit être installé sur le trou."},{"p":8,"t":"Ceci est nécessaire pour la protection des employés quand ils font la maintenance sur la tête ou qu’ils changent les forets ;"},{"p":8,"t":"19. La tête est inspectée pour toute réparation possible et ensuite les forets peuvent être changés à ce moment ;"},{"p":8,"t":"Si, pour des raisons d’opération, le couvert protecteur doit être enlevé et que les travailleurs s’exposent à une chute, il doit porter le harnais de sécurité antichute et être attaché à des points d’ancrage approuvés par le client et selon son programme de protection contre les chutes"},{"p":8,"t":"20. L’affûtage et le re-façonnage des forets peuvent être faits dans le chantier en appliquant la PRO-SEC-010 - Procédure pour affûtage de trépan sous terre ;"},{"p":8,"t":"21. Si les monteries sont planifiées pour plus de 40 pieds de forage, le foreur de M.R.I. doit installer un centralisateur pour stabiliser les tiges ;"},{"p":8,"t":"IL EST STRICTEMENT INTERDIT A UN EMPLOYÉ D’ENTRER DANS LA MONTERIE DE 30 POUCES POUR RECUPERER QUOI QUE CE SOIT"},{"p":8,"t":"M.R.I. A DES EQUIPEMENTS ADAPTÉS POUR EXTRAIRE LES MATERIAUX QUI SONT BRISÉS DANS LES TROUS (EX. TIGES DE FORAGE OU FORETS) POUR QUE LE FORAGE CONTINUE"},{"p":8,"t":"22. Le couvercle d’acier doit être installé : a. Dès que le forage de la V-30 est terminé, OU ; b. Que son forage est suspendu pour forer des trous de production, OU ; c. Pour effectuer du déblocage ; Couvert en acier"},{"p":9,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":9,"t":"Mars 2002 Révision : Juin 2024 23. Le couvercle doit rester sur la monterie jusqu’à ce que l’équipe de dynamitage de la mine ne le retire ;"},{"p":9,"t":"24. Quand les équipements sont sortis du chantier, une barricade et/ou des affiches doivent être installées pour que toutes les personnes soient avisées qu’il y a une condition de trou ouvert dans le secteur."},{"p":9,"t":"Le client est informe de la situation et il peut entreprendre les précautions nécessaires de sécurité qui s’appliquent ;"},{"p":9,"t":"Procédure d’un bris de la tige de forage :"},{"p":9,"t":"a. Advenant un bris de la tige de forage, arrêter immédiatement l’opération de forage, fermer l’interrupteur électrique ainsi que l’alimentation en air comprimé;"},{"p":9,"t":"b. Une barricade, un ruban rouge et/ou des panneaux ‘’ACCÈS INTERDIT’’ doivent par la suite être installés à l’entrée du chantier de façon à empêcher tout accès au site de travail;"},{"p":9,"t":"c. L’opérateur doit aviser son contremaitre de la situation et aucun travail de forage est permis avant l’arrivée du contremaitre sur les lieux de travail;"},{"p":9,"t":"d. L’opérateur, avec la collaboration du contremaitre, évaluera la situation et déterminera la méthode par laquelle la tige de forage sera retirée du trou et changée;"},{"p":9,"t":"e. La présence du contremaitre sur les lieux du travail est requise jusqu’à ce que la tâche de récupération de la tige soit complétée;"},{"p":9,"t":"f. Toutes activités d’opération de la foreuse qui seront requises pendant le travail de récupération de la tige doivent être accomplies en utilisant les contrôles à distance. Les contrôles doivent être placée dans un endroit sécuritaire, éloigné de la foreuse, qui assurera la sécurité de l’opérateur;"},{"p":9,"t":"g. Lorsque la tige brisée à été retirée et remplacée, toutes les autres tiges de forage seront retirées du trou et vérifiées, et ce dans le but de s’assurer qu’il n’y a pas une autre tige endommagée;"},{"p":9,"t":"h. Le contremaitre s’assurera que les outils et les équipements de forage sont dans des conditions optimales pour reprendre les activités de forage et donnera son approbation pour reprendre les activités;"},{"p":9,"t":"i. Le contremaitre s’assurera que la tige de forage brisée a été étiquetée et retournée au fournisseur pour déterminer la raison du bris;"},{"p":10,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":10,"t":"Mars 2002 Révision : Juin 2024 j. Le contremaitre devra compléter le rapport d’incident qui donnera les circonstances et détails du bris, l’opération de récupération de la tige et les actions correctives nécessaires à la suite de l’incident et de l’analyse de la tige;"},{"p":10,"t":"Ajouts ou modifications Date Par Ajout de l’obligation de mettre un couvercle de métal sur le trou au point #28 3 décembre 2020 S. Tremblay Changer tournure de phrase pour l’interdiction d’entrer dans la monterie pour récupérer pièces après point #29 3-12-2020 S."},{"p":10,"t":"Tremblay Point 2- Ajouter en …S’assurer que les contrôles sont en position neutre 12-02-2021 S. Tremblay Ajout au point #17 de la possibilité de coincement des boyaux hydrauliques et des mesures à prendre si ça survient. 12-01-2023 S. Tremblay 03-2023 S. Tremblay J-F Gagnon S."},{"p":10,"t":"Desrosiers Ajout de la mise en garde sur les inspections et les boyaux haute-température 7 avril 2023 S. Tremblay Ajout de la distance de 3 mètres entre le ruban et les premières pièces de matériel dans le chantier."},{"p":10,"t":"Ajout fait au point #2 et sur le ‘’STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS’’ à la suite de l’événement d’Amaruk 19 décembre 2023 S. Tremblay S. Desrosiers Point #16 ajouter 1,5 m et rephraser la fin du point 23 avril 2024 S."},{"p":10,"t":"Tremblay Ajout #23 de pousser une tige de plus pour le défonçage des trous 21 juin 2024 S. Tremblay JF Gagnon"},{"p":10,"t":"________________________________ Christian St-Amour Directeur des Opérations"},{"p":11,"t":"ALÉSAGE EN DESCENDANT SANS ACCÈS, V-30"},{"p":11,"t":"Mars 2002 Révision : Juin 2024"},{"p":11,"t":"STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS (Noter que la distance entre la foreuse et le surcompresseur doit être de 7 mètres) (Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…)"},{"p":11,"t":"b a r r i c a d e 3 m (10’)"}],"pro-op-ith-006":[{"p":1,"t":"PROCÉDURE DE TRAVAIL"},{"p":1,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour effectuer l’alésage conventionnel avec la tête de forage V-30. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document sont le directeur général et le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes."},{"p":1,"t":"RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure et de respecter les consignes qui proviennent du département d’ingénierie."},{"p":1,"t":"MÉTHODE POUR L’ALÉSAGE"},{"p":1,"t":"1. Les employés de M.R.I. peuvent déplacer l’équipement de forage à la place de travail en utilisant l’équipement de la compagnie en respectant toute réglementation et directives de la compagnie."},{"p":1,"t":"2. Une inspection visuelle doit être faite de l’équipement de forage sur le lieu de travail ainsi que la ventilation, l’alimentation d’énergie et la distribution de l’eau et de l’air."},{"p":1,"t":"3. Le câble électrique est déchargé, inspecté et branché à la distribution d’énergie (ground fault box). Un électricien de la compagnie est requis s’il faut reconnecter la rotation du moteur,"},{"p":2,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":2,"t":"2 Mars 2002 Révision: Juin 2024 4. La vérification de tous les leviers de commande est requise avant de déplacer l’unité de forage. Ils doivent être au neutre (point mort) avant que l’unité soit mise sous tension."},{"p":2,"t":"5. Une inspection visuelle de l’unité de forage est requise pour vérifier les huiles, les jauges, les fuites, etc. avant de la déplacer."},{"p":2,"t":"Il est primordial de faire une inspection rigoureuse de nos équipements dès qu’on doit les opérer. Dans le cas des CUBEX et des surcompresseurs, une attention particulière doit être portée sur les boyaux tressés haute-température (800 degrés F) des compresseurs."},{"p":2,"t":"Pour des raisons de sécurité, seul le type de boyau tel que présenté ci- dessous doit être utilisé."},{"p":2,"t":"6. Avant de déplacer l’unité de forage à la première ligne de forage, en respectant les plans et devis, il faut laver la zone de travail, vérifier l’écaillage et faire une inspection pour des explosifs restant dans le chantier ou non détonnés."},{"p":3,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":3,"t":"3 Mars 2002 Révision: Juin 2024 7. La foreuse est déplacée dans la zone de forage et nous prenons les précautions nécessaires pour ne pas endommager le câble électrique qui suit la foreuse et aussi nous vérifions s’il n’y a pas de fuites ou anomalies de la foreuse en mouvement."},{"p":3,"t":"Si l’extension doit être manipulée alors qu’elle est sous tension, il faut utiliser le crochet de plastique. Des barricades ou des affiches sont installées pour aviser tous les travailleurs des opérations en cours (trous ouverts, forage, etc.)."},{"p":3,"t":"Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…) Voir STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS"},{"p":3,"t":"8. Rendu au point de forage il faut mettre la foreuse hors tension en appuyant sur le E-STOP. Accrocher le câble électrique au mur au niveau de la poitrine (4 à 5 pieds du banc) pour éliminer autant que possible, tout contact avec des roches branlantes ou des véhicules motorisés."},{"p":3,"t":"Une inspection visuelle du câble doit être faite durant cette étape afin de déceler un bris."},{"p":3,"t":"9. Rendu au point de forage il faut mettre la foreuse hors tension et accrocher le câble électrique au mur au niveau de la poitrine (4 à 5 pieds du banc) pour éliminer autant que possible, tout contact avec des roches branlantes ou des véhicules motorisés."},{"p":3,"t":"Aussi, en suspendant le câble électrique, une inspection visuelle de l’état du câble sera faite."},{"p":3,"t":"10. La connexion du boyau à air de basse pression (2½ po. dia.) du dispositif d’alimentation de la mine au compresseur renforçateur de la foreuse est la prochaine priorité. Le boyau d’alimentation est relié au dispositif de purge et il est soufflé."},{"p":3,"t":"Ensuite retirer le boyau et le relier à l’entrée d’air de la foreuse. Les dispositifs de retenues (whip check) sont installés à chaque joint (s’il y en a un). A ce point, une inspection des dispositifs de retenu est importante."},{"p":3,"t":"Il faut vérifier l’état du câble métallique et le bon fonctionnement des mécanismes de serrage."},{"p":3,"t":"11. Le boyau à haute pression renforci (2½) est inspecté, soufflé et connecté du compresseur à la foreuse en installant les dispositifs de retenues à chacune des connections. (Note: Les « stem nuts » sur les boyaux de 2½ po. dia. sont"},{"p":4,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":4,"t":"4 Mars 2002 Révision: Juin 2024 faits pour qu’ils ne puissent pas être inter changés entre la basse et haute pression pour éliminer autant que possible, tout accident potentiel.)"},{"p":4,"t":"Attention particulière requise Les raccords et boyaux doivent être inspectés minutieusement afin de s’assurer que les collets soient bien serrés, que les filets des raccords d’accouplement sont en bonne état et que les boyaux ne présentent aucune anomalie."},{"p":4,"t":"12. Le boyau à eau de 1 po. dia. est inspecté, soufflé et connecté au dispositif d’alimentation de la mine au système de refroidisseur d'eau du compresseur renforçateur et à la foreuse."},{"p":4,"t":"13. Tous les boyaux sont suspendus en-dessous du câble électrique pour éliminer tout contact avec des roches branlantes et/ou de l’équipement minier."},{"p":4,"t":"14. S’il n’est pas physiquement possible de suspendre le câble et les boyaux (ex. les dimensions du chantier) ils sont étendus de façon à éliminer tout contact possible ou l’écrasement."},{"p":4,"t":"Ils peuvent être soulevés du banc avec des bidons ou des trépieds en bois et marqués (peinturés ou identifiés avec une banderole) pour être plus visibles."},{"p":4,"t":"15. Les lignes d’eau et d’air sont pressurisées avec soins et inspectées pour des fuites."},{"p":4,"t":"16. La foreuse est ensuite positionnée au-dessus de la cible de forage (sur la ligne et avec le pendage désiré) comme précisé dans les plans et devis"},{"p":5,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":5,"t":"5 Mars 2002 Révision: Juin 2024 fournis en utilisant un laser magnétique et un laser digital clinomètre pour le contrôle de qualité."},{"p":5,"t":"17. Lors du déplacement du mât en rotation, une attention particulière doit être portée aux boyaux hydrauliques, ils pourraient se coincer. Si c’est le cas, revenir en arrière et bouger le mât pour ramollir les boyaux et les décoincer."},{"p":5,"t":"Si un effort est nécessaire pour décoincer les boyaux, s’assurer d’être en position stable."},{"p":5,"t":"18. Les employés de M.R.I. sont formés à affûter et refaçonner les forets au chantier de travail. Des affûteurs et des meules à disques sont utilisés pour ces tâches et tout l’équipement de protection individuel (EPI) pour ses activités sont requises."},{"p":5,"t":"19. Pendant le forage du trou, personne (employé ou autre) n’est autorisé à circuler en avant de la foreuse."},{"p":5,"t":"20. Pour installer ou enlever les tiges de forage, la boite de vitesse doit être relevée et arrêtée. La foreuse doit être à la position neutre (Point mort) avant que les tiges de forage soient manipulées."},{"p":5,"t":"21. Une fois le trou de pilote de 6 ½ po. de diamètre complété, il est nécessaire de l’aléser (agrandir) à 10 po. de diamètre de façon à accepter le guide de la V-30. La même méthode pour changer ou installer les tiges de forage s’applique. Pour les trous de production plus gros que 6½ po."},{"p":5,"t":"de diamètre, l’opérateur doit utiliser le chariot de transport ou la cloche et la chaine. S’assurer que le chariot est stable avant de déposer le marteau dessus. En dernier recours, le marteau pourrait être transporté manuellement avec l’aide d’un autre travailleur."},{"p":5,"t":"Changer les forêts et les tiges peut être fait seul dépendamment de la longueur des trous forés. Nous privilégions la présence d’un 2e travailleur pour le forage et l’arrachement des tiges pour les trous de 200 pieds et plus. S’il n’est pas possible d’avoir ce 2e travailleur, le foreur doit prévoir des pauses."},{"p":5,"t":"22. Lors du défoncement de trous, il est important de pousser, SANS ROTATION, 1 tige de plus que la longueur du défoncement ;"},{"p":5,"t":"Raccordement de la tête aux tiges"},{"p":5,"t":"Une de ces méthodes peut être utilisée pour installer la tête V-30 à la tige de forage en préparation de forer le trou de 30 po. de diamètre. Des moyens différents peuvent être utilisés dépendamment des équipements disponibles sur le site minier."},{"p":5,"t":"Pour cette étape, un moyen de communication tel que ; Radio ou système femco doit être disponible et fonctionnel au niveau supérieur et inférieur."},{"p":6,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":6,"t":"6 Mars 2002 Révision: Juin 2024 L’utilisation du raccord situé entre la V-30 et la tige est obligatoire. Celui-ci empêche le serrage et permet le désaccouplement de la tête facilement pour effectuer les entretiens et le changement de trépans."},{"p":6,"t":"Voici 2 suggestions : a. En utilisant une chaîne de grade 80 (7100 lbs) et une chargeuse navette, la tête est attachée et suspendue en position d’attache. Le guide est positionné en fonction d'accepter la tige de forage, qui dépasse du plafond du niveau inférieur du chantier."},{"p":6,"t":"La chargeuse doit être utilisée pour ajuster l'alignement dans le trou pilote. La boîte de vitesse est activée pour visser la tête à la tige de forage. L'unité au complet est alors tirée au plafond pour commencer l'alésage."},{"p":6,"t":"b. La procédure plus longue et moins utilisée est celle où on utilise la même chaîne de grade 80 avec des palans à chaîne pour positionner la tête."},{"p":6,"t":"Il faut être très vigilant et porter beaucoup d’attention avec cette procédure en fonction de l’équipement utilisé et de la proximité des employés de la tête."},{"p":6,"t":"Les palans à chaîne doivent être installés à des boulons à œil conformes ou à un anneau de qualité conforme qui est ancré avec des boulons scellés à la résine. Les employés de M.R.I. ne font pas ces installations car ce n’est pas de notre expertise de travail."},{"p":6,"t":"Une chargeuse navette ou un camion à flèche est utilisé pour avancer la tête le plus près possible du point d’installation."},{"p":6,"t":"22. Des affiches ou des barricades sont installées à l'entrée du chantier pour aviser toutes les personnes dans les environs des travaux qui sont en cours et qu'il y a une situation de trou ouvert au-dessus. Seulement les personnes autorisées sont permises dans la zone de travail."},{"p":6,"t":"23. Les changements des forêts et une inspection visuelle sont requis périodiquement. La tête de la V-30 doit être descendue et sortie du chantier selon les procédures en place."},{"p":7,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":7,"t":"7 Mars 2002 Révision: Juin 2024 24. La tête est inspectée pour toute réparation possible et ensuite les forets peuvent être changés à ce moment."},{"p":7,"t":"26. L'affûtage et le façonnement des forets peut être fait dans le chantier en utilisant l'équipement manuel et les équipements de protection individuels (EPI) pendant que l'alésage continue."},{"p":7,"t":"27. Dépendamment des plans et devis fournis, soit un pilier de couronne est laissé en place pour protéger les travailleurs ou la monterie est défoncée au niveau et une plaque d'acier est installée sur le trou et identifiée pour la protection de tous."},{"p":7,"t":"28. Une fois la monterie complétée, la tête est descendue au niveau inférieur, la tête est attachée dans le godet de la chargeuse navette ou à la flèche du camion de service et retirée du chantier. Les tiges de forage sont enlevées au niveau supérieur en les remontant."},{"p":7,"t":"29. Une fois la monterie de 30 po. complétée et l'équipement sorti du chantier, une barricade ou les affiches nécessaires sont installées pour que tous soient avisés qu'il y a une condition de trou ouvert. La compagnie est avisée de la situation et elle peut entreprendre les précautions de sécurité nécessaires."},{"p":7,"t":"30. M.R.I. possède des équipements adaptés pour extraire les matériaux qui sont brisés dans les trous (ex. tiges de forage) pour que le forage continue."},{"p":7,"t":"31. Procédure pour un bris de la tige de forage:"},{"p":7,"t":"a. Advenant un bris de la tige de forage, arrêter immédiatement l’opération de forage, fermer l’interrupteur électrique ainsi que l’alimentation en air comprimé. b."},{"p":7,"t":"Une barricade ou des panneaux adéquats doivent par la suite être installées à l’entrée du chantier de façon à empêcher tout accès au site de travail. c."},{"p":7,"t":"L’opérateur doit aviser sont contremaitre de la situation et aucun travail de forage est permis avant l’arrivé du contremaitre sur les lieux de travail. d."},{"p":7,"t":"L’opérateur, avec la collaboration du contremaitre, évaluera la situation et déterminera la méthode par laquelle la tige de forage sera retirée du trou et changée. e. La présence du contremaitre sur les lieux du travail est requise jusqu’à ce que la tâche de récupération de la tige soit complétée."},{"p":7,"t":"f. Lorsque la tige brisée à été retirée et remplacée, toutes les autres tiges de forage seront retirées du trou et vérifiées, et ce dans le but de s’assurer qu’il n’y a pas une autre tige endommagée."},{"p":8,"t":"ALÉSAGE CONVENTIONNEL, V-30"},{"p":8,"t":"8 Mars 2002 Révision: Juin 2024 g. Le contremaitre s’assurera que l’équipement de forage est dans la condition requise pour reprendre les activités de forage et donnera son approbation pour reprendre les activités. h."},{"p":8,"t":"Le contremaitre s’assurera que la tige de forage brisée a été étiquetée et retournée au fournisseur pour déterminer la raison du bris. i."},{"p":8,"t":"Le contremaitre devra compléter le rapport d’incident qui donnera les circonstances et détails du bris, l’opération de récupération de la tige et les actions correctives nécessaires suite à l’incident et à l’analyse de la tige."},{"p":8,"t":"Modifications effectuées Par Date Point #23 : enlevé la cloison de bois pour protéger les travailleurs lors des maintenances et changement de forêts et ajouté sortir la V-30 pour faire ces travaux Point #25 : retiré complètement. Il disait d’enlever la cloison de bois S. Tremblay S."},{"p":8,"t":"Desrosiers 12-02-2021 Ajout au point #17 de la possibilité de coincement des boyaux hydrauliques et des mesures à prendre si ça survient. S. Tremblay 12-01-2023 Ajout de la mise en garde sur les inspections et les boyaux haute-température 7 avril 2023 S."},{"p":8,"t":"Tremblay Ajout de la distance de 3 mètres entre le ruban et les premières pièces de matériel dans le chantier. Ajout fait au point #7 et sur le ‘’STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS’’ à la suite de l’événement d’Amaruk 19 décembre 2023 S. Tremblay S."},{"p":8,"t":"Desrosiers Ajout #22 de pousser 1 rod de plus lors du défoncement des trous 21 juin 2024 S. Tremblay JF Gagnon"},{"p":8,"t":"_____________________________ Christian St-Amour Directeur des opérations"},{"p":9,"t":"STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS (Noter que la distance entre la foreuse et le surcompresseur doit être de 7 mètres) (Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…)"},{"p":9,"t":"b a r r i c a d e 3 m (10’)"}],"pro-op-ith-007":[{"p":1,"t":"Mars 2002 Révision Octobre 2024"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-007"},{"p":1,"t":"ALÉSAGE ASCENDANT SANS ACCÈS AVEC LA TÊTE V-30"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour effectuer l’alésage ascendant avec la tête de forage V-30. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure et de respecter les consignes qui proviennent du département d’ingénierie."},{"p":1,"t":"MESURES DE SÉCURITÉ ET CONSIGNES IMPORTANTES"},{"p":1,"t":"1. Les employés de M.R.I. peuvent déplacer l’équipement de forage à la place de travail en utilisant l’équipement de la compagnie en respectant toute réglementation et directives de la compagnie."},{"p":1,"t":"2. Une inspection visuelle doit être faite de l’équipement de forage sur le lieu de travail ainsi que la ventilation, l’alimentation d’énergie et la distribution de l’eau et de l’air."},{"p":1,"t":"3. Le câble électrique est déchargé, inspecté et branché à la distribution d’énergie (ground fault box). Un électricien de la mine est requis si la rotation du moteur est inversée;"},{"p":1,"t":"4. La vérification de tous les leviers de commande est requise avant de déplacer l’unité de forage. Ils doivent être au neutre avant que l’unité soit mise sous tension."},{"p":2,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":2,"t":"5. Une inspection visuelle de l’unité de forage est requise pour vérifier les huiles, les jauges, les fuites, etc. avant de la déplacer."},{"p":2,"t":"Il est primordial de faire une inspection rigoureuse de nos équipements dès qu’on doit les opérer. Dans le cas des CUBEX et des surcompresseurs, une attention particulière doit être portée sur les boyaux tressés haute-température (800 degrés F) des compresseurs."},{"p":2,"t":"Pour des raisons de sécurité, seul le type de boyau tel que présenté ci- dessous doit être utilisé."},{"p":2,"t":"6. Avant de déplacer l’unité de forage à la première ligne de forage, en respectant les plans et devis, il faut laver la zone de travail, vérifier l’écaillage et faire une inspection pour des explosifs restant dans le chantier ou non détonnés."},{"p":2,"t":"7. En tout temps, les travaux peuvent être interrompus pour écailler, ou purger puis sécuriser la cage de protection."},{"p":3,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":3,"t":"8. Prendre les précautions nécessaires pour ne pas endommager le câble électrique qui suit la foreuse et aussi nous devons vérifier s’il n’y a pas de fuites ou anomalies de la foreuse en mouvement. Si l’extension doit être manipulée alors qu’elle est sous tension, il faut utiliser le crochet de plastique."},{"p":3,"t":"9. Des barricades ou des affiches sont installées pour aviser tous les travailleurs des opérations en cours (trous ouverts, forage, etc.)."},{"p":3,"t":"Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…) Voir STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS"},{"p":3,"t":"10. Rendu au point de forage il faut mettre la foreuse hors tension avec le E-STOP et accrocher le câble électrique au mur au niveau de la poitrine (4 à 5 pieds du plancher) pour éliminer tout contact avec des roches branlantes ou des véhicules motorisés."},{"p":3,"t":"Aussi, en suspendant le câble électrique, une inspection visuelle de l’état du câble sera faite."},{"p":3,"t":"11. La connexion du boyau à air de basse pression (2½ po. dia.) du dispositif d’alimentation de la mine au compresseur renforçateur de la foreuse est la prochaine priorité. Le boyau d’alimentation est relié au dispositif de purge et il est soufflé."},{"p":3,"t":"Ensuite retirer le boyau et le relier à l’entrée d’air de la foreuse. Les dispositifs de retenues (whip check) sont installés à chaque joint. À ce point, une inspection des dispositifs de retenu est importante. Il faut vérifier l’état du câble métallique et le bon fonctionnement des mécanismes de serrage."},{"p":3,"t":"12. Le boyau à haute pression renforci (2½) est inspecté, soufflé et connecté du compresseur à la foreuse en installant les dispositifs de retenues à chacune des connections. (Note: Les « stem nuts » sur les boyaux de 2½ po. dia."},{"p":3,"t":"sont faits pour qu’ils ne puissent pas être inter changés entre la basse et haute pression pour éliminer autant que possible, tout accident potentiel.)"},{"p":4,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":4,"t":"Attention particulière requise"},{"p":4,"t":"13. Les raccords et boyaux doivent être inspectés minutieusement afin de s’assurer que les collets soient bien serrés, que les filets des raccords d’accouplement sont en bonne état et que les boyaux ne présentent aucune anomalie."},{"p":4,"t":"14. Le boyau à eau de 1 po. dia. est inspecté, soufflé et connecté au dispositif d’alimentation de la mine au système de refroidisseur d'eau du surcompresseur et à la foreuse."},{"p":4,"t":"15. Tous les boyaux sont suspendus en-dessous du câble électrique pour éliminer tout contact avec des roches branlantes et/ou de l’équipement minier."},{"p":4,"t":"16. S’il n’est pas physiquement possible de suspendre le câble et les boyaux (ex. les dimensions du chantier) ils sont étendus de façon à éliminer tout contact possible ou l’écrasement."},{"p":4,"t":"Ils peuvent être soulevés du sol avec des bidons ou des trépieds en bois et marqués (peinturés ou identifiés avec une banderole) pour être plus visibles."},{"p":4,"t":"17. Les lignes d’eau et d’air sont pressurisées avec soin et inspectées pour des fuites."},{"p":4,"t":"18. Lors du déplacement du mât en rotation, une attention particulière doit être portée aux boyaux hydrauliques, ils pourraient se coincer. Si c’est le cas, revenir en arrière et bouger le mât pour ramollir les boyaux et les décoincer."},{"p":4,"t":"Si un effort est nécessaire pour décoincer les boyaux, s’assurer d’être en position stable."},{"p":5,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":5,"t":"19. Pour les trous de production de plus de 6½ pouces de diamètre, le marteau doit être transporté à l’aide du chariot de transport. S’il n’est pas disponible, l’opérateur doit demander l’aide d’un 2e travailleur. Assurez-vous que le chariot de transport est stable avant de poser le marteau dessus."},{"p":5,"t":"Les changements de bits et la manipulation des tiges peuvent être effectués par l'opérateur uniquement, en fonction de la longueur des trous à percer."},{"p":5,"t":"Une longueur de trou de 200 pieds et plus nécessitera l'assistance d'un aide-foreur pour la manipulation des tiges, en raison de l'effort physique requis. Si ce n’est pas possible, le foreur doit prévoir des pauses;"},{"p":5,"t":"20. L’installation d’une cage de protection avec grillage à mailles soudées est requise pour canaliser les débris de forage loin de l’opérateur et l’équipement. (Voir modèles et photos en annexe);"},{"p":5,"t":"21. Pendant le forage du trou, personne (employé ou autre) n’est autorisé à circuler à moins de 5 mètres du mât de la foreuse;"},{"p":5,"t":"22. Pour installer ou enlever les tiges de forage, le gear box doit être abaissé et arrêté. La foreuse doit être à la position neutre (point mort) avant que les tiges de forage soient manipulées;"},{"p":5,"t":"23. Une fois le trou pilote de 6 ½ po. de diamètre complété, il est nécessaire de l’aléser (agrandir) à 10 ½ po. de diamètre de façon à accepter le guide de la V-30. La même méthode pour changer ou installer les tiges de forage s’applique;"},{"p":5,"t":"24. Les accès séparant les contrôles, le mât de la foreuse et le support à tige de forage doivent être libre en tout temps (pas de boyaux, pas de casing qui dépasse, pas de roche)"},{"p":5,"t":"25. Aussitôt que la tête de la V-30 est complètement entrée dans le roc (approx. 6 pieds) et qu’il est possible de fermer les tables, la foreuse doit être arrêté et la cage de protection doit être installée;"},{"p":5,"t":"26. Ces panneaux sont fabriqués avec des feuilles de grillage et recouvertes de toiles au besoin, ils seront suspendus au toit avec l’aide de chaînes ou cordes ou manilles et installées de façon à permettre l‘ouverture et la fermeture des panneaux;"},{"p":5,"t":"1. Avant de mobiliser la foreuse et tout l’équipement nécessaire pour le forage, la hauteur entre le plancher et le toit doit être entre 12 pieds et maximum 14 pieds selon les degrés de forage. Il est important de noter que la mesure entre la slip plate et le bout des taillants est de 7 pieds et 6 pouces."},{"p":6,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":6,"t":"2. Lorsque l’espace entre le plancher et le toit de l’endroit de travail excède plus de 4.3m (14pi), le plancher de l’endroit de travail doit être relevé avec de la roche abattue :"},{"p":6,"t":"3. Pour le forage de la V-30, pour éviter les bris d’actuateur, on doit avoir la meilleure répartition des charges de chaque côté du point de pivot. Il faut :"},{"p":6,"t":"a. Avoir une distance maximale de 2 à 4 pieds entre les tables du mat et le collet de trou b. Que la hauteur du toit permette aux 2 taillants d’être dans la monterie lorsque la V-30 est dans la slip plate c. Rétracter le ‘’feed extension du mât’’ le plus possible"},{"p":6,"t":"4. En arrivant au chantier avec les équipements, les positionner selon les positions dans le standard en annexe;"},{"p":6,"t":"5. S’assurer de ne pas positionner de matériel ou d’équipements au fond du chantier et qui empêcherait leur accessibilité;"},{"p":6,"t":"6. Toujours prévoir une distance de 7 mètres entre la foreuse et le compresseur;"},{"p":6,"t":"7. Aligner la foreuse sous la cible de forage (en ligne et à l'angle désirés) selon les plans et devis fournis par l’ingénierie, à l’aide d'un inclinomètre (degree hole) pour le contrôle de la qualité;"},{"p":6,"t":"8. La commande de forage doit être positionnée à 5 mètres du point de forage pour être à l'abri de la projection de roche;"},{"p":6,"t":"9. Forer le trou pilote de 6 ½ ‘’ et ensuite de 10’’"},{"p":6,"t":"10. Quand le 10’’ est terminé et que les tiges sont toutes retirées du trou, procéder à l’installation de la V-30"},{"p":6,"t":"INSTALLATION DE LA V-30 SUR LE MÂT DE LA FOREUSE"},{"p":6,"t":"Ne jamais se tenir dans l’axe de déplacement possible de la tête si elle se décroche. S’assurer que les contrôles sont en position neutre."},{"p":6,"t":"1. Positionner la foreuse dans l’axe de la V-30 à une distance d’environ 15 pieds. La tête doit être orientée de la façon suivante; stabilisateurs vers la foreuse et le centralisateur (nez) pointant vers l’avant;"},{"p":6,"t":"2. Incliner le mât à un angle d’environ 60 degrés vers l’arrière en gardant la base du mât au sol. Si ce n’est pas possible d’appuyer la base au sol pour approcher la tête, allonger le stinger pour créer un appui et stabiliser le mât et la foreuse;"},{"p":7,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":7,"t":"3. Installer l’adaptateur mâle dans le gear box ainsi que l’adaptateur femelle sur le drive shaft de la V-30;"},{"p":7,"t":"4. Installer la chaîne (grade 80, 12 pieds) entre le gear box de la foreuse et le drive shaft de la V-30;"},{"p":7,"t":"5. Utiliser le feed cylindre pour hisser la V-30 vers la table jusqu'à ce que le drive shaft soit entré suffisamment dans la table pour accoupler le gear box au drive shaft de la V-30;"},{"p":7,"t":"6. Fermer les centralisateurs sur le drive shaft de la V-30;"},{"p":7,"t":"7. Fermer la foreuse et enlever les adaptateurs;"},{"p":7,"t":"8. Positionner le mât afin d’aligner le drive shaft et le gear box;"},{"p":7,"t":"9. Approcher le gear box sur le drive shaft et amorcer la rotation pour les visser ensemble;"},{"p":7,"t":"10. Engager la slip plate dans les coches de la tige pour serrer le montage;"},{"p":7,"t":"11. Retirer la pine et ouvrir les tables;"},{"p":7,"t":"12. Hisser complètement la V-30 sur le mât;"},{"p":7,"t":"13. Refermer les tables de chaque côté de la V-30 pour la stabiliser;"},{"p":7,"t":"14. Réaligner le mât en position de forage initial;"},{"p":7,"t":"15. Si les monteries sont planifiées pour aller au-delà de 40 pieds, des centralisateurs doivent être installés aux 40 pieds pour stabiliser les tiges."},{"p":7,"t":"Déblais de forage."},{"p":7,"t":"- L’alésage du trou à 30’’ produit des déblais (cuttings) Si ces débris venaient à interférer avec les opérations de forage, arrêter le forage et souffler ces déblais sur le côté à l’aide d’un boyau à l’air sans s’exposer directement sous le trou de V-30."},{"p":7,"t":"Il faut porter un masque lors du soufflage des déblais de forage."},{"p":7,"t":"- Il est possible que des roches se retrouvent sur les tables avant qu’elles puissent être fermées."},{"p":7,"t":"o Si elles ne nuisent pas, elles peuvent rester sur les tables et le forage peut se poursuivre jusqu’à ce que les tables puissent être fermées; o Si une roche doit absolument être enlevée, l’utilisation de l’eau sera préconisée;"},{"p":8,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":8,"t":"o Si la roche ne s’enlève pas avec de l’eau, ▪ Le foreur devra retirer complètement la V-30 du trou, ▪ Éloigner la foreuse du trou pour ne pas s’exposer, ▪ Déplacer le mât sur le côté, ▪ Enlever la roche ▪ Replacer la foreuse et remettre la V-30 dans le trou ▪ Poursuivre le forage"},{"p":8,"t":"- Pendant le forage, l’accumulation de résidus de forage ou de roche sur les déflecteurs et dans les grillages de la cage de protection doit être nettoyée avant de s’exposer sous les déflecteurs."},{"p":8,"t":"- Si l’affutage des bits est nécessaire, appliquer la procédure PRO-SEC-010 Affutage de trépan"},{"p":8,"t":"- Une fois la monterie de 30 po. terminée et les équipements sortis du chantier, une barricade ou des affiches sont installées pour que toutes les personnes soient avisées qu'il y a une condition de trou ouvert au toit dans le secteur."},{"p":8,"t":"La compagnie est informée de la situation et elle peut entreprendre les précautions nécessaires de sécurité pour sécuriser ce trou."},{"p":8,"t":"PROCÉDURE POUR L’ENTRETIEN DE LA V-30 OU CHANGEMENT DE TRÉPANS"},{"p":8,"t":"1. Descendre la V-30 jusqu’à ce qu’elle soit vissée sur le gear box ;"},{"p":8,"t":"2. Coucher le mât sur la foreuse, en position de transport ;"},{"p":8,"t":"3. Rabattre les grillages de la cage de protection pour qu’ils referment le trou ;"},{"p":8,"t":"4. Bien nettoyer les tractions et les amas de résidus de forage (cutting) à l’intérieur et autour des tractions avant de déplacer la foreuse ;"},{"p":8,"t":"5. La foreuse doit être déplacée pour que lors de l’entretien, le travailleur soit :"},{"p":8,"t":"a. À 5 mètres de la ligne de forage de la monterie et, b. Hors de la ligne de tir d’objets ou roche pouvant tomber de la monterie ;"},{"p":8,"t":"6. Appuyer le nez de la V-30 au sol en tout temps pour effectuer l’entretien"},{"p":8,"t":"7. Lorsque l’entretien est terminé : a. Coucher le mât sur la foreuse, en position transport ; b. Ramener la foreuse à la ligne de forage ; c. Remettre la V-30 dans la monterie ; d. Repositionner la cage de protection."},{"p":9,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":9,"t":"PROCÉDURE LORS D’UN BRIS DE LA TIGE DE FORAGE :"},{"p":9,"t":"1- Advenant un bris de la tige de forage, arrêter immédiatement l’opération de forage, fermer l’interrupteur électrique ainsi que l’alimentation en air comprimé."},{"p":9,"t":"2- Une barricade ou des panneaux adéquats doivent par la suite être installées à l’entrée du chantier de façon à empêcher tout accès au site de travail."},{"p":9,"t":"3- L’opérateur doit aviser son superviseur de la situation et aucun travail de forage est permis avant l’arrivée du superviseur sur les lieux de travail. 4- L’opérateur, avec la collaboration du superviseur, évaluera la situation et déterminera la méthode par laquelle la tige de forage sera retirée du trou et changée."},{"p":9,"t":"5- La présence du superviseur sur les lieux du travail est requise jusqu’à ce que la tâche de récupération de la tige soit complétée."},{"p":9,"t":"6- Toutes activités d’opération de la foreuse qui seront requises pendant le travail de récupération de la tige doivent être accomplies en utilisant la manette de contrôle à distance. La manette doit être placée dans un endroit sécuritaire :"},{"p":9,"t":"i. À 5 mètres de la ligne de forage de la monterie et, ii. Hors de la ligne de tir d’objets ou roche pouvant tomber de la monterie ;"},{"p":9,"t":"UNE ANALYSE DE RISQUE DOIT ÊTRE EFFECTUÉE À CE POINT"},{"p":9,"t":"7- Lorsque la tige brisée à été retirée et remplacée, toutes les autres tiges de forage seront retirées du trou et vérifiées, et ce dans le but de s’assurer qu’il n’y a pas une autre tige endommagée."},{"p":9,"t":"8- Le contremaitre s’assurera que l’équipement de forage est dans la condition requise pour reprendre les activités de forage et donnera son approbation pour reprendre les activités."},{"p":9,"t":"9- Le contremaitre s’assurera que la tige de forage brisée a été étiquetée et retournée au fournisseur pour déterminer la raison du bris."},{"p":9,"t":"10- Le contremaitre devra compléter le rapport d’incident qui donnera les circonstances et détails du bris, l’opération de récupération de la tige et les actions correctives nécessaires suite à l’incident et à l’analyse de la tige."},{"p":9,"t":"Ajouts ou modifications Date Par Point 2- Ajouter : S’assurer que les contrôles sont en position neutre 12-02-2021 S. Tremblay Replacé les numéros de séquences à partir du point 23. 16-06-2022 S. Tremblay Au point #25 (anciennement #28) ajout du nettoyage des 16-06-2022 S. Tremblay"},{"p":10,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":10,"t":"déflecteurs et grillages avant de s’exposer Ajout # 28 affûtages de bits 16-06-2022 S. Tremblay Assimiler version française et anglaise pour qu’elles soient pareilles 16-06-2022 S. Tremblay Ajouts de photos comme exemple de cage de grillage 16-06-2022 S."},{"p":10,"t":"Tremblay Ajout au point #17 de la possibilité de coincement des boyaux hydrauliques et des mesures à prendre si ça survient. 12-02-2023 S. Tremblay 26-01-2023 S. Tremblay S. Desrosiers JF Gagnon Ajout de la mise en garde sur les inspections et les boyaux haute- température 7 avril 2023 S."},{"p":10,"t":"Tremblay Ajout dans la partie déblais de forage des mesures à prendre si des roches doivent être retirées sur la foreuse 11 octobre 2023 S. Tremblay D. Baribeault Ajout de la distance de 3 mètres entre le ruban et les premières pièces de matériel dans le chantier."},{"p":10,"t":"Ajout fait au point #7 et sur le ‘’STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS’’ à la suite de l’événement d’Amaruk 19 décembre 2023 S. Tremblay S. Desrosiers Réaménager pour que les procédures en français et en anglais soient pareilles 23 avril 2024 S. Tremblay Ajout du point 1-b."},{"p":10,"t":"sur la distance maximale de 2 à 4 pieds entre la table et le collet du trou. Suite à un bris d’actuateur. 31 octobre 2024 S. Tremblay D, Baribeault JF Gagnon"},{"p":10,"t":"_______________________________ Christian St-Amour"},{"p":10,"t":"Directeur des Opérations"},{"p":11,"t":"Mars 2002 Révision Octobre 2024"},{"p":11,"t":"STANDARD DE POSITIONNEMENT DES ÉQUIPEMENTS (Noter que la distance entre la foreuse et le surcompresseur doit être de 7 mètres) (Une distance d’au moins 3 mètres (10 pieds) doit être laissée entre la barricade à l’entrée du chantier et les premières pièces de matériel (toolbox, huile etc…)"},{"p":11,"t":"b a r r i c a d e 3 m (10’)"},{"p":12,"t":"Mars 2002 Révision Octobre 2024"},{"p":12,"t":"CAGE DE PROTECTION #1"},{"p":13,"t":"ALÉSAGE ASCENDANT SANS ACCES AVEC LA TÊTE V-30 Mars 2002 Révision Octobre 2024"},{"p":13,"t":"CAGE DE PROTECTION #2"}],"pro-op-ith-008":[{"p":1,"t":"Date : 31 Octobre 2006 ½"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-008"},{"p":1,"t":"PROCÉDURES À SUIVRE LORSQU’UN TAILLANT DE LA V-30 SE BRISE DANS UN TROU DESCENDANT."},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires pour effectuer le défonçage de trous sous terre. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de cette personne."},{"p":1,"t":"RESPONSABILITÉS Le travailleur responsable du forage doit s’assurer d’appliquer cette procédure et de respecter les consignes qui proviennent du département d’ingénierie."},{"p":1,"t":"En cours de forage de V-30, lorsque l’un des taillants de la V-30 se brise ou que des outils sont échappés, il est strictement défendu à quiconque, et ce en tout temps, de descendre au fond de la monterie pour dégager ou récupérer les pièces métalliques, les outils, les taillants ou tout autre équipement ;"},{"p":1,"t":"1- L’opérateur doit enlever les tiges de forage pour sortir la V-30 de la monterie ;"},{"p":2,"t":"PROCÉDURES À SUIVRE LORSQU’UN TAILLANT DE LA V-30 SE BRISE DANS UN TROU DESCENDANT."},{"p":2,"t":"Date : 31 Octobre 2006 2/2"},{"p":2,"t":"2- Avant d’enlever le couvercle, le travailleur doit porter un harnais et s’attacher à un ancrage ou à une ligne de vie ;"},{"p":2,"t":"3- Lorsque la V-30 est sortie de la monterie, on doit remettre le couvercle ;"},{"p":2,"t":"4- Installer le racloir de monterie (raise scraper), conçue à cet effet ;"},{"p":2,"t":"5- Enlever le couvercle ;"},{"p":2,"t":"6- Descendre le racloir au bord de la monterie ;"},{"p":2,"t":"7- Remettre le couvercle ;"},{"p":2,"t":"8- Descendre le racloir jusqu’au fond de la monterie ;"},{"p":2,"t":"9- Le faire tourner jusqu’à ce que le taillant brisé tombe dans le trou pilote ;"},{"p":2,"t":"10- Retirer le racloir de la monterie (raise scraper), couvrir la monterie sécuritairement ;"},{"p":2,"t":"11- Si l’accès au niveau inférieur est possible, il faut récupérer le taillant ;"},{"p":2,"t":"12- Si non, le superviseur de la mine doit être averti qu’un taillant est présent à cet endroit ;"},{"p":2,"t":"13- Le forage avec la V-30 peut ensuite être poursuivi."},{"p":2,"t":"IMPORTANT : Le port du harnais est obligatoire et le travailleur doit être attaché à un ancrage ou une ligne de vie durant les travaux de manipulation du couvercle et quand le couvercle est retiré de la monterie."},{"p":2,"t":"________________________ Christian St-Amour Directeur des opérations"}],"pro-op-ith-012":[{"p":1,"t":"Septembre 2019"},{"p":1,"t":"Novembre 2022"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-012"},{"p":1,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE ITH OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour le forage à distance avec une foreuse ITH APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL (MRI)."},{"p":1,"t":"Le forage à distance doit être décidé par l’ingénierie du client en fonction des dangers pouvant être présents lors du forage. Le foreur ou la supervision de MRI sont invités à proposer le forage à distance s’il le considère davantage sécuritaire que le forage conventionnel."},{"p":1,"t":"L’article 440 du Règlement sur la Santé et la Sécurité du travail dans les Mines prévoit :"},{"p":1,"t":"440. Malgré l’article 439, des trous peuvent être forés à des distances moindres que celles prévues à cet article pourvu que le forage soit exécuté au moyen d’un dispositif de commande à distance sous surveillance et que la zone de forage soit évacuée."},{"p":1,"t":"Cette procédure vient encadrer les travaux de forage à distance."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes."},{"p":1,"t":"RESPONSABILITÉS LE FOREUR Le foreur doit appliquer la procédure de forage à distance selon les exigences proposées par le client. Il doit respecter toutes les procédures entourant le forage avec une CUBEX ou tout autre équipement. Cette procédure est le minimum demandé par Machines Roger International."},{"p":2,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE ITH"},{"p":2,"t":"Septembre 2019"},{"p":2,"t":"Novembre 2022 LE SUPERVISEUR MRI"},{"p":2,"t":"Le superviseur MRI doit s’assurer de l’application de cette procédure ainsi que du respect du plan et devis de l’ingénierie du client. Il doit aussi participer à toute analyse de risque demandée par nous ou par le client."},{"p":2,"t":"INGÉNIERIE DU CLIENT"},{"p":2,"t":"L’Ingénierie responsable du forage doit émettre des plans et devis de forage à distance. Ces plans et devis doivent prendre en considération les risques associés à ce type de forage."},{"p":2,"t":"L’ingénierie du client doit être l’initiateur, si une analyse de risque est nécessaire, où minimalement participer à cette analyse de risque."},{"p":2,"t":"OPÉRATIONS SOUS-TERRE"},{"p":2,"t":"Le département des opérations sous-terre doit exiger l’application de cette procédure. Il doit aussi participer à la mise en place des travaux en collaboration avec MRI et l’ingénierie, en plus de participer à toute analyse de risque"},{"p":2,"t":"PROCÉDURE 1. Installer la foreuse au-dessus du trou à forer 2. Installer le système à distance entre le foreur et le trou à forer à un minimum de 50' (15 mètres) : a. Le foreur et l’aide-foreur doivent être vers la sortie en s’assurant que rien ne bloque l’accès b."},{"p":2,"t":"Ne pas être dans la ligne de sautage, ou c. Certains clients pourraient aussi exiger d’être derrière une protection comme : i. Une galerie perpendiculaire à celle où la foreuse est installée ii. Un équipement iii. Un amas de roche 3."},{"p":2,"t":"Tous les accès aux lieux forage (foreur et la foreuse) doivent être barricadés par une clôture (selon exigences/procédures du client) ou gardés par un travailleur 4. Une signalisation indiquant le type de travaux (ex."},{"p":2,"t":": ACCÈS INTERDIT, FORAGE EN COURS, FORAGE À DISTANCE.) doit être appliquée sur la clôture 5. Cette procédure doit être mise dans un sac étanche sur les clôtures de tous les accès et signée par le foreur qui aura visité ces endroits avant le début du forage, au début de chaque quart de travail. 6."},{"p":2,"t":"Si une visite des lieux de forage est nécessaire, l'opérateur doit être contacté par radio, ou si un contact visuel est possible, le foreur se déplacera pour aller rejoindre la ou les personnes voulant visiter les lieux. 7. Le foreur et l’aide-foreur resteront en tout temps dans la zone sécuritaire pendant le forage."},{"p":3,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE ITH"},{"p":3,"t":"Septembre 2019"},{"p":3,"t":"Novembre 2022 8. Lors du déblocage le foreur doit être attentif au matériel qui sort du trou et s’il constate qu’il y a présence d’explosif, l’opération avec la foreuse doit être arrêter et le superviseur doit en être aviser pour la suite des travaux. 9."},{"p":3,"t":"Lors du déblocage de trou dynamité avec amex (ANFO), on doit mettre de l’eau dans les tiges de forage pour diminuer le risque d’explosion."},{"p":3,"t":"Modifications effectuées Par Date Ajouter les raisons possibles pour le forage à distance dans l’application S. Tremblay"},{"p":3,"t":"18-11-2022 Ajout des points 8 et 9 S. Tremblay 18-11-2022"},{"p":3,"t":"____________________________ Christian St-Amour"},{"p":3,"t":"Directeur des opérations"},{"p":4,"t":"PROCÉDURE DE FORAGE À DISTANCE AVEC FOREUSE ITH"},{"p":4,"t":"Septembre 2019"},{"p":4,"t":"Novembre 2022 FEUILLE DE SIGNATURES DES BARRICADES LORS DU FORAGE À DISTANCE"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"},{"p":4,"t":"Signatures du foreur : Nom en lettres moulées_______________________ Signature :_______________________"},{"p":4,"t":"Date : _____________________ Nuit Jour Heure : ________ : _________"}],"pro-op-ith-014":[{"p":1,"t":"Date : 20 août 2020"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-014"},{"p":1,"t":"PROCÉDURE D’INSTALLATION DE TUBAGE (CASING) AU COLLET DES TROUS OBJECTIF L’objectif de cette procédure est de définir des méthodes sécuritaires pour l’installation de tubage (casing) ABS au collet des trous APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION Le personnel ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès d’une de ces personnes. RESPONSABILITÉS Les travailleurs sont responsables d’appliquer cette procédure."},{"p":1,"t":"Le superviseur doit s’assure que la procédure est appliquée"},{"p":1,"t":"L’installation de tubage au collet des trous est fréquente pour protéger les collets des trous contre la chute de roches qui pourraient bloquer le trou et nuire au forage ou au chargement d’explosifs."},{"p":1,"t":"La séquence de l’opération doit être suivie rigoureusement pour une installation de qualité et pour éviter tout accident."},{"p":1,"t":"1- Respecter la procédure de forage PRO-OP-ITH-004 (Procédure de forage production de 3,375’’ à 6.5’’) 2- Lorsque la foreuse est bien alignée selon les plans de forage, suivre le tableau suivant :"},{"p":2,"t":"PROCÉDURE D’INSTALLATION DE TUBAGE (CASING) AU COLLET DES TROUS"},{"p":2,"t":"Date : 20 août 2020"},{"p":2,"t":"Dimension du casing Dimension du 1er forage Longueur du 1er forage Dimension du 2e forage Longueur du 2e forage 4 pouces 3 pouces 7/8 Selon les besoins 4 pouces 1 pied dans le roc solide 6 pouces 4 pouces 1/2 Selon les besoins 6 pouces 1 pied dans le roc solide 10 pouces 6 pouces 1/2 Selon les besoin"},{"p":2,"t":"s 10 pouces 1 pied dans le roc solide"},{"p":2,"t":"3- Pour toutes les dimensions et toutes les longueurs de forage, la séquence suivante doit être suivie : a. Faire le 1er forage de de la longueur désirée dépendant de la solidité du roc au plancher; b."},{"p":2,"t":"Quand il est temps de changer de bit pour le 2ième forage, faire les manœuvres de changement et remonter la bit au-delà des tables; c. Fermer la slip-plate ou les jaws;"},{"p":2,"t":"IL EST INTERDIT À QUI QUE CE SOIT DE POSITIONNER TOUTE PARTIES DE SON CORPS SOUS LES TABLES SI LE MARTEAU N’EST PAS MONTÉ AU-DELÀ DES TABLES ET QUE LA SLIP PLATE N’EST PAS FERMÉE. Une distance minimum de 1.5 mètre entre le mât et la console doit obligatoirement être respectée."},{"p":2,"t":"Quand une pièce est en mouvement, aucun travailleur ne peut se placer entre la console et le mât, ni à moins de 1,5 mètre du mât de tous les côtés."},{"p":2,"t":"d. Faire le 2ième forage selon les conditions de terrain; e. Enlever la 2ième tige; f. Visser le marteau au saver sub au complet sans le serrer avec force; g. S’il y a un besoin de nettoyage du collet du trou avec les mains, monter le marteau au-delà des tables; h."},{"p":2,"t":"Fermer la slip-plate ou les jaws; i. Appuyer la bit sur la slip-plate ou les jaws; j. Fermer l’interrupteur de la foreuse; k. Procéder au nettoyage;"},{"p":2,"t":"IL EST INTERDIT À QUI QUE CE SOIT DE POSITIONNER TOUTE PARTIES DE SON CORPS SOUS LES TABLES SI LE MARTEAU N’EST PAS MONTÉ AU-DELÀ DES TABLES ET QUE LA SLIP PLATE N’EST PAS FERMÉE. Une distance minimum de 1.5 mètre entre le mât et la console doit obligatoirement être respectée."},{"p":2,"t":"Quand une pièce est en mouvement, aucun travailleur ne peut se placer entre la console et le mât, ni à moins de 1,5 mètre du mât de tous les côtés."},{"p":3,"t":"PROCÉDURE D’INSTALLATION DE TUBAGE (CASING) AU COLLET DES TROUS"},{"p":3,"t":"Date : 20 août 2020"},{"p":3,"t":"l. Remonter la tête et le marteau au maximum m. Ouvrir la slip-plate et les jaws; n. Insérer le tubage de la longueur requise selon les conditions du plancher en le passant par le trou des tables; o. Utiliser la bit et le marteau pour pousser le tubage si nécessaire; p."},{"p":3,"t":"Quand il est temps de changer de bit pour revenir au forage de production, faire les manœuvres de changement et remonter la bit au- delà des tables;"},{"p":3,"t":"Les tubages peuvent devenir des embûches pour les travailleurs s’ils sont laissés trop longs hors du plancher du chantier. La longueur de dépassement peut changer pendant le forage à cause de l’accumulation de boue de forage. Il faut que le trajet effectué par les travailleurs soit exempt de ces tubages qui dépassent."},{"p":3,"t":"_________________________________ Christian St-Amour Directeur des opérations"}],"pro-op-ith-016":[{"p":1,"t":"Date : Novembre 2021 1"},{"p":1,"t":"PROCÉDURE DE TRAVAIL PRO-OP-ITH-016"},{"p":1,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES OBJET L’objectif de cette procédure est de définir la séquence des opérations pour manipuler les marteaux de forage."},{"p":1,"t":"Ceci inclus la manipulation, l’installation du marteau, l’ajout ou l’enlèvement des bits et l’ajout du ‘’DRIVER SUB’’. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"INTERPRÉTATION La personne ayant l’autorité pour l’interprétation de ce document est le directeur des opérations. Toute demande de modification, révision ou de mise à jour doit être faite auprès de cette personne."},{"p":1,"t":"RESPONSABILITÉS Le foreur a la responsabilité de s’assurer d’une bonne communication avec l’aide-foreur. Ils doivent respecter cette procédure. Le superviseur doit faire respecter la procédure"},{"p":1,"t":"MISE EN CONTEXTE"},{"p":1,"t":"Les risques associés à la manipulation des marteaux de longs-trous sont reliés au TMS (Troubles musculosquelettiques) ainsi qu’à des blessures causées par la chute des marteaux."},{"p":1,"t":"À cause du poids de ces marteaux, les mauvaises méthodes de travail peuvent provoquer des accidents avec des conséquences graves."},{"p":1,"t":"Pour contrôler ces risques, un outil de transport existe et les séquences de travail doivent être respectées pour éviter l’exposition des travailleurs à une chute d’un marteau, ou au développement de TMS."},{"p":1,"t":"Le poids des marteaux selon spécifications des fournisseurs (Sources: Sandvik et Epiroc): Marteau 3’’ 60 lbs Marteau 4’’ 89 lbs Marteau 6 ‘’ 211 lbs"},{"p":2,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 2"},{"p":2,"t":"LES MARTEAUX DE 3’’ ET 4’’ DOIVENT ÊTRE INSTALLÉS SUR LE GEAR BOX MANUELLEMENT DE LA MÊME MANIÈRE QUE LES TIGES DE FORAGE. LE TRAVAILLEUR APPLIQUERA ENSUITE CETTE PROCÉDURE À PARTIR DU POINT #8."},{"p":2,"t":"LES MARTEAUX DE 6’’ DOIVENT TOUJOURS ÊTRE TRANSPORTÉS À L’AIDE DU CHARIOT CONÇU À CET EFFET. LE ‘’DRIVER SUB’’ DOIT ÊTRE INSTALLÉ SUR LES MARTEAUX EN TOUT TEMPS LORS DE LA MANIPULATION"},{"p":2,"t":"Pour visser le marteau de 6’’ sur la tête :"},{"p":2,"t":"1- Approcher le chariot près de la foreuse;"},{"p":2,"t":"2- Ouvrir les tables;"},{"p":2,"t":"3- Positionner le marteau entre les tables sous la tête à l’aide du chariot;"},{"p":2,"t":"4- Descendre le ‘’GEAR BOX’’ et aligner le ‘’SAVER SUB’’ vis-à-vis les filets du marteau;"},{"p":2,"t":"5- Faire tourner la tête pour visser le marteau dans le ‘’SAVER SUB’’ jusqu’à ce que les filets soient accotés;"},{"p":3,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 3"},{"p":3,"t":"6- Enlever la chaîne de sûreté sur le chariot;"},{"p":3,"t":"7- Remonter la tête avec le marteau et retirer le chariot;"},{"p":3,"t":"8- Redescendre le marteau dans les jaws et les refermer sur le marteau;"},{"p":3,"t":"9- Serrer les filets en s’assurant qu’ils soient bien accotés;"},{"p":3,"t":"10- Appliquer le ‘’SPLINE PISTON’’;"},{"p":3,"t":"Pour mettre une bit de 6’’, 8’’ ou 10’’ sur le marteau de 6’’;"},{"p":3,"t":"À CHAQUE FOIS QU’ON DOIT S’EXPOSER LES MAINS SOUS LE MARTEAU, IL FAUT VALIDER QUE LE MARTEAU EST BIEN VISSER AU GEAR BOX"},{"p":3,"t":"11- Installer le casse-bit dans la ‘’SLIP PLATE’’ et fermer les jaws;"},{"p":4,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 4"},{"p":4,"t":"12- Déposer la bit sur le casse-bit;"},{"p":4,"t":"13- Descendre le marteau sur la bit et dévisser le driver sub avec la rotation;"},{"p":4,"t":"14- Monter ensuite le marteau assez haut pour permettre d’installer les ‘’RETAINING RING’’ (Anneaux de retenu);"},{"p":4,"t":"15- Redescendre le marteau dur le ‘’DRIVER SUB’’ et les visser ensemble avec la rotation pour qu’ils soient bien accotés;"},{"p":4,"t":"16- Relever le marteau au maximum pour enlever le casse-bit;"},{"p":4,"t":"17- Commencer le forage;"},{"p":5,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 5"},{"p":5,"t":"Pour enlever une bit de 6’’, 8’’ ou 10’’ sur le marteau de 6’’"},{"p":5,"t":"À CHAQUE FOIS QU’ON DOIT S’EXPOSER LES MAINS SOUS LE MARTEAU, IL FAUT VALIDER QUE LE MARTEAU EST BIEN VISSÉ AU GEAR BOX"},{"p":5,"t":"18- Monter le marteau assez haut pour pouvoir installer le casse-bit dans la ‘’SLIP- PLATE’’ et fermer les jaws;"},{"p":5,"t":"19- Descendre le marteau jusqu’à ce que la bit soit dans le casse-bit;"},{"p":5,"t":"20- S’assurer que le ‘’SPLINE-PISTON’’ est appliqué ;"},{"p":6,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 6"},{"p":6,"t":"21- Casser la bit et dévisser le marteau du ‘’DRIVER SUB’’ ;"},{"p":6,"t":"22- Monter le marteau assez haut pour pouvoir retirer les ‘’RETAINING RINGS’’;"},{"p":6,"t":"23- Enlever les ‘’RETAINING RINGS’’;"},{"p":6,"t":"24- Redescendre le marteau sur le ‘’DRIVER SUB’’ et les visser ensemble;"},{"p":6,"t":"25- Remonter le marteau assez haut pour enlever la bit et le casse-bit;"},{"p":6,"t":"26- Ouvrir les jaws;"},{"p":6,"t":"27- Désappliquer le ‘’SPLINE PISTON’’;"},{"p":6,"t":"28- Descendre le marteau entre les jaws et les refermer sur le marteau;"},{"p":6,"t":"29- Casser le marteau et le dévisser d’un tour seulement;"},{"p":7,"t":"PROCÉDURE POUR LA MANIPULATION DES MARTEAUX DE FORAGE ET DE LEURS COMPOSANTES Date : Novembre 2021 7"},{"p":7,"t":"30- Ouvrir les jaws;"},{"p":7,"t":"31- Remonter le marteau pour insérer le chariot sous les tables;"},{"p":7,"t":"32- Redescendre le marteau sur le chariot en laissant l’espace pour finir de dévisser le marteau;"},{"p":7,"t":"33- Dévisser manuellement le marteau en ne s’exposant pas les mains;"},{"p":7,"t":"34- Attacher le marteau à l’aide de la chaîne de retenu et sortir le chariot."},{"p":7,"t":"__________________________ Christian St-Amour Directeur des Opérations"}],"ss-dd-st-001":[{"p":1,"t":"PROCÉDURE DE TRAVAIL SS-DD-ST-001"},{"p":1,"t":"INSTALLATION DES SYSTÈMES DE SÉCURITÉ"},{"p":1,"t":"L’objectif de cette procédure est de définir des méthodes sécuritaires, efficaces et de standardiser l’installation des systèmes de sécurité pour les foreuses aux diamants. APPLICATION Cette procédure s’applique à tous les employés de MACHINES ROGER INTERNATIONAL."},{"p":1,"t":"RESPONSABILITÉS Le travailleur est responsable d’appliquer cette procédure et de voir au bon déroulement des opérations et de la qualité du travail accompli. Le superviseur doit faire appliquer cette procédure rigoureusement."},{"p":1,"t":"EPI OBLIGATOIRES Équipements de base obligatoires"},{"p":1,"t":"INTER-VERROUILLAGE"},{"p":1,"t":"Le système d’interverrouillage « FORTRESS » comprend 2 pièces : la coulisse et la serrure"},{"p":1,"t":"1. La coulisse doit être fixer sur la porte en tout temps; 2. La serrure doit être installée sur le cadrage de la porte en tout temps."},{"p":1,"t":"Coulisse Serrure"},{"p":2,"t":"PROCÉDURE DE TRAVAIL SS-DD-ST-001"},{"p":2,"t":"INSTALLATION DES SYSTÈMES DE SÉCURITÉ"},{"p":2,"t":"Le dead man doit être positionné à un minimum de 1,5 mètre de la tour de la foreuse, à côté du rack à rod sinon il est très important de respecter les 1,5 mètres."},{"p":2,"t":"Ajouts ou modifications Date Par Changement des interverrouillages « AIMANTS » pour les « FORTRESS ». 31-08-2023 S. Tremblay F. Croteau"},{"p":2,"t":"____________________________ Stéphane Tremblay Surintendant Santé-Sécurité"}],"std-dd-installation":[{"p":1,"t":"STANDARD D’INSTALLATION SITES DE FORAGE MACHINES ROGER INTERNATIONAL"},{"p":1,"t":"Porte et grillages CONTRÔLES STM POWER PACK DR : Laissez accès à l’interrupteur principal STM : Interrupteur accessible COFFRE À OUTILS TABLE À CORE MARCHES AVEC RAMPES (si nécessaire) POMPE À EAU extincteur Trousse 1er soins 1 extincteur à l’entrée du site graisse poubelle Les contrôles de STM sont"},{"p":1,"t":"toujours à droite. Les contrôles des DR peuvent aussi être à droite ou à gauche"}]};
